insert into staging.generated_run_content (
  id, parse_run_id, content_type, payload, created_at, updated_at
) values (
  'c4c10124-54db-4152-b1e3-9db7835d6f7b'::uuid, 'b6511faa-f537-4214-b427-e4ff5fd4cba7'::uuid, 'health_checkup', E'{"coverProgram": "건강검진C", "followUpCare": "밤이의 건강 관리를 위해 다음과 같은 사후 관리 계획이 필요합니다.\\n\\n우선, 쿠싱증후군이 의심되는 임상 증상(다음다뇨, 헥헥거림, 털 빠짐)과 SDMA 수치를 고려하여, 수개월 이내에 내분비 호르몬 검사를 포함한 추가적인 혈액검사를 진행하여 정확한 감별 진단을 하는 것이 중요합니다. 가정에서는 밤이의 음수량, 배뇨 빈도, 호흡 양상 및 털 빠짐 정도를 꾸준히 관찰해 주시기 바랍니다.\\n\\n담낭 슬러지 관리를 위해 현재 처방된 담즙 배출 개선제를 지시에 따라 꾸준히 복용시켜 주십시오. 신장 결석은 미세하기 때문에 지속적으로 초음파검사 시 변화를 관찰하면 됩니다. \\n\\n근골격계의 퇴행성 변화와 어깨 부위 관절염에 대해서는 통증 관리를 위한 보조제 및 물리치료 등을 고려할 수 있으며, 격렬한 운동이나 미끄러운 환경을 피하여 관절에 부담을 줄여주는 것이 좋습니다. 절음 증상이 지속되거나 악화될 경우 재진을 통해 정밀 검사를 진행할 것을 권고합니다.", "coverOwnerName": "노하진", "overallSummary": "이번 건강검진 결과, 밤이에게서 몇 가지 주의 깊은 관찰이 필요한 소견이 확인되었습니다.\\n\\n우선, 보호자께서 호소하신 물을 많이 마시고 헥헥거리는 증상, 그리고 털 빠짐 증상은 내분비계 질환, 특히 쿠싱증후군의 가능성을 시사합니다. 혈액검사에서 SDMA 수치가 정상 상한선에 위치하는 점 또한 이러한 가능성을 완전히 배제할 수 없음을 보여줍니다.\\n\\n복부 초음파 검사에서 담낭 내 다량의 슬러지가 확인되었으며, 부신장기의 크기는 정상으로 확인 되었습니다. 비뇨기계에서는 신장 내 미세결석 소견이 관찰되었습니다.\\n\\n근골격계에서는 흉요추부위 및 요추부위에 퇴행성 척추 변화가 관찰됩니다.   또한, 어깨 관절부위에 관절염 소견이 있습니다.", "coverPatientAge": "9", "coverPatientSex": "수컷(중성화)", "coverCheckupDate": "2026-04-24", "coverPatientName": "밤이", "coverPatientBreed": "Poodles", "coverVeterinarian": "김전모", "labInterpretation": "이번 건강검진 혈액검사 결과, CBC와 Chem 15 항목은 전반적으로 정상 범위 내에 있었습니다. 다만, 적혈구 지표 중 MCV(평균 적혈구 용적)와 MCH(평균 적혈구 혈색소량)가 정상보다 낮은 수치를 보였으나, 임상적으로 유의미한 빈혈 소견은 아닙니다. SDMA 수치는 14 µg/dL로 정상 상한선에 해당하여, 향후 신장 기능 변화에 대한 지속적인 관찰이 필요합니다.", "systemsPage3Blocks": [{"rows": [{"label": "주요 진단 내용", "content": "신체 검사 결과, 심장 잡음(murmur)이나 폐음(lung sound)에서 특별한 이상 소견은 확인되지 않았습니다. 혈압은 120 mmHg로 정상 범주에 속합니다. 흉부 방사선 검사에서 심장 크기 측정 결과 VHS 9.5로 정상 범위 내에 있습니다. "}, {"label": "시사점", "content": "현재 검진 상 순환기 및 호흡기 계통의 직접적인 이상 소견은 발견되지 않았으나, 보호자께서 말씀하신 헥헥거림 증상은 다양한 원인에 의해 나타날 수 있습니다. 나이가 있는 환자에서 심장 질환의 초기 증상일 수도 있으므로, 이갈림 증상의 빈도나 양상 변화를 면밀히 관찰해 주시고, 활동량 감소나 기침 동반 여부 등을 함께 살펴봐 주시는 것이 중요합니다."}], "titleEn": "Circulatory & Respiratory Systems", "titleKo": "순환기&호흡기", "variant": "rows"}, {"rows": [{"label": "주요 진단 내용", "content": "복부 초음파 검사 결과, 위장관 및 주위 림프절에서는 특이 소견이 관찰되지 않았습니다."}, {"label": "시사점", "content": "이상 소견이 없습니다. "}], "titleEn": "Digestive System", "titleKo": "소화기", "variant": "rows"}, {"rows": [{"label": "주요 진단 내용", "content": "혈액검사 결과는 전반적으로 정상 범위였으나, SDMA 수치가 14 µg/dL로 정상 상한선에 해당합니다. 보호자께서 말씀하신 헥헥거림, 물을 많이 마시는 증상(다뇨증), 그리고 다리/등 부위 털 빠짐(탈모)은 쿠싱증후군과 같은 내분비 질환의 임상 증상과 유사한 점이 있습니다."}, {"label": "시사점", "content": "SDMA 수치는 신장 기능 평가에 중요한 지표이지만, 정상 상한선에 위치하더라도 환자의 임상 증상과 함께 고려했을 때 내분비 기능 이상 가능성을 배제하기 어렵습니다. 쿠싱증후군 감별 진단을 위한 추가적인 호르몬 검사가 필요하며, 보호자께서는 평소 다음다뇨(물을 많이 마시고 소변을 자주 보는 것)와 헥헥거림 증상의 변화를 주의 깊게 관찰해 주시기 바랍니다."}], "titleEn": "Endocrine System", "titleKo": "내분비계", "variant": "rows"}], "systemsPage4Blocks": [{"rows": [{"label": "주요 진단 내용", "content": "치과 및 안과 육안평가 검사에서 치석정도는 미약한 정도로 확인되며 양측 핵경화 소견이 관찰되었습니다. "}, {"label": "시사점", "content": "치석의 경우 더 심해지거나 불편감이 있을 시 스케일링이 필요하며 핵경화의 경우 시력에 영향이 없는 노령성 변화기 때문에 특별한 처치가 필요하진 않습니다. "}], "titleEn": "Dental & Ophthalmology", "titleKo": "치과 및 안과", "variant": "rows"}, {"images": [{}, {}, {}, {}, {}, {}], "titleEn": "", "titleKo": "", "variant": "imagesGrid2x3"}, {"rows": [{"label": "주요 진단 내용", "content": "보호자께서 다리 및 등 부위 털 빠짐 증상을 호소하셨습니다. 또한, 왼쪽 목과 오른쪽 등 부위에 뾰루지로 의심되는 피부 병변이 관찰된다고 하셨습니다."}, {"label": "시사점", "content": "털 빠짐과 피부 병변은 알레르기, 호르몬 불균형, 외부 기생충, 또는 다른 전신 질환의 증상일 수 있습니다. 가정에서 피부를 청결하게 유지해 주시고, 증상이 지속되거나 악화될 경우 피부과적인 추가 검사 및 정확한 원인 파악을 위한 진료를 받아보시는 것이 필요합니다. 뾰루지는 수종으로 확인되며 수종의 경우 이후 재발 시 국소 마취 후에 제거하는 것을 추천드립니다. "}], "titleEn": "Skin & External Ear Canal", "titleKo": "피부와 외이도", "variant": "rows"}, {"images": [{}, {}, {}], "titleEn": "", "titleKo": "", "variant": "images"}], "systemsPage5Blocks": [{"rows": [{"label": "검사 결과 해석", "content": "흉부 측면 방사선 영상에서는 특이소견이 발견되지 않고 흉요추부 방사선 사진에서는 흉추-요추 경계부에 경미한 골융기, 즉 척추증(spondylosis deformans) 소견이 관찰되었습니다. 어깨관절에서는 골증식(osteophyte)이 있어 관절염을 생각해 볼 수 있습니다. "}], "compact": true, "titleEn": "X-ray", "titleKo": "방사선 검사", "variant": "rows"}, {"images": [{"src": "jungdn-260427-01_b6511faa/2026-04-24/1777252466187_0_a42f4a03.webp", "caption": "흉부 방사선"}, {"src": "jungdn-260427-01_b6511faa/2026-04-24/1777252654915_0_ec6e7853.webp", "caption": "흉부 방사선"}, {"src": "jungdn-260427-01_b6511faa/2026-04-24/1777252656040_1_1da0653e.webp", "caption": "관절 방사선"}, {"src": "jungdn-260427-01_b6511faa/2026-04-24/1777252607132_1_f8066a7a.webp", "caption": "복부 방사선", "rotationDeg": 0}], "titleEn": "", "titleKo": "", "variant": "images4"}, {"rows": [{"label": "검사 결과 해석", "content": "복부 초음파 검사에서 담낭 내 다량의 슬러지가 확인되었습니다. 신장에 미세결석이 확인되며 그 외 특이소견 없습니다. "}], "compact": true, "titleEn": "Ultrasonography", "titleKo": "초음파 검사", "variant": "rows"}, {"images": [{"src": "jungdn-260427-01_b6511faa/2026-04-24/1777252990182_0_7201fe0e.webp", "caption": "담낭"}, {"src": "jungdn-260427-01_b6511faa/2026-04-24/1777253028981_0_8464f081.webp", "caption": "담낭"}, {"src": "jungdn-260427-01_b6511faa/2026-04-24/1777253187406_0_296d5ef5.webp", "caption": "좌측신장"}, {"src": "jungdn-260427-01_b6511faa/2026-04-24/1777253822401_0_af207e42.webp", "caption": "좌측부신", "rotationDeg": 0}, {}, {}, {}, {}, {}], "titleEn": "", "titleKo": "", "variant": "imagesGrid3x3"}], "coverPatientSpecies": "개", "recheckWithin1Month": "", "systemsPage3bBlocks": [{"rows": [{"label": "주요 진단 내용", "content": "혈액검사 상 SDMA 수치는 14 µg/dL로 정상 범위 상한선에 위치합니다. 신장 및 방광 초음파 검사에서는 뚜렷한 특이 소견이 없었습니다."}, {"label": "시사점", "content": "SDMA 수치가 정상 상한선에 있는 점은 신장 및 비뇨기계 관찰의 중요성을 시사합니다. 향후 음수량 증가 및 균형 잡힌 식단관리가 권장됩니다. "}], "titleEn": "Kidney & Urinary System", "titleKo": "신장 및 비뇨기계", "variant": "rows"}, {"rows": [{"label": "주요 진단 내용", "content": "복부 초음파 검사에서 간과 비장은 특이 소견이 없었습니다. 그러나 담낭 내에 다량의 슬러지가 명확하게 관찰되었습니다. 이 외에 간실질의 이상이나 담관 확장 소견은 확인되지 않았습니다."}, {"label": "시사점", "content": "담낭 슬러지는 담낭 기능 저하나 담즙 구성 성분의 불균형으로 인해 발생하며, 시간이 지남에 따라 담낭점액낭종이나 담석으로 발전할 위험이 있습니다. 현재 처방된 담즙 배출 개선제를 꾸준히 복용하며 담낭 건강을 관리하는 것이 중요합니다. 주기적인 초음파 검사를 통해 슬러지의 변화 양상을 추적 관찰할 필요가 있습니다."}], "titleEn": "Hepatobiliary System", "titleKo": "간담도계", "variant": "rows"}, {"rows": [{"label": "주요 진단 내용", "content": "보호자께서 좌측 앞다리 절음 증상을 호소하셨습니다. 방사선 검사 결과, 흉추 12-13번과 요추 1-2번 부위에 경미한 퇴행성 골변화인 척추증(spondylosis deformans) 소견이 확인되었습니다. 또한, 양측 어깨관절의 관절염 소견이 확인되었습니다. "}, {"label": "시사점", "content": "확인된 척추의 퇴행성 변화는 허리 통증이나 신경학적 증상과 관련될 수 있으며, 절음 증상의 원인 중 하나일 수 있습니다. 어깨관절의 관절염 역시 일시적인 파행을 유발시킬 수 있습니다. 관절 건강 보조제나 소염제 처방을 고려해 볼 수 있으며, 점프나 미끄러운 바닥에서의 활동을 제한하여 관절에 무리가 가지 않도록 관리해 주시는 것이 중요합니다."}], "titleEn": "Musculoskeletal System", "titleKo": "근골격계", "variant": "rows"}], "recheckWithin3Months": "쿠싱증후군 감별 검사\\n내분비 호르몬 검사 등 추가 혈액검사를 고려해 주세요.", "recheckWithin6Months": "종합 건강 재검진\\n전반적인 건강 상태 및 만성 질환 관리 계획을 재평가합니다.", "recheckWithin1to2Weeks": ""}'::jsonb, '2026-04-27 01:43:15.308166+00'::timestamptz, '2026-04-27 05:16:12.462+00'::timestamptz
);

insert into staging.generated_run_content (
  id, parse_run_id, content_type, payload, created_at, updated_at
) values (
  '8d8ac517-e614-4d97-806d-85e0ffebd598'::uuid, '62069645-b4bd-4fe1-af9a-36b0171d2750'::uuid, 'health_checkup', E'{"followUpCare": "쿠로미의 건강 관리를 위해 몇 가지 중요한 사후 관리 계획을 제안 드립니다. 우선, 확인된 고지혈증에 대해서는 1개월 뒤 아침 금식 후 혈액 검사를 통해 재평가를 진행할 예정입니다. 이 검사 결과를 바탕으로 저지방 식이요법이나 보조제 복용 등 구체적인 관리 방안을 논의하게 될 것입니다. 보호자께서는 이 기간 동안 식단 관리에 특별히 신경 써 주시기 바랍니다.\\n\\n양측 슬개골 내측 탈구 2기 관리를 위해서는 체중 조절이 필수적입니다. 현재 BCS 5.5에서 4.0~4.5 수준으로 체중을 감량하여 관절에 가해지는 부담을 최소화하는 것이 중요합니다. 집에서 뒷다리를 불편해하거나 절뚝거리는 증상이 나타나는지 세심하게 관찰해 주시고, 필요시 추가적인 진료를 통해 수술적 교정 가능성도 함께 논의할 수 있습니다.\\n\\n호흡기 증상인 역재채기 발생 시에는 흥분하지 않도록 진정시키고, 코를 부드럽게 마사지하여 증상 완화를 시도해 주십시오. 찬 바람 노출을 최소화하는 것도 도움이 됩니다. 주기적인 건강검진을 통해 심잡음 및 전반적인 건강 상태를 지속적으로 확인하고 관리해 나갈 것입니다.", "coverOwnerName": "정종욱", "overallSummary": "이번 건강검진 결과, 쿠로미는 양측 슬개골 내측 탈구 2기 소견을 보였습니다. 이는 뒷다리 통증 및 관절염으로 이어질 수 있으므로 지속적인 관찰과 관리가 필요합니다. 특히, 현재 체평점(BCS 5.5)을 4.0~4.5 수준으로 조절하여 관절에 가해지는 부담을 줄여주는 것이 중요합니다.\\n\\n혈액 검사에서는 고지혈증 소견이 확인되었으며, 중성지방(TG) 수치가 매우 높게 측정되어 추가적인 평가가 필요합니다. 1개월 뒤 아침 금식 후 고지혈증 재검사를 통해 현재 상태를 정확히 파악하고, 필요시 식이 관리 및 보조제 복용을 고려할 예정입니다.\\n\\n호흡기 증상으로는 가끔 침 뱉듯이 숨쉬기 힘들어하는 증상과 산책 시 거위 울음 소리(goosehunking)가 관찰되었으며, 이는 역재채기(Reverse Sneezing)일 가능성이 높습니다. 흉부 방사선 검사에서 기관 허탈 소견은 없었으나, 심잡음이 확인되어 주기적인 모니터링이 권장됩니다. 간, 신장 등 주요 장기 기능 및 복강 내 장기 초음파 검사는 현재까지 특이 소견 없이 양호한 상태를 보였습니다.", "coverPatientAge": "4", "coverPatientSex": "수컷(중성화)", "coverCheckupDate": "2026-04-20", "coverPatientName": "쿠로미", "coverPatientBreed": "치와와", "coverVeterinarian": "김준", "labInterpretation": "이번 혈액 검사에서는 고지혈증 소견이 확인되었으며, 특히 중성지방(TG) 수치는 매우 높게 측정되었습니다. 이는 대사 기능과 관련된 부분을 시사합니다. 글로불린(GLOB) 및 간 수치는 정상 범위로 확인되어 전반적인 장기 기능은 양호한 것으로 평가됩니다. 1개월 후 금식 후 재검이 필요합니다.", "systemsPage3Blocks": [{"rows": [{"label": "주요 진단 내용", "content": "흉부 방사선 검사 결과, 기관 허탈(TC) 소견은 관찰되지 않았습니다. 심장 크기는 VHS 9.4로 정상 범위에 해당합니다. 신체검사에서 심잡음이 확인되었고, 호흡 패턴 이상으로 가끔 침 뱉듯이 숨쉬기 힘들어하는 증상과 산책 시 거위 울음 소리(goosehunking)가 관찰되었습니다. 이는 찬 바람에 더 심해지는 경향을 보였습니다."}, {"label": "시사점", "content": "현재 관찰되는 호흡기 증상은 역재채기(Reverse Sneezing)일 가능성이 가장 높습니다. 역재채기는 일반적으로 생명에 위협이 되는 심각한 질환은 아니나, 증상이 나타날 때 보호자님의 세심한 관리가 필요합니다. 확인된 심잡음은 현재 심장 크기가 정상 범위이나, 향후 추적 관찰이 필요할 수 있습니다."}], "titleEn": "Circulatory & Respiratory Systems", "titleKo": "순환기&호흡기", "variant": "rows"}, {"rows": [{"label": "주요 진단 내용", "content": "복부 초음파 검사 결과, 담낭은 양호한 상태로 확인되었으며, 간 수치 또한 정상 범위에 해당합니다. 위장관 및 기타 복강 장기에서 특이적인 질환 소견은 관찰되지 않았습니다. 환자는 평소 밥을 잘 먹지 않는 경향이 있다고 보호자께서 알려주셨습니다."}, {"label": "시사점", "content": "현재 소화기 계통과 관련하여 특별한 이상 소견은 확인되지 않았습니다. 평소 식사량이 적은 부분은 환자의 활동량과 체중 변화를 고려하여 지속적인 관찰이 필요합니다. 급격한 식욕 저하나 구토, 설사 등 소화기 증상 발생 시 내원하여 진찰을 받는 것이 좋습니다."}], "titleEn": "Digestive System", "titleKo": "소화기", "variant": "rows"}, {"rows": [{"label": "주요 진단 내용", "content": "혈액 검사 결과, 고지혈증 소견이 확인되었으며, 특히 중성지방(TG) 수치는 기계 측정 불가 수준으로 높게 나타났습니다. 신체 검사 상 체평점(BCS)은 5.5로 측정되어, 적정 체중보다 약간 높은 상태로 평가됩니다. 전반적인 건강 관리를 위해 적정 체중 유지가 권고됩니다."}, {"label": "시사점", "content": "고지혈증은 대사 이상을 시사하며, 혈관 건강에 영향을 미칠 수 있으므로 추적 관리가 중요합니다. 이를 위해 1개월 뒤 아침 금식 후 고지혈증 재검사가 필요합니다. 더불어, BCS 4.0~4.5를 목표로 체중 감량을 진행하는 것이 고지혈증 관리뿐만 아니라 슬개골 탈구, 호흡기 증상 관리에도 도움이 될 것으로 판단됩니다. 저지방 식이나 보조제 복용을 고려할 수 있습니다."}], "titleEn": "Endocrine System", "titleKo": "내분비계", "variant": "rows"}], "systemsPage4Blocks": [{"rows": [{"label": "주요 진단 내용", "content": "구강 검진 결과, 현재 특별히 눈에 띄는 치과 질환(치석, 치주염, 치아 파절 등)은 확인되지 않았습니다. 안과 검진에서도 결막 충혈이나 각막 혼탁 등 유의미한 이상 소견은 관찰되지 않았습니다."}, {"label": "시사점", "content": "현재 치과 및 안과 계통은 건강한 상태로 평가됩니다. 건강한 구강 위생 유지를 위해 평소 양치 습관을 들이는 것이 좋으며, 눈곱 증가나 충혈 등 안과 관련 이상 증상 발생 시 내원하여 진찰받는 것을 권장합니다."}], "titleEn": "Dental & Ophthalmology", "titleKo": "치과 및 안과", "variant": "rows"}, {"images": [{}, {}, {}, {}, {}, {}], "titleEn": "", "titleKo": "", "variant": "imagesGrid2x3"}, {"rows": [{"label": "주요 진단 내용", "content": "해당 프로그램 미포함 영역"}, {"label": "시사점", "content": "해당 프로그램 미포함 영역"}], "titleEn": "Skin & External Ear Canal", "titleKo": "피부와 외이도", "variant": "rows"}, {"images": [{}, {}, {}], "titleEn": "", "titleKo": "", "variant": "images"}], "systemsPage5Blocks": [{"rows": [{"label": "검사 결과 해석", "content": "흉부 방사선 사진에서 폐와 심장의 이상 소견은 없었으며 기관 허탈은 관찰되지 않았습니다. 관절 방사선 사진에서는 양측 슬개골의 위치 이상이 확인되었고, 이는 차트상 양측 슬개골 내측 탈구 2기와 연관됩니다. 복부 방사선 사진은 특이 소견이 없습니다."}], "compact": true, "titleEn": "X-ray", "titleKo": "방사선 검사", "variant": "rows"}, {"images": [{"src": "kimjoon-260427-02_62069645/2026-04-20/1777270801113_0_eb939217.webp", "caption": "관절 방사선"}, {"src": "kimjoon-260427-02_62069645/2026-04-20/1777270826382_0_b2416367.webp", "caption": "관절 방사선"}, {"src": "kimjoon-260427-02_62069645/2026-04-20/1777270850128_0_24b8a3a0.webp", "caption": "관절 방사선"}, {"src": "kimjoon-260427-02_62069645/2026-04-20/1777270872381_0_9bf4aca4.webp", "caption": "관절 방사선"}], "titleEn": "", "titleKo": "", "variant": "images4"}, {"rows": [{"label": "검사 결과 해석", "content": "복부 초음파 검사에서 간, 담낭, 신장, 부신 등 주요 복강 장기 모두 명확한 이상 소견은 관찰되지 않았습니다. 특이적인 구조 변화나 병변이 없어, 현재 초음파상으로는 전반적으로 양호한 상태입니다."}], "compact": true, "titleEn": "Ultrasonography", "titleKo": "초음파 검사", "variant": "rows"}, {"images": [{"src": "kimjoon-260427-02_62069645/2026-04-20/1777270983456_0_3c0252fb.webp", "caption": "복부 초음파"}, {"src": "kimjoon-260427-02_62069645/2026-04-20/1777270996202_0_06e2bf6f.webp", "caption": "복부 초음파"}, {"src": "kimjoon-260427-02_62069645/2026-04-20/1777271058836_0_71795d88.webp", "caption": "복부 초음파"}, {"src": "kimjoon-260427-02_62069645/2026-04-20/1777271067982_0_f68837bd.webp", "caption": "복부 초음파"}, {"src": "kimjoon-260427-02_62069645/2026-04-20/1777270887451_0_e5e078d4.webp", "caption": "복부 초음파"}, {"src": "kimjoon-260427-02_62069645/2026-04-20/1777270901012_0_0c3fb12b.webp", "caption": "복부 초음파"}, {}, {}, {}], "titleEn": "", "titleKo": "", "variant": "imagesGrid3x3"}], "coverPatientSpecies": "개", "recheckWithin1Month": "고지혈증 재평가\\n아침 금식 후 혈액검사를 통해 고지혈증 여부를 재확인합니다.", "systemsPage3bBlocks": [{"rows": [{"label": "주요 진단 내용", "content": "신체검사에서 CRT 수치는 정상 범위(<1.5)로 확인되었으며, 복부 초음파 검사에서도 좌측 및 우측 신장 모두에서 명확한 이상 소견은 관찰되지 않았습니다. 비뇨기계 관련하여 결석이나 방광벽 비후 등 특이사항은 확인되지 않았습니다."}, {"label": "시사점", "content": "현재 신장 및 비뇨기계는 건강한 상태로 평가됩니다. 향후 정기적인 건강검진을 통해 신장 기능과 요로계 상태를 지속적으로 확인하는 것이 중요합니다. 충분한 수분 섭취와 균형 잡힌 식단 유지를 통해 비뇨기계 건강을 관리해 주시면 좋습니다."}], "titleEn": "Kidney & Urinary System", "titleKo": "신장 및 비뇨기계", "variant": "rows"}, {"rows": [{"label": "주요 진단 내용", "content": "혈액 검사에서 간 수치(ALT, AST, ALKP, GGT 등)는 정상 범위에 속하는 것으로 확인되었습니다. 복부 초음파 검사 결과, 담낭 및 간 실질에서 슬러지, 점액종, 종괴 등 특별한 이상 소견은 관찰되지 않았습니다. 전반적인 간담도계는 양호한 상태입니다."}, {"label": "시사점", "content": "현재 간담도계 기능 및 구조는 모두 건강한 것으로 평가됩니다. 고지혈증 관리를 위한 저지방 식이요법이 간 기능에 무리를 주지 않도록 정기적인 모니터링이 필요할 수 있습니다. 특별한 추가 조치 없이 건강한 식생활 유지를 권장합니다."}], "titleEn": "Hepatobiliary System", "titleKo": "간담도계", "variant": "rows"}, {"rows": [{"label": "주요 진단 내용", "content": "신체검사 및 방사선 검사 결과, 양측 슬개골 내측 탈구 2기 소견이 확인되었습니다. 특히 우측 슬개골이 더 잘 빠지고 좌측 슬개골은 빠질 때 더 확연한 움직임을 보였습니다. 방사선 사진에서도 슬개골의 위치 이상이 명확하게 관찰되었습니다."}, {"label": "시사점", "content": "슬개골 탈구는 관절의 불안정성을 유발하여 통증 및 퇴행성 관절염으로 이어질 수 있습니다. 현재 체평점(BCS 5.5)을 4.0~4.5 수준으로 유지하여 관절에 가해지는 부담을 줄여주는 것이 매우 중요합니다. 평소 뒷다리 절뚝거림 등 임상 증상 변화를 세심하게 관찰하고, 필요시 추가적인 관리가 논의될 수 있습니다."}], "titleEn": "Musculoskeletal System", "titleKo": "근골격계", "variant": "rows"}], "recheckWithin3Months": "슬개골 및 호흡기 재평가\\n임상 증상 변화 및 체중 관리 상태를 확인합니다.", "recheckWithin6Months": "정기 건강검진 진행\\n전반적인 건강 상태를 지속적으로 관리하고 평가합니다.", "recheckWithin1to2Weeks": "활동 관찰 및 증상 기록\\n슬개골 탈구 및 호흡기 증상 변화를 세심하게 확인해주세요."}'::jsonb, '2026-04-27 07:12:12.927779+00'::timestamptz, '2026-04-27 07:12:12.673+00'::timestamptz
);

insert into staging.generated_run_content (
  id, parse_run_id, content_type, payload, created_at, updated_at
) values (
  '7fe1cdc9-677c-4b0c-8cc5-08667abfbf7e'::uuid, '242be746-e93c-4197-be9c-3d672191434e'::uuid, 'health_checkup', E'{"coverProgram": "건강검진A", "followUpCare": "이번 검진 결과에 따라 토리의 건강 관리를 위해 다음과 같은 사후 관리가 권장됩니다. 초음파에서 확인된 미세 담낭 슬러지는 1년 뒤 추적 초음파 검사를 통해 변화를 확인해야 합니다.\\n\\n중등도 치석은 구강 건강 유지를 위해 빠른 시일 내 스케일링 관리가 필요합니다. 흉부 방사선에서 의심되는 패턴은 기침이나 호흡곤란 등 임상 증상 발현 시 즉시 호흡기 평가를 받아야 합니다. 앞다리 등을 핥는 행동은 알러지가능성이 있어 주기적으로 모니터링할 필요가 있습니다.\\n\\n전반적인 건강 유지를 위해 최소 6개월에서 1년 주기로 정기적인 건강검진을 지속적으로 시행하여 잠재적인 건강 문제를 조기에 발견하고 관리하는 것이 매우 중요합니다.", "coverOwnerName": "김경화", "overallSummary": "토리의 이번 건강검진 결과, 전반적으로 양호한 건강 상태를 보였습니다. 기본적인 신체검사 및 혈액검사에서는 특이적인 이상 소견이 확인되지 않았습니다.\\n\\n다만, 영상 검사에서 몇 가지 주의 깊게 살펴봐야 할 소견들이 관찰되었습니다. 복부 초음파 검사에서는 미세한 담낭 슬러지가 확인되었으며, 이는 추후 경과 관찰이 필요한 부분입니다. 또한, 방사선 검사에서는 흉부의 경미한 간질/기관지성 패턴이 관찰됩니다. 구강 검사에서는 중등도의 치석이 확인되었습니다. 이러한 소견들은 현재 토리의 활동성 저하나 특정 불편감을 유발하지 않을 수 있으나, 잠재적인 건강 문제를 예방하고 관리하기 위해 정밀 검사 및 지속적인 관심이 중요합니다.\\n\\n정기적인 건강검진은 반려동물의 건강을 조기에 확인하고 적절한 시기에 관리할 수 있도록 돕는 매우 중요한 과정입니다.", "coverPatientAge": "4", "coverPatientSex": "수컷(중성화)", "coverCheckupDate": "2026-04-25", "coverPatientName": "토리", "coverPatientBreed": "말티푸", "coverVeterinarian": "김전모", "labInterpretation": "토리의 혈액검사 결과는 전반적으로 모두 정상 범위 내에 있어 양호한 건강 상태를 보여주었습니다. 특히, 간, 신장, 췌장 관련 수치와 전해질 균형 또한 안정적으로 유지되고 있습니다. 이러한 결과는 현재 주요 장기의 기능이 원활함을 시사합니다.", "systemsPage3Blocks": [{"rows": [{"label": "주요 진단 내용", "content": "신체검사에서 심잡음 및 폐음은 정상으로 청진되었습니다. 혈압은 150mmHg으로 측정되어 정상 범위 상한에 근접하거나 약간 높은 수치로 확인되었습니다. 흉부 방사선 검사에서 VHS는 10으로 측정되어 정상 범위 내에 있었으나, 흉부 중심부에 경미한 간질/기관지성 패턴이 의심되는 소견이 관찰되었습니다."}, {"label": "시사점", "content": "혈압 수치는 스트레스나 흥분으로 일시적으로 높을 수 있으나, 지속적인 관찰이 필요합니다. 흉부 방사선에서 관찰된 미세한 패턴은 현재 임상 증상이 없더라도 향후 호흡기계 문제의 가능성을 배제할 수 없으므로, 기침이나 호흡 곤란 등 이상 증상 발생 시 즉시 내원하여 정밀 검사를 받는 것이 중요합니다."}], "titleEn": "Circulatory & Respiratory Systems", "titleKo": "순환기&호흡기", "variant": "rows"}, {"rows": [{"label": "주요 진단 내용", "content": "복부 초음파 검사에서 위장관 및 주위 림프절에서는 특이 소견이 관찰되지 않았습니다. "}, {"label": "시사점", "content": "현재 주의 해야 될 사항은 없습니다. "}], "titleEn": "Digestive System", "titleKo": "소화기", "variant": "rows"}, {"rows": [{"label": "주요 진단 내용", "content": "혈액검사 결과, 혈당(GLU=106mg/dL), 콜레스테롤, 중성지방 등 내분비계와 관련된 수치들은 모두 정상 범위 내에 있었습니다. "}, {"label": "시사점", "content": "혈액검사 상 내분비계 관련 지표들은 양호하나 다른 증상(다음다뇨/다식/ 탈모 등)이 생긴다면 내분비계 질환을 체크해 봐야 합니다. "}], "titleEn": "Endocrine System", "titleKo": "내분비계", "variant": "rows"}], "systemsPage4Blocks": [{"rows": [{"label": "주요 진단 내용", "content": "신체검사 중 구강 검진에서 중등도 수준의 치석이 확인되었습니다. 군데군데 치은염이 있습니다. "}, {"label": "시사점", "content": "중등도 치석은 치주염으로 진행될 수 있으며, 이는 구취, 잇몸 염증, 치아 손실 등의 문제를 야기할 수 있습니다. 정기적인 치과 관리가 필요하며, 스케일링을 통해 치석을 제거하고 구강 건강을 유지하는 것을 권장합니다."}], "titleEn": "Dental & Ophthalmology", "titleKo": "치과 및 안과", "variant": "rows"}, {"images": [{}, {}, {}, {}, {}, {}], "titleEn": "", "titleKo": "", "variant": "imagesGrid2x3"}, {"rows": [{"label": "주요 진단 내용", "content": "보호자 상담 시 토리가 앞다리 쪽을 씹고, 뒷다리와 사타구니, 항문 쪽을 핥는다는 증상이 확인되었습니다. 검이경 검사에서는 양측 외이도에 특이사항이 없었습니다. "}, {"label": "시사점", "content": "몸을 핥거나 씹는 행동은 알레르기, 피부염, 통증 등 다양한 원인에 의해 발생할 수 있습니다. 현재 알러지 가능성이 매우 높습니다. 증상이 미약하기 때문에 증상이 더 심해지면 알러지 관리가 필요할 수 있습니다. "}], "titleEn": "Skin & External Ear Canal", "titleKo": "피부와 외이도", "variant": "rows"}, {"images": [{}, {}, {}], "titleEn": "", "titleKo": "", "variant": "images"}], "systemsPage5Blocks": [{"rows": [{"label": "검사 결과 해석", "content": "흉부 경미한 간질/기관지성 패턴 관찰 됩니다. "}], "compact": true, "titleEn": "X-ray", "titleKo": "방사선 검사", "variant": "rows"}, {"images": [{"src": "jungdn-260427-02_242be746/2026-04-25/1777279951222_0_b6c29212.webp", "caption": "흉부 방사선"}, {"src": "jungdn-260427-02_242be746/2026-04-25/1777280039959_0_7e38b6f2.webp", "caption": "복부 방사선"}, {"src": "jungdn-260427-02_242be746/2026-04-25/1777279989188_0_16a2a318.webp", "caption": "관절 방사선"}, {"src": "jungdn-260427-02_242be746/2026-04-25/1777280077334_0_f24b2ebc.webp", "caption": "관절 방사선"}], "titleEn": "", "titleKo": "", "variant": "images4"}, {"rows": [{"label": "검사 결과 해석", "content": "복부 초음파 검사에서 간, 비장, 신장, 방광, 위장관 및 주위 림프절은 정상입니다. 담낭 내 미세 슬러지(미세 에코)가 관찰되었으며, 이는 담즙 농축으로 인한 담낭 질환 가능성이 있어 지속적인 추적 관찰이 권장됩니다."}], "compact": true, "titleEn": "Ultrasonography", "titleKo": "초음파 검사", "variant": "rows"}, {"images": [{"src": "jungdn-260427-02_242be746/2026-04-25/1777280188556_0_df836f0f.webp", "caption": "담낭 "}, {}, {}, {}, {}, {}, {}, {}, {}], "titleEn": "", "titleKo": "", "variant": "imagesGrid3x3"}], "coverPatientSpecies": "개", "recheckWithin1Month": "치과 스케일링 상담\\n중등도 치석에 대한 구강 관리 계획을 상의해 주십시오.", "systemsPage3bBlocks": [{"rows": [{"label": "주요 진단 내용", "content": "복부 초음파 검사에서 양쪽 신장과 방광에서는 형태학적으로 특이 소견이 관찰되지 않았습니다. 혈액검사 결과, BUN(17mg/dL) 및 Creatinine(1.1mg/dL) 수치 또한 모두 정상 범위 내로 확인되었습니다."}, {"label": "시사점", "content": "현재 신장 및 비뇨기계 기능은 양호한 것으로 판단됩니다. 평소 음수량과 배뇨량의 변화, 소변의 색깔 등 비뇨기계 관련 증상을 주의 깊게 관찰해 주시고, 정기적인 건강검진을 통해 신장 기능을 지속적으로 모니터링하는 것이 중요합니다."}], "titleEn": "Kidney & Urinary System", "titleKo": "신장 및 비뇨기계", "variant": "rows"}, {"rows": [{"label": "주요 진단 내용", "content": "복부 초음파 검사에서 간과 비장은 특이 소견이 없었으나, 담낭 내에 미세한 슬러지(미세 에코)가 관찰되었습니다. 혈액검사 결과, 간 효소 수치(ALT=29U/L, AST=33U/L, ALP=41U/L)는 모두 정상 범위 내에 있었습니다."}, {"label": "시사점", "content": "담낭 슬러지는 담즙이 농축되어 생기는 현상으로, 당장 임상 증상을 유발하지 않을 수 있지만, 향후 담낭점액낭종이나 담석으로 진행될 가능성이 있습니다. 따라서 임상 증상 여부를 주시하고, 1년 뒤 초음파 재검을 통해 슬러지의 변화 여부를 확인하는 것이 권장됩니다. 간 기능 수치는 양호하게 유지되고 있습니다."}], "titleEn": "Hepatobiliary System", "titleKo": "간담도계", "variant": "rows"}, {"rows": [{"label": "주요 진단 내용", "content": "방사선 검사 결과, 뒷다리에 큰 특이소견이 관찰되지 않았습니다. "}, {"label": "시사점", "content": "특이소견이 없었지만 혹시라도 파행이 발생된다면 슬개골 탈구 의심을 해볼 수 있기 때문에 임상증상이 생길 시 진료를 보러 오시는게 좋습니다. "}], "titleEn": "Musculoskeletal System", "titleKo": "근골격계", "variant": "rows"}], "recheckWithin3Months": "피부 상태 재평가\\n앞다리 쪽을 씹고 핥는 증상에 대한 변화를 살펴봅니다.", "recheckWithin6Months": "일반 건강 상태 확인\\n전반적인 건강 상태 재확인을 권장합니다.", "recheckWithin1to2Weeks": ""}'::jsonb, '2026-04-27 09:24:07.272937+00'::timestamptz, '2026-04-27 09:47:40.015+00'::timestamptz
);

