  id, parse_run_id, content_type, payload, created_at, updated_at
) values (
  '1814ba86-a2b6-4260-8bd9-724889b3cd63'::uuid, '875632e0-b225-49c2-ad2c-5a32122d1e6f'::uuid, 'health_checkup', E'{"followUpCare": "또치\\"의 건강 관리를 위해 다음과 같은 사후 관리 계획을 제안 드립니다. 중등도 치석과 치은염, 그리고 치주 질환이 의심되는 구강 상태 개선을 위해 빠른 시일 내에 치과 스케일링을 진행하여 치석을 제거하고 염증을 관리하는 것을 권장합니다. 스케일링 후에는 보호자님께서 가정에서 매일 양치질을 해 주시는 등 꾸준한 구강 위생 관리가 필수적입니다.\\n\\n안과적으로 확인된 수정체 혼탁과 결막 문제에 대해서는 안과 정밀 검진을 통해 정확한 원인과 진행 정도를 평가하고, 필요 시 추가적인 안약 처방 또는 치료 계획을 수립할 예정입니다. 보호자님께서는 \\"또치\\"의 눈곱, 충혈, 눈을 불편해하는 증상 등을 면밀히 관찰해 주시기 바랍니다.\\n\\n혈액 검사에서 높게 측정된 콜레스테롤 수치에 대해서는 식이 관리 및 생활 환경 개선을 먼저 시도하고, 1개월 후 혈액 재검을 통해 수치 변화를 모니터링할 계획입니다. 오른쪽 귀의 귀지 관리를 위해 귀 세정제를 사용하여 주기적으로 귀를 닦아주시고, 귀 분비물 증가나 냄새, 가려움 등의 증상이 보이면 즉시 내원해 주십시오. 또한, 필수 예방 접종 및 심장사상충 예방을 위한 진료도 함께 진행해 주시기를 당부드립니다.", "coverOwnerName": "김현지", "overallSummary": "이번 건강검진 결과, \\"또치\\"는 전반적으로 양호한 건강 상태를 보였으나 몇 가지 관리 및 추적 관찰이 필요한 소견들이 확인되었습니다. 구강 내 중등도의 치석과 치은염이 관찰되었으며, 이는 치주 질환으로 진행될 가능성이 있어 적극적인 치과 관리가 필요합니다.\\n\\n안과 검진에서는 양쪽 수정체 혼탁과 함께 결막의 충혈 및 부종, 혈관 증식, 동공 주변의 침착물이 확인되어 안구 건강에 대한 면밀한 관심이 요구됩니다.\\n\\n혈액 검사에서는 콜레스테롤 수치(CHOL 252 mg/dL)가 정상 범위보다 높게 측정되었으며, 평균 적혈구 헤모글로빈 농도(MCHC 36.0 g/dL) 또한 약간 상승된 소견을 보였습니다. 이는 식이 또는 대사 이상과 관련될 수 있으므로 추후 재평가가 필요합니다. 그 외 순환기, 호흡기, 소화기, 신장 및 비뇨기계, 간담도계 기능은 혈액 및 방사선 검사상 특이 소견 없이 양호하게 평가되었습니다. 오른쪽 귀에서 귀지가 관찰되었으나, 검이경 검사상 심각한 염증 소견은 보이지 않았습니다. 전반적으로 건강하나, 만성적인 치과 문제와 안과 소견, 그리고 혈액 수치 변화에 대한 지속적인 관리가 중요하겠습니다.", "coverPatientAge": "2019-07", "coverPatientSex": "암컷(중성화)", "coverCheckupDate": "2026-04-01", "coverPatientName": "또치", "coverPatientBreed": "C.S", "coverVeterinarian": "김혜정", "labInterpretation": "혈액 검사 결과 \\"또치\\"는 전반적으로 양호한 상태를 보였으나, 콜레스테롤 수치(CHOL)가 252 mg/dL로 정상 범위보다 높게 측정되었습니다. 또한, 평균 적혈구 헤모글로빈 농도(MCHC)가 36.0 g/dL로 약간 높게 나타났습니다. 그 외 SDMA, T4, proBNP를 포함한 대부분의 혈액학적 및 생화학적 지표들은 모두 정상 범위 내에 있어 내부 장기 기능 및 건강 상태가 대체로 양호한 것으로 판단됩니다.", "systemsPage3Blocks": [{"rows": [{"label": "주요 진단 내용", "content": "\\"또치\\"의 순환기 및 호흡기 관련 검사 결과, 청진 시 특이 소견은 확인되지 않았습니다. 심장 관련 바이오마커인 proBNP 수치는 65.6 pmol/L로 정상 범위 내에 있었으며, 흉부 방사선 사진에서도 심폐 윤곽은 정상적으로 평가되었고 명백한 병변은 관찰되지 않았습니다. 폐와 흉곽 구조 또한 뚜렷한 이상 소견 없이 건강한 상태로 확인되었습니다."}, {"label": "시사점", "content": "현재 \\"또치\\"는 순환기 및 호흡기 계통에서 특별한 이상 징후나 질병 소견이 확인되지 않아 양호한 상태를 유지하고 있습니다. 이는 심장과 폐 기능이 현재 건강하게 유지되고 있음을 시사합니다. 앞으로도 정기적인 건강검진을 통해 지속적으로 관리하는 것이 중요합니다."}], "titleEn": "Circulatory & Respiratory Systems", "titleKo": "순환기&호흡기", "variant": "rows"}, {"rows": [{"label": "주요 진단 내용", "content": "환자 \\"또치\\"는 보호자님의 문진상 한 달에 한두 번 털 섞인 구토를 하는 이력이 확인되었습니다. 하지만 혈액 검사 결과 췌장 효소인 Pancreatic Lipase는 <25.0 U/L로 정상 범위에 해당하며, FSAA는 5 ug/mL, AMYL은 933 U/L, LIPA는 73 U/L로 모두 정상 수치를 나타내어 췌장염 등의 소화기 염증 소견은 발견되지 않았습니다. 복부 방사선 사진에서도 복부 장기 및 위장관의 윤곽은 정상적으로 관찰되었으며, 명확한 이물이나 특이 병변은 확인되지 않았습니다."}, {"label": "시사점", "content": "털 섞인 구토는 고양이에게 흔히 나타날 수 있는 현상으로, 주로 그루밍 과정에서 섭취한 털이 위장관 내에 축적되어 발생합니다. 현재 검사 결과상 위장관 자체의 심각한 문제는 확인되지 않았으나, 지속적인 털 구토는 소화 불편감을 유발할 수 있으므로, 헤어볼 관리용 사료나 영양제 급여를 고려해 보시는 것이 좋겠습니다. 구토 빈도나 양상에 변화가 있다면 추가적인 진료가 필요합니다."}], "titleEn": "Digestive System", "titleKo": "소화기", "variant": "rows"}, {"rows": [{"label": "주요 진단 내용", "content": "\\"또치\\"의 내분비계 관련 검사 결과, 콜레스테롤(CHOL) 수치가 252 mg/dL로 정상 범위보다 높게 측정되었습니다. 반면, 갑상선 기능 관련 지표인 T4 수치는 2.96 µg/dL로 정상 범위에 있었고, 혈당(GLU)은 81 mg/dL, 중성지방(TRIG)은 68 mg/dL로 모두 정상 수치를 보였습니다. 전반적인 내분비 기능은 양호하나, 고콜레스테롤혈증이 확인되었습니다."}, {"label": "시사점", "content": "콜레스테롤 수치가 높게 측정된 것은 다양한 원인에 의해 발생할 수 있습니다. 이는 식이 요인, 유전적 소인, 혹은 다른 내분비 질환의 초기 징후일 수도 있습니다. 현재로서는 다른 내분비 지표들이 정상으로 확인되었으므로, 우선적으로 식이 관리 및 생활 습관 개선을 통해 수치를 조절해 보고 추후 재검을 통해 변화를 관찰하는 것이 중요합니다."}], "titleEn": "Endocrine System", "titleKo": "내분비계", "variant": "rows"}], "systemsPage4Blocks": [{"rows": [{"label": "주요 진단 내용", "content": "구강 검진 결과, \\"또치\\"는 중등도의 치석과 함께 치은염이 관찰되었으며, 구강 사진상 하악 잇몸에 치석과 홍반이 뚜렷하게 확인되어 치주 질환이 의심됩니다.\\n\\n안과 검진에서는 양쪽 눈(OU) 수정체 혼탁 소견이 발견되었으며, 슬릿램프 검사에서는 결막 부위에 충혈, 부종, 혈관 확장 및 증식이 다수 관찰되었습니다. 또한, 동공 부근에서 소량의 노란 점 형태의 침착물도 확인되었습니다."}, {"label": "시사점", "content": "구강 내 치석과 치은염은 만성 염증을 유발하고 심할 경우 치주 질환으로 진행되어 치아 손실 및 전신 건강에 영향을 미칠 수 있습니다. 이를 관리하기 위해 치과 스케일링이 필요하며, 꾸준한 양치질을 통해 치아 위생 관리에 신경 써 주셔야 합니다.\\n\\n수정체 혼탁은 노령성 변화일 수 있으나, 백내장 등의 진행 가능성도 배제할 수 없습니다. 결막의 충혈과 부종, 동공 주변 침착물에 대해서는 추가적인 안약 처방 또는 정밀 안과 검진을 고려해 볼 필요가 있습니다."}], "titleEn": "Dental & Ophthalmology", "titleKo": "치과 및 안과", "variant": "rows"}, {"images": [{"src": "nuel-260408-02_875632e0/2026-04-01/1775614990412_7_39806647.webp", "caption": "구강 검사 (치석 및 치은염)"}, {"src": "nuel-260408-02_875632e0/2026-04-01/1775614818268_0_99aeeace.webp", "caption": "안과 검사 (결막 충혈)"}, {"src": "nuel-260408-02_875632e0/2026-04-01/1775614819881_2_a9bd1340.webp", "caption": "안과 검사 (동공 침착)"}], "titleEn": "", "titleKo": "", "variant": "images"}, {"rows": [{"label": "주요 진단 내용", "content": "\\"또치\\"는 보호소에서 입양 당시 링웜 치료 이력이 있었으나, 현재는 해당 소견은 관찰되지 않습니다. 외이도 검진에서는 오른쪽 귀(AD)에 귀지가 확인되었습니다. 검이경을 통한 외이도 내부 관찰 시 점막과 분비물이 보였으나, 심각한 염증이나 특정 질환과 명확히 연관될 만한 병변은 뚜렷하게 확인되지 않았습니다."}, {"label": "시사점", "content": "과거 링웜 치료 이력은 있으나 현재 활성 병변이 없어 안심하셔도 좋습니다. 오른쪽 귀에 관찰된 귀지는 청결 관리가 필요한 부분이며, 주기적으로 귀 세정을 해 주시는 것이 좋습니다. 귀를 자주 긁거나 털거나 귀에서 냄새가 나는 등 이상 증상이 나타나면 외이염 등의 발생 가능성을 고려하여 다시 진료를 받아보시는 것이 중요합니다."}], "titleEn": "Skin & External Ear Canal", "titleKo": "피부와 외이도", "variant": "rows"}, {"images": [{"src": "nuel-260408-02_875632e0/2026-04-01/1775614988896_4_43040052.webp", "caption": "외이도 검사 (점막 및 분비물)"}, {"src": "nuel-260408-02_875632e0/2026-04-01/1775614989683_5_f9ab4314.webp", "caption": "외이도 검사 (점막 주름)"}, {}], "titleEn": "", "titleKo": "", "variant": "images"}], "systemsPage5Blocks": [{"rows": [{"label": "검사 결과 해석", "content": "흉부 방사선 검사 결과, 측면 및 배측-복부 사진에서 \\"또치\\"의 심장과 폐, 흉곽 구조가 정상적으로 평가되었으며, 특별한 확장이나 병변은 관찰되지 않았습니다. 복부 방사선 검사에서도 측면 및 배측-복부 사진 모두에서 복부 장기 윤곽이 정상적이었고, 위장관 및 장 내용물이 확인되었으나, 명확한 이물이나 염증 소견 등 특이 병변은 뚜렷하게 발견되지 않았습니다."}], "compact": true, "titleEn": "X-ray", "titleKo": "방사선 검사", "variant": "rows"}, {"images": [{"src": "nuel-260408-02_875632e0/2026-04-01/1775614987255_0_dc4d21be.webp", "caption": "흉부 방사선 (측면)"}, {"src": "nuel-260408-02_875632e0/2026-04-01/1775614988520_3_b945c32d.webp", "caption": "흉부 방사선 (배측-복부)"}, {"src": "nuel-260408-02_875632e0/2026-04-01/1775614987757_1_d0b1b890.webp", "caption": "복부 방사선 (측면)"}, {}], "titleEn": "", "titleKo": "", "variant": "images4"}, {"rows": [{"label": "검사 결과 해석", "content": "해당 프로그램 미포함 영역"}], "compact": true, "titleEn": "Ultrasonography", "titleKo": "초음파 검사", "variant": "rows"}, {"images": [{}, {}, {}, {}, {}, {}, {}, {}, {}], "titleEn": "", "titleKo": "", "variant": "imagesGrid3x3"}], "coverPatientSpecies": "Feline", "recheckWithin1Month": "혈액 재검 및 치과 상담\\n고콜레스테롤 재검 및 치과 스케일링 계획을 논의합니다.", "systemsPage3bBlocks": [{"rows": [{"label": "주요 진단 내용", "content": "\\"또치\\"의 신장 및 비뇨기계 검사 결과, 신장 기능 지표인 SDMA 수치는 11 ug/dL로 정상 범위에 속하였고, BUN 수치 또한 26 mg/dL로 정상으로 확인되었습니다. 보호자 문진상 배뇨 상태도 양호하다고 하셨습니다. 종합적으로 신장 및 비뇨기계와 관련된 검사 수치 및 문진 소견에서 특이적인 이상은 관찰되지 않았습니다."}, {"label": "시사점", "content": "현재 \\"또치\\"는 신장 및 비뇨기계 기능이 양호한 것으로 평가됩니다. 고양이의 경우 신장 질환 발병률이 높은 편이므로, 앞으로도 정기적인 검진을 통해 신장 기능을 꾸준히 모니터링하는 것이 중요합니다. 충분한 수분 섭취를 유도하고 양질의 사료를 급여하여 신장 건강을 유지해 주시길 바랍니다."}], "titleEn": "Kidney & Urinary System", "titleKo": "신장 및 비뇨기계", "variant": "rows"}, {"rows": [{"label": "주요 진단 내용", "content": "\\"또치\\"의 간담도계 관련 혈액 검사 결과, 간 수치인 ALT 49 U/L, AST 30 U/L, ALKP 31 U/L는 모두 정상 범위에 있었습니다. GGT는 <3 U/L, 총 빌리루빈(BIL-Total)은 <0.1 mg/dL로 측정되었으며, 알부민(ALB) 수치도 3.2 g/dL로 정상 범위였습니다. 복부 방사선 사진에서도 간을 포함한 복부 장기 윤곽에서 특이 소견은 뚜렷하지 않았습니다."}, {"label": "시사점", "content": "현재 \\"또치\\"의 간담도계 기능은 혈액 검사 및 방사선 사진상에서 특별한 이상 소견 없이 건강한 상태로 평가됩니다. 간은 체내 해독 작용 등 중요한 역할을 담당하므로, 앞으로도 정기적인 건강검진을 통해 간 기능을 지속적으로 확인하고 관리해 나가는 것이 중요합니다."}], "titleEn": "Hepatobiliary System", "titleKo": "간담도계", "variant": "rows"}, {"rows": [{"label": "주요 진단 내용", "content": "이번 건강검진에서 \\"또치\\"의 근골격계와 관련하여 특정 방사선 검사나 정형외과적 신체검사는 심층적으로 진행되지 않았습니다. 다만, 일반 흉부 및 복부 방사선 사진에서 주요 골격 구조가 평가되었으며, 해당 사진상에서 뚜렷한 골절이나 심각한 관절 변형과 같은 급성 이상 소견은 관찰되지 않았습니다."}, {"label": "시사점", "content": "현재 특별한 근골격계 질환의 증상은 보이지 않으나, 고양이의 경우 노령화가 진행됨에 따라 관절염이나 퇴행성 변화가 발생할 수 있습니다. 평소 \\"또치\\"가 움직임이 둔해지거나 특정 부위 통증을 호소하는 등의 변화가 있다면 본원에 내원하여 정밀 검사를 받아보시는 것이 좋습니다."}], "titleEn": "Musculoskeletal System", "titleKo": "근골격계", "variant": "rows"}], "recheckWithin3Months": "치과 스케일링\\n필요시 치과 스케일링을 통해 구강 건강을 관리합니다.", "recheckWithin6Months": "정기 건강검진\\n전반적인 건강 상태와 만성 질환 진행 여부를 확인합니다.", "recheckWithin1to2Weeks": "귀 청결 및 안약\\n귀지 관리 및 결막 충혈 확인을 위해 방문해 주세요."}'::jsonb, '2026-04-08 02:28:44.666153+00'::timestamptz, '2026-04-08 02:28:44.443+00'::timestamptz
);

