  id, parse_run_id, content_type, payload, created_at, updated_at
) values (
  'ea53eae1-0e30-44d4-9a64-74484c0e4c86'::uuid, '4ddf80b9-78ec-4eb4-8966-747ace19d079'::uuid, 'health_checkup', E'{"followUpCare": "구름이의 건강 관리를 위해 보호자님께서는 갑상선기능항진증과 심근비대증에 대한 꾸준한 약물 복용 및 정기적인 검진을 지속해 주셔야 합니다.\\n\\n갑상선 기능 및 심장 상태의 안정적인 유지를 위해 본원에서는 3~4개월 단위로 혈액 검사(CBC, T4, 간/신장 수치, SDMA 등)를 권장드리며, 심장 관련해서는 6개월 단위로 심장 초음파 재평가를 통해 심장 상태 변화를 면밀히 관찰할 예정입니다.\\n\\n가정에서는 매일 구름이의 호흡수를 체크하시고, 활동성, 식욕, 구토, 유연, 황달 등 특이 증상이 나타나는지 주의 깊게 살펴봐 주시기 바랍니다. 특히 호흡수가 비정상적으로 증가하거나 기침이 잦아지는 경우 즉시 본원으로 연락 주십시오.\\n\\n치과 건강 관리를 위해 스케일링을 통한 치석 제거 및 염증 치료를 계획하는 것이 좋습니다.\\n\\n외이도 염증에 대해서는 추가적인 검사 및 치료가 필요하며, 귀 분비물 증가나 가려움증 같은 증상이 있는지 지속적으로 관찰해 주십시오.\\n\\n방광 슬러지와 비장 변화에 대해서도 다음 검진 시 재평가를 통해 진행 상황을 확인하겠습니다.", "coverOwnerName": "채슬기", "overallSummary": "구름이는 2026년 4월 4일 종합 건강검진을 통해 전반적으로 양호한 건강 상태를 확인하였으나, 만성 질환에 대한 지속적인 관리가 중요하게 평가됩니다.\\n\\n특히 갑상선기능항진증은 지난 2년 간 약물(메티마졸)로 잘 관리되고 있으며, 이번 검진에서도 관련 특이사항은 추가로 확인되지 않았습니다.\\n\\n심장 초음파 검사 결과, 기존에 진단된 심근비대증이 확인되었고, 경미한 승모판 역류(Mild MR) 및 좌심실 유출로 폐색(LVOT) 소견이 관찰되었습니다. 이는 심장 기능에 영향을 줄 수 있으므로 꾸준한 모니터링이 필요합니다.\\n\\n혈액 검사상 BNP 수치가 다시 상승한 점은 심장 건강에 대한 주의를 요하는 부분입니다.\\n\\n구강 검진에서는 중등도의 치석과 잇몸 염증이 확인되어 치과 관리가 필요하며, 외이도에서는 갈색 귀지와 함께 내시경 영상에서 섬유성 구조물이 관찰되어 외이염 가능성을 배제할 수 없습니다.\\n\\n방광 슬러지와 비장 일부 고에코성 변화도 초음파 검사에서 관찰되어 추적 관찰이 필요합니다.", "coverPatientAge": "2013-03", "coverPatientSex": "수컷(중성화)", "coverCheckupDate": "2026-04-04", "coverPatientName": "구름", "coverPatientBreed": "Persian", "coverVeterinarian": "이덕원", "labInterpretation": "구름이의 혈액 검사는 전반적으로 양호한 결과를 보였습니다. 백혈구, 적혈구, 혈소판을 포함한 모든 혈구 수치는 정상 범위 내에 있습니다. 간 및 신장 기능 수치(ALT, AST, ALKP, BUN) 또한 정상으로, 주요 장기의 기능은 현재 안정적인 것으로 평가됩니다. 췌장 효소 수치(AMYL, LIPA, Pancreatic Lipase)와 혈당(GLU) 역시 정상 소견으로 확인되었습니다. 다만, BNP 수치가 다시 상승한 점은 심장 건강에 대한 주의 깊은 모니터링이 필요함을 시사합니다.", "systemsPage3Blocks": [{"rows": [{"label": "주요 진단 내용", "content": "심장 청진 시 심잡음이 확인되었으며, 심장 초음파 검사 결과 심근비대증과 함께 경미한 승모판 역류(Mild MR), 좌심실 유출로 폐색(LVOT) 소견이 관찰되었습니다.\\n\\n이는 기존의 심근비대증이 지속되고 있음을 시사합니다.\\n\\n혈액 검사에서는 심장 질환과 관련하여 BNP 수치가 상승한 것으로 확인되었습니다.\\n\\n흉부 방사선 검사상 폐 및 심영은 전반적으로 큰 이상이 없어 보이나, 임상 증상과 연계하여 수의사 추가 판독이 필요합니다."}, {"label": "시사점", "content": "구름이는 심근비대증과 경미한 승모판 역류를 가지고 있으며, BNP 수치 상승은 심장에 부담이 가중될 수 있음을 나타냅니다.\\n\\n보호자님께서는 평소 구름이의 호흡수와 활동성을 주의 깊게 관찰해 주셔야 합니다.\\n\\n갑작스러운 호흡곤란, 기침, 활력 저하 등의 증상이 나타나면 즉시 병원에 내원하여 정밀 검사를 받는 것이 중요합니다.\\n\\n현재 심장 약물 복용 여부는 확인되지 않으나, BNP 수치 상승을 고려하여 향후 약물 치료 계획을 논의할 수 있습니다."}], "titleEn": "Circulatory & Respiratory Systems", "titleKo": "순환기&호흡기", "variant": "rows"}, {"rows": [{"label": "주요 진단 내용", "content": "소화기 관련 혈액 검사 결과, 총 단백(TP), 알부민(ALB), 글로불린(GLOB) 등은 모두 정상 범위 내로 확인되었습니다.\\n\\n아밀라아제(AMYL), 리파아제(LIPA), 췌장 특이 리파아제(Pancreatic Lipase) 수치 또한 정상으로 확인되어 현재 췌장염 소견은 관찰되지 않습니다.\\n\\n복부 방사선 검사상 장내 가스 및 분변은 관찰되었으나, 뚜렷한 소화기계의 폐쇄나 급성 병변은 확인되지 않았습니다.\\n\\n간헐적인 연변 증상이 보고되었으나, 현재는 정상 변 상태를 유지하고 있습니다."}, {"label": "시사점", "content": "구름이는 현재 소화기계 전반에 걸쳐 큰 이상 소견은 확인되지 않아 양호한 상태를 보입니다.\\n\\n간헐적인 연변은 식이 변화나 스트레스 등 다양한 원인으로 발생할 수 있으므로, 보호자님께서는 평소 구름이의 식이 내용과 배변 상태를 꾸준히 관찰해 주시는 것이 중요합니다.\\n\\n만약 구토, 설사, 식욕 부진 등 소화기계 관련 증상이 지속되거나 악화될 경우, 본원에 내원하여 추가적인 검사를 받는 것을 권장드립니다.\\n\\n현재 복용 중인 약물이 소화기계에 미치는 영향은 낮은 것으로 판단됩니다."}], "titleEn": "Digestive System", "titleKo": "소화기", "variant": "rows"}, {"rows": [{"label": "주요 진단 내용", "content": "구름이는 갑상선기능항진증으로 2년째 갑상선 약물(메티마졸)을 복용하며 관리 중인 환자입니다.\\n\\n이번 검진 시에도 약물은 계속 처방되었으며, 혈액 검사상 혈당(GLU) 수치는 정상 범위로 확인되었습니다.\\n\\n다만, 갑상선 호르몬(T4) 수치 자체는 이번 검진 결과에서 직접적으로 제시되지 않았습니다.\\n\\n추가적인 내분비계 관련 호르몬 검사는 진행되지 않았습니다."}, {"label": "시사점", "content": "구름이의 갑상선기능항진증은 약물 복용을 통해 현재 잘 관리되고 있는 것으로 보입니다.\\n\\n치료 중인 만성 질환이므로, 보호자님께서는 처방된 갑상선 약물을 꾸준히 복용시켜 주시는 것이 매우 중요합니다.\\n\\n약물 복용 중 활력, 식욕, 음수량, 배변/배뇨 상태 및 구토, 유연 등의 부작용 여부를 면밀히 관찰해 주시고, 특이사항 발생 시 본원으로 문의 주십시오.\\n\\n3~4개월 단위로 T4 수치 및 관련 혈액 검사를 통해 갑상선 기능의 적절한 조절 여부를 지속적으로 평가할 계획입니다."}], "titleEn": "Endocrine System", "titleKo": "내분비계", "variant": "rows"}], "systemsPage4Blocks": [{"rows": [{"label": "주요 진단 내용", "content": "구강 검진 시 중등도의 치석 침착과 잇몸 염증(치은염) 소견이 확인되었습니다.\\n\\n이는 2021년 마지막 스케일링 이후 치아 관리가 부족했음을 시사합니다.\\n\\n구강 사진에서도 일부 치아 표면에 다량의 치석과 잇몸 가장자리 염증 의심 소견이 뚜렷하게 관찰됩니다.\\n\\n치아 흔들림이나 파절 등 심각한 치주 질환의 직접적인 증거는 현재 보고되지 않았습니다."}, {"label": "시사점", "content": "구름이는 현재 중등도의 치주 질환을 앓고 있으며, 이는 구취, 통증, 식욕 부진으로 이어질 수 있습니다.\\n\\n치석은 구강 내 세균 번식을 촉진하여 잇몸 염증을 악화시키고, 심한 경우 전신 건강에도 영향을 미칠 수 있습니다.\\n\\n따라서 빠른 시일 내에 스케일링을 통한 치석 제거 및 염증 치료를 진행하여 구강 건강을 회복시켜 주는 것이 중요합니다.\\n\\n스케일링 후에도 보호자님께서는 가정에서 정기적인 양치질이나 구강 관리 용품 사용을 통해 치석 재침착을 예방해 주시는 노력이 필요합니다."}], "titleEn": "Dental & Ophthalmology", "titleKo": "치과 및 안과", "variant": "rows"}, {"images": [{"src": "nuel-260408-03_4ddf80b9/2026-04-04/1775616082402_6_645231e9.webp", "caption": "구강 검사 — 치석"}, {}, {}], "titleEn": "", "titleKo": "", "variant": "images"}, {"rows": [{"label": "주요 진단 내용", "content": "피부 검진 결과, 전반적인 피부 상태는 특이사항 없이 양호한 것으로 확인되었습니다.\\n\\n하지만 양쪽 귀(AU)에서 갈색 귀지 증가 소견이 관찰되었습니다.\\n\\n검이경 내시경 영상에서는 외이도 관내에 가늘고 선 모양의 이물성 또는 섬유성 구조물이 관찰되어 외이염 가능성을 시사합니다.\\n\\n알레르기나 다른 피부 질환과 관련된 뚜렷한 병변은 현재 확인되지 않았습니다."}, {"label": "시사점", "content": "구름이의 피부는 건강한 상태이나, 귀에서 발견된 갈색 귀지와 외이도 내 이물성 구조물은 외이염을 강력히 의심하게 하는 소견입니다.\\n\\n외이염은 통증, 가려움증을 유발하여 생활의 질을 저하시킬 수 있으며, 방치할 경우 만성적인 문제로 발전하거나 중이염으로 진행될 수 있습니다.\\n\\n정확한 진단을 위해 추가적인 귀 내시경 검사 및 귀지 세포 검사를 통해 염증의 원인(세균, 곰팡이, 귀 진드기 등)을 파악하는 것이 필요합니다.\\n\\n보호자님께서는 구름이가 귀를 자주 긁거나 머리를 흔드는 등의 행동을 하는지 관찰해 주시고, 이상 증상 시 즉시 본원으로 내원해 주십시오."}], "titleEn": "Skin & External Ear Canal", "titleKo": "피부와 외이도", "variant": "rows"}, {"images": [{"src": "nuel-260408-03_4ddf80b9/2026-04-04/1775616080768_4_1f169ef6.webp", "caption": "외이도 내시경 검사"}, {}, {}], "titleEn": "", "titleKo": "", "variant": "images"}], "systemsPage5Blocks": [{"rows": [{"label": "검사 결과 해석", "content": "흉부 방사선 검사상 폐 실질 및 심장 음영에 전반적으로 뚜렷한 침윤이나 삼출, 이상 소견은 확인되지 않았습니다.\\n\\n복부 방사선 검사에서는 장내 가스와 분변이 관찰되었으나, 위장관의 명확한 폐쇄나 급성 병변은 확인되지 않았습니다.\\n\\n골반, 고관절 및 사지 방사선 검사에서는 골절이나 뚜렷한 골 병변, 뼈의 정렬 이상은 보이지 않았습니다.\\n\\n전반적으로 방사선 영상에서 생명에 위협을 주는 심각한 급성 병변은 발견되지 않았습니다."}], "compact": true, "titleEn": "X-ray", "titleKo": "방사선 검사", "variant": "rows"}, {"images": [{"src": "nuel-260408-03_4ddf80b9/2026-04-04/1775616537469_0_df35f0da.webp", "caption": "복부 방사선 (측면)"}, {"src": "nuel-260408-03_4ddf80b9/2026-04-04/1775616538001_1_ba6bf284.webp", "caption": "흉부 방사선 (측면)"}, {"src": "nuel-260408-03_4ddf80b9/2026-04-04/1775616539068_4_923adda8.webp", "caption": "골반 고관절 방사선"}, {"src": "nuel-260408-03_4ddf80b9/2026-04-04/1775616538712_3_5c6c9066.webp", "caption": "흉부 방사선 (배복측)"}], "titleEn": "", "titleKo": "", "variant": "images4"}, {"rows": [{"label": "검사 결과 해석", "content": "심장 초음파 컬러 도플러 영상에서 판막 주변에 색 혼합이 뚜렷한 혈류 제트가 관찰되었는데, 이는 경미한 승모판 역류(Mild MR) 소견을 뒷받침합니다.\\n\\n복부 초음파 검사에서는 방광 내부에 슬러지(침전물)가 확인되었으며, 비장 일부에서 고에코성 변화가 관찰되었습니다.\\n\\n그 외 복강 내 다른 장기에서는 뚜렷한 종괴나 비정상적인 구조 변화는 확인되지 않았습니다."}], "compact": true, "titleEn": "Ultrasonography", "titleKo": "초음파 검사", "variant": "rows"}, {"images": [{"src": "nuel-260408-03_4ddf80b9/2026-04-04/1775616078645_0_ce6936bf.webp", "caption": "심초음파 컬러 도플러"}, {"src": "nuel-260408-03_4ddf80b9/2026-04-04/1775616079368_1_254f2555.webp", "caption": "초음파 측정값 표 (1)"}, {"src": "nuel-260408-03_4ddf80b9/2026-04-04/1775616080003_2_a5fce1b3.webp", "caption": "초음파 판막 수치표 (2)"}, {"src": "nuel-260408-03_4ddf80b9/2026-04-04/1775616080392_3_dbf3e489.webp", "caption": "초음파 심장 치수표 (3)"}, {}, {}, {}, {}, {}], "titleEn": "", "titleKo": "", "variant": "imagesGrid3x3"}], "coverPatientSpecies": "Feline", "recheckWithin1Month": "갑상선 및 심장 기능 재평가\\n갑상선 약물 반응 및 심장 상태를 확인합니다.", "systemsPage3bBlocks": [{"rows": [{"label": "주요 진단 내용", "content": "신장 기능 관련 혈액 검사 결과, 혈중 요소 질소(BUN) 수치는 정상 범위로 확인되었습니다.\\n\\n추가 신장 기능 지표인 SDMA 수치는 이번 검진 결과에 포함되어 있지 않습니다.\\n\\n초음파 검사에서 방광 내 슬러지(침전물)가 관찰되었습니다. 이는 요로계 감염이나 결석 형성의 초기 단계일 수 있습니다.\\n\\n방광의 구조적 변화나 결석은 육안으로 확인되지 않았습니다."}, {"label": "시사점", "content": "구름이의 신장 기능은 현재 혈액 검사상 정상으로 평가되나, 초음파에서 확인된 방광 슬러지는 주의 깊은 관찰이 필요합니다.\\n\\n방광 슬러지는 음수량 부족, 식이, 감염 등 다양한 원인으로 발생할 수 있으며, 방치 시 방광염이나 요로결석으로 진행될 가능성이 있습니다.\\n\\n보호자님께서는 구름이의 음수량을 충분히 유지할 수 있도록 신경 써 주시고, 배뇨 시 불편함, 잦은 배뇨, 혈뇨 등의 증상이 있는지 관찰해 주시기 바랍니다.\\n\\n방광 슬러지에 대한 추적 초음파 검사를 통해 변화 양상을 확인하고, 필요 시 추가적인 요검사 또는 처치를 고려할 수 있습니다."}], "titleEn": "Kidney & Urinary System", "titleKo": "신장 및 비뇨기계", "variant": "rows"}, {"rows": [{"label": "주요 진단 내용", "content": "간담도계 관련 혈액 검사 결과, 알라닌 아미노전이효소(ALT), 아스파르테이트 아미노전이효소(AST), 알칼리성 인산분해효소(ALKP), 총 빌리루빈(BIL-Total) 수치는 모두 정상 범위로 확인되었습니다.\\n\\n감마 글루타밀 전이효소(GGT)는 측정되었으나 참고치가 없어 해석에 제한이 있습니다.\\n\\n초음파 검사에서 비장 일부에 고에코성 변화가 관찰되었습니다. 이는 비장 실질 내의 미묘한 변화를 시사할 수 있습니다.\\n\\n담낭 슬러지나 담관 확장 등 뚜렷한 담도계 이상은 보고되지 않았습니다."}, {"label": "시사점", "content": "구름이의 간 기능 관련 혈액 수치는 현재 양호한 상태를 보이며, 간담도계 질환의 증거는 명확히 확인되지 않았습니다.\\n\\n하지만 비장 일부의 고에코성 변화는 염증, 섬유화 또는 다른 미세 병변의 가능성을 배제할 수 없으므로, 추후 정기 검진 시 비장 크기 및 실질의 변화를 추적 관찰하는 것이 중요합니다.\\n\\n보호자님께서는 구름이의 활력 저하, 식욕 부진, 구토, 황달 등 간담도계 관련 증상이 나타나는지 주의 깊게 살펴봐 주시기 바랍니다.\\n\\n현재 처방된 간 영양제(실리마린, UDCA)는 간 보호 및 기능 유지를 돕는 데 도움이 될 수 있습니다."}], "titleEn": "Hepatobiliary System", "titleKo": "간담도계", "variant": "rows"}, {"rows": [{"label": "주요 진단 내용", "content": "이번 건강검진에서 근골격계에 대한 특별한 임상 증상은 보고되지 않았습니다.\\n\\n방사선 검사에서는 골반 및 고관절, 사지 부위에서 골절이나 뚜렷한 골 병변은 관찰되지 않았으며, 뼈의 정렬과 골밀도도 명확한 이상 소견은 보이지 않았습니다.\\n\\n다만, 관절 내부 병변 여부나 통증의 원인 평가는 추가적인 수의사 판독이 필요하다고 언급되어 있습니다.\\n\\n뒷다리 관련 내용이 CC에 있으나, 검사 결과상 특이 소견은 명확히 기록되어 있지 않습니다."}, {"label": "시사점", "content": "구름이의 근골격계 방사선 검사 결과는 전반적으로 양호한 것으로 평가됩니다.\\n\\n하지만 뒷다리 관련 증상 및 관절 내부 병변 가능성에 대한 언급이 있으므로, 보호자님께서는 구름이가 걷거나 뛸 때 불편해하는 모습, 다리를 저는 증상, 특정 관절 부위를 만졌을 때 통증을 느끼는 등의 변화가 있는지 주의 깊게 관찰해 주십시오.\\n\\n만약 통증이나 불편함을 나타내는 증상이 발견될 경우, 본원에 내원하여 보다 정밀한 신체검사 및 필요 시 추가 영상 검사를 진행하는 것을 권장드립니다.\\n\\n집에서 관절에 무리가 가지 않도록 적절한 활동량을 유지해 주시는 것도 중요합니다."}], "titleEn": "Musculoskeletal System", "titleKo": "근골격계", "variant": "rows"}], "recheckWithin3Months": "혈액검사(T4, 신장)\\n갑상선 기능 및 주요 장기 수치 추이를 확인합니다.", "recheckWithin6Months": "심장 초음파 재평가\\n심근비대증 및 판막 역류 진행 여부를 관찰합니다.", "recheckWithin1to2Weeks": "외이도 검사 및 치료\\n외이도 염증에 대한 추가 검사 및 치료를 진행합니다."}'::jsonb, '2026-04-08 02:53:42.34234+00'::timestamptz, '2026-04-08 02:53:41.576+00'::timestamptz
);

