  id, parse_run_id, content_type, payload, created_at, updated_at
) values (
  'ef3d07fe-e22a-461e-a3e4-a773c715c7fb'::uuid, '8e318390-c9ed-419a-97b8-5667d7996924'::uuid, 'health_checkup', E'{"followUpCare": "이번 검진에서 확인된 구강 내 치석은 향후 치주 질환으로 진행될 수 있으므로, 현재 처방된 구내염 내복약을 복용하시면서 가정에서 꾸준한 양치 관리를 강화해 주시는 것이 중요합니다. 만약 치석이 조절되지 않거나 구강 내 불편함이 지속될 경우 스케일링을 계획해 볼 수 있습니다.\\n\\n슬개골 탈구와 관련하여서는 과격한 활동을 제한하고 적절한 체중을 유지하는 생활 관리가 필요합니다. 파행이나 통증 등의 증상이 나타나면 즉시 본원으로 내원하여 추가적인 평가를 받아보시는 것을 권장합니다.\\n\\n담낭 슬러지 및 콩팥 석회화는 현재 임상 증상이 없지만, 3개월 후 복부 초음파 재검진을 통해 변화 여부를 확인하고 장기적인 관찰 계획을 수립할 예정입니다. 전반적인 건강 관리를 위해 주기적인 건강검진을 통해 건강 상태를 지속적으로 모니터링하는 것이 필요합니다.", "coverOwnerName": "박문숙", "overallSummary": "이번 건강검진에서 베로는 전반적으로 양호한 건강 상태를 보였습니다. 주요 특이사항으로는 구강 내 경도에서 중등도의 치석 침착이 확인되었으며, 이로 인한 입 냄새가 보고되었습니다.\\n\\n근골격계 검진에서는 좌측 1단계, 우측 2단계의 내측 슬개골 탈구가 진단되었습니다. 이는 활동 시 불편함을 유발할 수 있으므로 지속적인 관찰이 필요합니다.\\n\\n영상 검사에서는 복부 초음파를 통해 담낭 내 슬러지와 좌측 신장에 경미한 석회화 소견이 관찰되었으나, 현재는 임상 증상을 유발하지 않는 것으로 판단됩니다. 혈액 검사 결과는 대부분 정상 범위 내였으며, 일부 항목의 경미한 변동은 현재 임상적으로 큰 의미를 두기 어렵습니다. 전반적으로 큰 문제가 없으나, 발견된 소견들에 대해서는 추적 관찰 및 관리가 중요합니다.", "coverPatientAge": "7", "coverPatientSex": "수컷(중성화)", "coverCheckupDate": "2026-04-15", "coverPatientName": "베로", "coverPatientBreed": "Maltipo", "coverVeterinarian": "백동기", "labInterpretation": "베로의 혈액 검사 결과는 전반적으로 양호합니다. 다만, 림프구 비율(%LYM 36.5%)이 다소 높고 호중구 비율(WBCGRANS% 58%)이 낮게 관찰되었으나, 전반적인 백혈구 수치는 정상입니다. 알부민/글로불린 비율(ALB/GLOB 2)도 경미한 변화를 보이나, 다른 항목들은 모두 정상 범위 내로 확인되어 현재는 임상적으로 큰 의미를 두지 않습니다.", "systemsPage3Blocks": [{"rows": [{"label": "주요 진단 내용", "content": "흉부 방사선 검사 결과, 심장 크기(VHS 9.5)는 정상 범위 내로 확인되었습니다. 기관 및 폐에서 특이 소견은 관찰되지 않았습니다. 청진 시 심잡음은 확인되지 않았습니다."}, {"label": "시사점", "content": "현재 베로의 순환기 및 호흡기 계통에서는 특별한 이상 소견이 발견되지 않았습니다. 이는 심장과 폐의 기능이 현재 양호함을 시사합니다. 향후 호흡곤란, 기침 등의 증상이 나타나면 본원으로 내원하시기 바랍니다."}], "titleEn": "Circulatory & Respiratory Systems", "titleKo": "순환기&호흡기", "variant": "rows"}, {"rows": [{"label": "주요 진단 내용", "content": "복부 방사선 및 초음파 검사 결과, 소화기계(위, 장 등)에서 특이 소견은 관찰되지 않았습니다. 혈액 검사 결과에서도 소화기 관련 지표는 정상 범위 내로 확인되었습니다."}, {"label": "시사점", "content": "현재 베로의 소화기계는 건강한 상태로 판단됩니다. 구토, 설사, 식욕 부진 등의 소화기 증상이 지속될 경우 추가적인 검사가 필요할 수 있으니 주의 깊게 살펴봐 주시기 바랍니다."}], "titleEn": "Digestive System", "titleKo": "소화기", "variant": "rows"}, {"rows": [{"label": "주요 진단 내용", "content": "혈액 검사에서 포도당(GLU 101 mg/dL) 수치를 포함한 내분비 관련 지표들은 모두 정상 범위 내로 확인되었습니다. 다음다뇨나 체중 변화 등 내분비계 이상을 시사하는 임상 증상은 관찰되지 않았습니다."}, {"label": "시사점", "content": "현재 검진 결과로는 내분비계 질환의 가능성이 낮습니다. 그러나 연령이 증가함에 따라 당뇨병이나 갑상선 기능 이상 등 내분비 질환 발생 가능성이 있으므로, 음수량, 배뇨량, 식욕 및 체중 변화를 지속적으로 관찰하는 것이 중요합니다."}], "titleEn": "Endocrine System", "titleKo": "내분비계", "variant": "rows"}], "systemsPage4Blocks": [{"rows": [{"label": "주요 진단 내용", "content": "구강 검진 및 이미지 분석 결과, 치아 표면에 경도에서 중등도 수준의 치석 침착이 관찰되었습니다. 잇몸에서는 경미한 염증 소견이 동반된 것으로 보이며, 보호자께서는 평소 입 냄새를 인지하셨습니다."}, {"label": "시사점", "content": "치석은 구내염 및 치주염의 원인이 될 수 있으며, 이는 구강 건강뿐 아니라 전신 건강에도 영향을 미칠 수 있습니다. 현재 구내염에 대한 내복약 복용과 함께 꾸준한 양치 관리를 통해 치석 관리에 힘써 주시고, 조절되지 않을 경우 스케일링을 고려해 볼 수 있습니다."}], "titleEn": "Dental & Ophthalmology", "titleKo": "치과 및 안과", "variant": "rows"}, {"images": [{"src": "baek-260429-05_8e318390/2026-04-15/1777437760686_0_c39cb9e8.webp", "caption": "치아"}, {"src": "baek-260429-05_8e318390/2026-04-15/1777437795685_0_4a8a6c94.webp", "caption": "치아"}, {"src": "baek-260429-05_8e318390/2026-04-15/1777437838699_0_6a757151.webp", "caption": "슬릿램프"}, {"src": "baek-260429-05_8e318390/2026-04-15/1777437862685_0_7ed58816.webp", "caption": "슬릿램프"}, {"src": "baek-260429-05_8e318390/2026-04-15/1777437817895_0_fd48eb90.webp", "caption": "치아"}, {"src": "baek-260429-05_8e318390/2026-04-15/1777437885130_0_e5afcbbc.webp", "caption": "치아"}], "titleEn": "", "titleKo": "", "variant": "imagesGrid2x3"}, {"rows": [{"label": "주요 진단 내용", "content": "신체검사 결과, 우측 팔꿈치 부위에 작은 돌기성 병변(skin tag)이 확인되었습니다. 복부 피부는 다른 부위에 비해 얇아 보였습니다. 다른 피부 부위 및 외이도에서는 특이 소견이 관찰되지 않았습니다."}, {"label": "시사점", "content": "우측 팔꿈치 스킨 태그는 양성 종양으로 판단되며, 현재로서는 특별한 처치 없이 경과 관찰이 가능합니다. 크기나 형태 변화, 출혈 등의 증상이 나타나면 본원에 재내원하여 재평가해 주십시오. 얇은 복부 피부는 품종 특성일 수 있습니다."}], "titleEn": "Skin & External Ear Canal", "titleKo": "피부와 외이도", "variant": "rows"}, {"images": [{"src": "baek-260429-05_8e318390/2026-04-15/1777438063848_0_43a9c6cb.webp", "caption": "피부"}, {"src": "baek-260429-05_8e318390/2026-04-15/1777437927961_0_6ead0440.webp", "caption": "검이경"}, {"src": "baek-260429-05_8e318390/2026-04-15/1777438004472_0_f8331e6e.webp", "caption": "복부"}], "titleEn": "", "titleKo": "", "variant": "images"}], "systemsPage5Blocks": [{"rows": [{"label": "검사 결과 해석", "content": "흉부 방사선 영상에서는 심장 크기(VHS 9.5)가 정상 범위였으며, 기관과 폐 실질에서 염증이나 종괴와 같은 특이 소견은 관찰되지 않았습니다. 복부 방사선 영상에서도 특별한 이상 소견은 확인되지 않았습니다."}], "compact": true, "titleEn": "X-ray", "titleKo": "방사선 검사", "variant": "rows"}, {"images": [{"src": "baek-260429-05_8e318390/2026-04-15/1777440006984_0_dfab73ca.webp", "caption": "복부 방사선"}, {"src": "baek-260429-05_8e318390/2026-04-15/1777439987358_0_52e98119.webp", "caption": "복부 방사선"}, {"src": "baek-260429-05_8e318390/2026-04-15/1777440025353_0_bdac4be4.webp", "caption": "흉부 방사선"}, {"src": "baek-260429-05_8e318390/2026-04-15/1777440043806_0_de00bb2b.webp", "caption": "흉부 방사선"}], "titleEn": "", "titleKo": "", "variant": "images4"}, {"rows": [{"label": "검사 결과 해석", "content": "복부 초음파 검사에서 담낭 내 슬러지로 보이는 침전물이 관찰되었고, 좌측 신장에 경미한 석회화 소견이 확인되었습니다. 전반적인 영상은 빈호흡으로 인해 약간 흔들릴 수 있었으나, 다른 장기에서는 특이 소견이 없었습니다."}], "compact": true, "titleEn": "Ultrasonography", "titleKo": "초음파 검사", "variant": "rows"}, {"images": [{"src": "baek-260429-05_8e318390/2026-04-15/1777438897178_0_487cb63e.webp", "caption": "복부 초음파"}, {"src": "baek-260429-05_8e318390/2026-04-15/1777438996167_0_605e3e62.webp", "caption": "복부 초음파"}, {"src": "baek-260429-05_8e318390/2026-04-15/1777438510765_0_b26c69d6.webp", "caption": "복부 초음파"}, {"src": "baek-260429-05_8e318390/2026-04-15/1777438538424_0_0c34969b.webp", "caption": "복부 초음파"}, {"src": "baek-260429-05_8e318390/2026-04-15/1777438550703_0_3dd5a042.webp", "caption": "복부 초음파"}, {"src": "baek-260429-05_8e318390/2026-04-15/1777438790652_0_01055e1c.webp", "caption": "복부 초음파"}, {}, {}, {}], "titleEn": "", "titleKo": "", "variant": "imagesGrid3x3"}], "coverPatientSpecies": "개", "recheckWithin1Month": "전반적인 건강 상태 점검\\n일상생활에서의 특이사항 여부를 확인합니다.", "systemsPage3bBlocks": [{"rows": [{"label": "주요 진단 내용", "content": "복부 초음파 검사에서 좌측 신장에 경미한 석회화 소견이 관찰되었습니다. 혈액 검사상 신장 기능 관련 지표인 BUN 18.1 mg/dL, CREA 0.82 mg/dL는 정상 범위였습니다. 요검사는 진행되지 않았습니다."}, {"label": "시사점", "content": "좌측 신장의 경미한 석회화는 현재 임상 증상을 유발할 가능성이 낮습니다. 하지만 이는 향후 신장 기능에 영향을 줄 수 있으므로, 3개월 후 재검진을 통해 경과를 면밀히 관찰하는 것이 권장됩니다. 평소 음수량 증가에 신경 써 주시면 좋습니다."}], "titleEn": "Kidney & Urinary System", "titleKo": "신장 및 비뇨기계", "variant": "rows"}, {"rows": [{"label": "주요 진단 내용", "content": "복부 초음파 검사 결과, 담낭 내에 슬러지(침전물)가 관찰되었습니다. 혈액 검사에서 간 수치(ALT 32 U/L, GGT 7 U/L)는 모두 정상 범위 내로 확인되었습니다. 간 실질에는 특이 소견이 없었습니다."}, {"label": "시사점", "content": "담낭 슬러지는 염증이나 담즙 정체로 인해 발생할 수 있으며, 현재는 임상 증상을 유발하지 않는 것으로 보입니다. 하지만 향후 담석 등으로 진행될 가능성이 있으므로, 3개월 후 초음파 재검진을 통해 담낭 상태를 추적 관찰하는 것이 중요합니다."}], "titleEn": "Hepatobiliary System", "titleKo": "간담도계", "variant": "rows"}, {"rows": [{"label": "주요 진단 내용", "content": "신체검사 결과, 좌측 슬개골은 1단계, 우측 슬개골은 2단계 내측 탈구가 확인되었습니다. 방사선 검사상 골절이나 관절의 심각한 변형은 관찰되지 않았습니다."}, {"label": "시사점", "content": "슬개골 탈구는 관절의 불안정성을 유발하며, 우측은 좌측보다 진행된 상태입니다. 통증이나 파행을 유발할 수 있으므로, 과격한 운동을 피하고 체중 관리에 신경 써 주시는 것이 중요합니다. 증상 발현 시 본원으로 내원하시기 바랍니다."}], "titleEn": "Musculoskeletal System", "titleKo": "근골격계", "variant": "rows"}], "recheckWithin3Months": "담낭 및 신장 상태 재검진\\n담낭 슬러지 및 콩팥 석회화의 경과를 관찰합니다.", "recheckWithin6Months": "슬개골 탈구 진행 여부 확인\\n슬개골 탈구의 임상 증상 및 진행 정도를 평가합니다.", "recheckWithin1to2Weeks": "구내염 및 양치 관리 확인\\n구내염 내복약 복용 후 경과를 확인합니다."}'::jsonb, '2026-04-29 05:23:54.354404+00'::timestamptz, '2026-04-29 05:51:20.136+00'::timestamptz
);

