  id, parse_run_id, content_type, payload, created_at, updated_at
) values (
  '74373e51-3cc0-4ebb-a208-9871293abb4b'::uuid, '93130b68-93f4-4e63-9593-e3aeea157b03'::uuid, 'health_checkup', E'{"coverProgram": "기본", "followUpCare": "3개월 이내 간수치 체크를 권장드립니다.\\n\\n양치질과 주기적인 스케일링으로 치아를 관리해 주세요.\\n\\n양측 눈에 처방된 안약을 꾸준히 점안하여 주세요. 향후 재검이 권장됩니다.\\n\\n지간 소독, 보습 등 적합한 방법으로 피부를 관리해 주세요. 오메가 3 등 영양제가 권장됩니다.\\n\\n관절 건강을 위해 적정 체중 유지와 관절 영양제가 권장됩니다.", "coverOwnerName": "조인경", "overallSummary": "혈구검사, 신장 수치 등 전반적인 혈액검사 결과가 정상범위로 확인됩니다.\\n\\n심장 관련 BNP 수치, 신장의 이상을 조기에 확인하는 SDMA 수치, 췌장효소수치(cPL), 갑상선 수치(T4)도 정상 범위로 확인됩니다.\\n\\n일부 간수치(AST)의 경도 상승이 확인됩니다.\\n\\n구강 검진 시 경미한 치석과 어금니, 송곳니 주위 치은염이 관찰되었습니다. \\n\\n양안 결막충혈과 결막염 소견이 관찰됩니다.\\n\\n피부가 전반적으로 건조하며 각질이 있고, 사지 지간 발적과 피부염이 관찰됩니다.  \\n\\n양측 귓바퀴 발적이 확인됩니다. 귀를 털거나 불편해 하지 않는지 지켜봐 주세요. 주기적인 귀 세정이 권장됩니다. \\n\\n우측 슬개골 탈구가 관찰됩니다.", "coverPatientAge": "4", "coverPatientSex": "수컷(중성화)", "coverCheckupDate": "2026-04-21", "coverPatientName": "바다", "coverPatientBreed": "푸들", "coverVeterinarian": "이덕원", "labInterpretation": "혈액 검사 결과, 간 수치 중 AST가 62 U/L로 경미하게 상승한 소견 외에 다른 혈액학 및 혈청학적 지표들은 대부분 정상 범위로 확인되었습니다.\\n\\n아밀라아제(AMYL) 수치가 낮게 측정되었으나, 췌장 특이 리파아제(cPL)는 정상입니다.\\n\\n적혈구 지표 중 MCV, MCHC에 일부 변화가 있으나, 전반적인 적혈구 수치는 정상입니다.", "coverPatientWeight": "3.2kg", "systemsPage3Blocks": [{"rows": [{"label": "주요 진단 내용", "content": "proBNP 수치는 739 pmol/L로 정상 범위에 속합니다.\\n\\n청진 시 심음 및 폐음은 정상 소견을 보였습니다."}, {"label": "시사점", "content": "현재 순환기 및 호흡기 관련 검사에서는 특이적인 질환 소견이 관찰되지 않았습니다.\\n\\n호흡 곤란 등 이상 증상 발생 시 내원해 주시기 바랍니다."}], "titleEn": "Circulatory & Respiratory Systems", "titleKo": "순환기&호흡기", "variant": "rows"}, {"rows": [{"label": "주요 진단 내용", "content": "혈액 검사에서 아밀라아제(AMYL) 수치가 445 U/L로 정상 범위보다 다소 낮게 측정되었으나, 췌장 특이 리파아제(cPL) 및 리파아제(LIPA) 수치는 각각 54.7 U/L, 291 U/L로 정상 범위였습니다.\\n\\n"}, {"label": "시사점", "content": "전반적인 췌장 수치는 양호하게 확인됩니다. 평소 구토, 설사 등 소화기 관련 증상이 발생하지 않는지 모니터링 해 주세요."}], "titleEn": "Digestive System", "titleKo": "소화기", "variant": "rows"}, {"rows": [{"label": "주요 진단 내용", "content": "갑상선 호르몬(T4) 수치는 3.47 µg/dL로 정상 범위였습니다.\\n\\n혈당(GLU)은 91 mg/dL, 콜레스테롤(CHOL)은 177 mg/dL, 중성지방(TRIG)은 78 mg/dL로 모두 정상 소견을 보였습니다."}, {"label": "시사점", "content": "이번 검진에서 측정된 주요 내분비계 관련 수치들은 모두 정상 범위에 있어 현재 내분비계 이상 소견은 확인되지 않습니다.\\n\\n특별히 우려할 만한 사항은 없으나, 평소 체중이나 활동량 변화를 지속적으로 관찰해 주시면 좋습니다."}], "titleEn": "Endocrine System", "titleKo": "내분비계", "variant": "rows"}], "systemsPage4Blocks": [{"rows": [{"label": "주요 진단 내용", "content": "구강 검진 시 경미한 치석(mild tartar)과 잇몸 염증(gingivitis)이 관찰되었습니다.\\n\\n안과 검진에서는 양안 결막염 소견이 관찰되었습니다."}, {"label": "시사점", "content": "잇몸 염증과 치석은 구강 건강의 악화와 전신 건강 문제로 이어질 수 있으므로, 전문적인 치과 검진 및 스케일링을 통한 관리가 필요합니다.\\n\\n양안 결막염은 눈 주위 자극이나 감염으로 인한 증상일 수 있으며 꾸준한 안약 점안과 모니터링이 필요합니다. "}], "titleEn": "Dental & Ophthalmology", "titleKo": "치과 및 안과", "variant": "rows"}, {"images": [{"src": "nuel-260502-01_93130b68/2026-04-21/1777685054006_0_d7763a5a.webp", "caption": "사진", "rotationDeg": 0}, {"src": "nuel-260502-01_93130b68/2026-04-21/1777685066123_0_0d65e008.webp", "caption": "치아", "rotationDeg": 0}, {"src": "nuel-260502-01_93130b68/2026-04-21/1777685043781_0_de577059.webp", "caption": "치아"}, {"src": "nuel-260502-01_93130b68/2026-04-21/1777685032373_0_586376f7.webp", "caption": "치아", "rotationDeg": 0}, {"src": "nuel-260502-01_93130b68/2026-04-21/1777685138424_0_4e4843b1.webp", "caption": "안과"}, {"src": "nuel-260502-01_93130b68/2026-04-21/1777685126918_0_d76cec93.webp", "caption": "안과"}], "titleEn": "", "titleKo": "", "variant": "imagesGrid2x3"}, {"rows": [{"label": "주요 진단 내용", "content": "전신적으로 피부 건조, 각질, 피부염 소견이 관찰되었으며, 사지 지간 발적도 확인되었습니다.\\n\\n양측 귓바퀴 발적이 확인되었습니다."}, {"label": "시사점", "content": "피부 건조 및 각질, 피부염 개선을 위해 적절한 보습 관리와 처방 샴푸, 보습제 사용이 권장됩니다. 만성적인 재발이 있는 경우 원인 파악을 위한 추가 검진이 필요합니다."}], "titleEn": "Skin & External Ear Canal", "titleKo": "피부와 외이도", "variant": "rows"}, {"images": [{"src": "nuel-260502-01_93130b68/2026-04-21/1777685105957_0_6e96beaf.webp", "caption": "검이경"}, {"src": "nuel-260502-01_93130b68/2026-04-21/1777685116578_0_a7bf2263.webp", "caption": "검이경"}, {}], "titleEn": "", "titleKo": "", "variant": "images"}], "systemsPage5Blocks": [{"rows": [{"label": "검사 결과 해석", "content": "\\n\\n"}], "compact": true, "titleEn": "X-ray", "titleKo": "방사선 검사", "variant": "rows"}, {"images": [{"src": "nuel-260502-01_93130b68/2026-04-21/1777685079732_0_edb62ae7.webp", "caption": "흉부 방사선"}, {"src": "nuel-260502-01_93130b68/2026-04-21/1777685095402_0_edb1f98f.webp", "caption": "흉부 방사선"}, {"src": "nuel-260502-01_93130b68/2026-04-21/1777684997993_0_1ddcae3d.webp", "caption": "복부 방사선"}, {"src": "nuel-260502-01_93130b68/2026-04-21/1777685010152_0_f8795c55.webp", "caption": "복부 방사선"}], "titleEn": "", "titleKo": "", "variant": "images4"}, {"rows": [{"label": "검사 결과 해석", "content": "해당 프로그램 미포함 영역"}], "compact": true, "titleEn": "Ultrasonography", "titleKo": "초음파 검사", "variant": "rows"}, {"images": [{}, {}, {}, {}, {}, {}, {}, {}, {}], "titleEn": "", "titleKo": "", "variant": "imagesGrid3x3"}], "coverPatientSpecies": "개", "recheckWithin1Month": "구강 재진\\n치과 검진 및 스케일링 상담이 권장됩니다.", "systemsPage3bBlocks": [{"rows": [{"label": "주요 진단 내용", "content": "신장 수치인 혈액요소질소(BUN)는 17 mg/dL, 크레아티닌(Creatinine)은 정상 범위였으며, 신장 특이적 지표인 SDMA는 6 ug/dL로 모두 정상으로 확인되었습니다."}, {"label": "시사점", "content": "신장 및 비뇨기계 관련 혈액 검사 수치는 모두 양호한 상태를 보이고 있어, 현재 신장 기능에 대한 특별한 이상 소견은 관찰되지 않습니다.\\n\\n정기적인 수분 섭취와 규칙적인 배뇨 활동을 유지하는 것이 중요합니다."}], "titleEn": "Kidney & Urinary System", "titleKo": "신장 및 비뇨기계", "variant": "rows"}, {"rows": [{"label": "주요 진단 내용", "content": "혈액 검사 결과, 간 수치 중 ALT는 88 U/L로 정상, ALP는 18 U/L로 정상 범위였습니다.\\n\\nAST는 62 U/L로 정상 범위보다 약간 높게 측정되었으며, GGT는 5 U/L로 정상입니다.\\n\\n빌리루빈(TBIL)은 <0.1 mg/dL로 정상 범위에 해당합니다."}, {"label": "시사점", "content": "간 수치 중 AST가 미약하게 상승한 소견이 있으나, 다른 간 수치는 정상 범위에 있습니다.\\n\\n간 기능의 지속적인 관찰을 위해 3~6개월 후 간 기능 검사 재진행을 통해 변화 여부를 확인하는 것이 좋습니다."}], "titleEn": "Hepatobiliary System", "titleKo": "간담도계", "variant": "rows"}, {"rows": [{"label": "주요 진단 내용", "content": "우측 슬개골 탈구 소견이 확인되었습니다.\\n\\n신경계 검사는 정상 소견을 보였습니다."}, {"label": "시사점", "content": "우측 슬개골 탈구는 관리가 필요합니다.\\n\\n체중 관리와 함께 관절 건강 보조제 급여 및 적절한 운동 관리가 중요하며, 증상 악화 시 내원하여 평가받는 것이 좋습니다."}], "titleEn": "Musculoskeletal System", "titleKo": "근골격계", "variant": "rows"}], "recheckWithin3Months": "혈액검사재검\\n혈액검사 재진을 권고합니다.", "recheckWithin6Months": "종합 건강 재평가\\n전반적인 건강 상태 및 만성 질환 관리를 위한 재검진입니다.", "recheckWithin1to2Weeks": "피부 및 안과 재진\\n피부염, 외이염 및 결막염 개선 여부 확인을 위해 재진 바랍니다."}'::jsonb, '2026-05-02 01:27:07.534096+00'::timestamptz, '2026-05-02 02:16:24.358+00'::timestamptz
);

insert into staging.generated_run_content (
  id, parse_run_id, content_type, payload, created_at, updated_at
) values (
  'ca4fde45-4f1d-4897-b917-e41c14bb705c'::uuid, '9ed65e47-b711-4aed-a34a-42db249e57ca'::uuid, 'health_checkup', E'{"followUpCare": "요미의 건강 상태를 고려하여 다음과 같은 사후 관리 계획을 제안합니다. 우선, 확인된 만성 신장 질환에 대해서는 신장 기능 보호를 위한 처방식 전환을 권장하며, 주기적인 신장 기능 검사를 통해 질환의 진행 양상을 평가하고 필요시 약물 치료를 고려할 예정입니다. 췌장염 의심 소견에 대해서는 추가적인 췌장 효소 검사 및 영상 재평가를 통해 정확한 진단을 진행할 것이며, 적절한 식이 관리 및 치료를 시작할 것입니다.\\n\\n간에서 발견된 다수의 결절은 악성 여부를 확인하기 위해 조직 검사 또는 세침 흡인 검사를 통한 정밀 진단이 필수적입니다. 이 결과에 따라 향후 치료 방향이 결정될 것이며, 악성일 경우 보호자께서는 기대 수명에 대한 상담을 받으신 바와 같이 신중한 결정이 필요합니다. 고혈압 관리를 위해 혈압 모니터링 및 필요시 혈압약 처방을 통해 혈압을 안정화시키는 노력이 중요합니다.\\n\\n심한 관절염 및 퇴행성 관절 질환으로 인한 통증 관리를 위해 보호자께서는 요미가 다리 불편감을 느낄 때 내원하시어 내복약 처방을 받으실 수 있습니다. 또한, 체중 관리와 보조제 급여를 통해 관절에 부담을 줄여주시는 것이 좋습니다. 심한 치석은 치주 질환 예방을 위해 빠른 시일 내 스케일링을 권장하며, 경미한 백내장은 정기적인 안과 검진을 통해 진행 여부를 확인할 필요가 있", "coverOwnerName": "김혜성", "overallSummary": "요미의 이번 건강검진 결과, 전반적으로 여러 계통에서 면밀한 추적 관찰과 관리가 필요한 소견들이 확인되었습니다. 혈액 검사상 경미한 빈혈과 함께 신장 기능 저하를 시사하는 SDMA 수치 16 µg/dL 상승 및 낮은 뇨비중(1.015)이 확인되었고, 복부 초음파 검사에서 양측 신장의 만성 신장 질환(CKD) 소견이 관찰되어 신장 기능에 대한 집중적인 관리가 필요합니다.\\n\\n또한, 췌장염 보조 진단 지표인 cPL 수치가 377로 유의미하게 상승하여 췌장 염증 가능성을 배제할 수 없습니다. 간에서는 방사선 검사상 간종대와 초음파 검사상 다수의 결절 및 담낭 슬러지가 확인되어 간 종양 가능성에 대한 추가 정밀 검사가 시급합니다. 혈압은 190 mmHg로 측정되어 고혈압 진단이 필요하며, 이는 신장 질환 등과 연관될 수 있습니다.\\n\\n근골격계에서는 양측 무릎의 심한 관절염과 좌측 고관절의 퇴행성 관절 질환이 확인되어 만성 통증 관리가 필요합니다. 치아에는 심한 치석이, 눈에는 노령성 핵경화 및 경미한 백내장이 관찰되었습니다. 이처럼 여러 소견들이 복합적으로 나타나므로, 각 질환에 대한 통합적이고 지속적인 관리가 중요합니다.", "coverCheckupDate": "2026-03-09", "coverPatientName": "요미", "coverVeterinarian": "김전모", "labInterpretation": "혈액검사 결과, 경미한 빈혈(HCT 34.2%, HGB 13.0g/dL)이 확인되었으며, 이는 적혈구의 크기가 작고(MCV 60.4fL) 적혈구 내 헤모글로빈 농도가 높은(MCHC 38.1g/dL) 특징을 보입니다. 신장 기능 지표인 SDMA 수치는 16 µg/dL로 상승하였고, 췌장염 진단 보조 지표인 cPL 수치 또한 377로 유의미하게 상승되어 있습니다. 나머지 항목들은 대체로 정상 범위 내에 있었습니다.", "systemsPage3Blocks": [{"rows": [{"label": "주요 진단 내용", "content": "신체검사에서 심장 잡음이나 폐음 이상은 청취되지 않았습니다. 그러나 혈압 측정 결과 190 mmHg로 높은 혈압이 확인되었습니다. 흉부 방사선 검사상 심장 크기 평가 지수인 VHS는 9.5로 측정되었으며, 이는 정상 상한치에 해당합니다."}, {"label": "시사점", "content": "측정된 높은 혈압(190 mmHg)은 고혈압을 시사하며, 이는 추가적인 원인 평가 및 관리가 필요합니다. 심장 크기(VHS 9.5)는 현재 정상 범위의 상한에 있으나, 추후 심장 부담 증가 여부를 면밀히 관찰하고 평가하는 것이 중요합니다."}], "titleEn": "Circulatory & Respiratory Systems", "titleKo": "순환기&호흡기", "variant": "rows"}, {"rows": [{"label": "주요 진단 내용", "content": "혈액 검사 결과, 췌장염 진단 보조 지표인 cPL 수치가 377로 유의미하게 상승된 것이 확인되었습니다. 복부 초음파 검사에서는 위장관 및 주변 림프절에서 특이 소견은 발견되지 않았습니다."}, {"label": "시사점", "content": "cPL 수치 상승은 췌장염 또는 췌장 염증 가능성을 시사하므로, 정밀 검사를 통해 원인을 파악하고 적절한 관리를 시작하는 것이 중요합니다. 췌장 기능에 대한 추가적인 평가가 필요합니다."}], "titleEn": "Digestive System", "titleKo": "소화기", "variant": "rows"}, {"rows": [{"label": "주요 진단 내용", "content": "혈액 검사에서 Chem 15 항목은 정상 범위 내에 있었습니다. 하지만 혈압 측정 시 190 mmHg의 높은 혈압이 확인되어, 내분비계 질환과의 연관성을 배제하기 어렵습니다."}, {"label": "시사점", "content": "확인된 고혈압은 신장 질환, 심장 질환뿐만 아니라 쿠싱 증후군과 같은 내분비계 질환과도 관련될 수 있습니다. 현재 혈액 검사에서 특이 소견은 없었으나, 고혈압의 원인을 파악하기 위한 추가적인 내분비 검사가 필요할 수 있습니다."}], "titleEn": "Endocrine System", "titleKo": "내분비계", "variant": "rows"}], "systemsPage4Blocks": [{"rows": [{"label": "주요 진단 내용", "content": "신체검사에서 치아에 심한 치석이 축적된 것이 확인되었습니다. 안과 검사에서는 양쪽 눈에 노령성 핵경화와 경미한 백내장 소견이 관찰되었습니다. 안압(IOP 11,11)과 눈물량(STT 19,19)은 정상 범위였습니다."}, {"label": "시사점", "content": "심한 치석은 치주염으로 진행될 위험이 높으므로, 스케일링을 통한 치과 치료가 권장됩니다. 노령성 핵경화는 자연스러운 노화 과정이며, 경미한 백내장은 현재 시력에 큰 영향을 주지 않지만, 진행 여부를 주기적으로 확인하는 것이 좋습니다."}], "titleEn": "Dental & Ophthalmology", "titleKo": "치과 및 안과", "variant": "rows"}, {"images": [{"caption": "플레이스홀더 — 이미지 캡션"}, {"caption": "플레이스홀더 — 이미지 캡션"}, {"caption": "플레이스홀더 — 이미지 캡션"}], "titleEn": "", "titleKo": "", "variant": "images"}, {"rows": [{"label": "주요 진단 내용", "content": "해당 프로그램 미포함 영역"}, {"label": "시사점", "content": "해당 프로그램 미포함 영역"}], "titleEn": "Skin & External Ear Canal", "titleKo": "피부와 외이도", "variant": "rows"}, {"images": [{"caption": "플레이스홀더 — 이미지 캡션"}, {"caption": "플레이스홀더 — 이미지 캡션"}, {"caption": "플레이스홀더 — 이미지 캡션"}], "titleEn": "", "titleKo": "", "variant": "images"}], "systemsPage5Blocks": [{"rows": [{"label": "검사 결과 해석", "content": "흉부 방사선 검사상 심장 크기 지수(VHS) 9.5는 정상 상한치에 해당합니다. 복부에서는 간종대가 관찰되었으며, 사지 방사선 검사에서는 양측 무릎의 심한 관절염과 좌측 고관절 퇴행성 변화가 확인되었습니다."}], "compact": true, "titleEn": "X-ray", "titleKo": "방사선 검사", "variant": "rows"}, {"images": [{"caption": "플레이스홀더 — 이미지 캡션"}, {"caption": "플레이스홀더 — 이미지 캡션"}, {"caption": "플레이스홀더 — 이미지 캡션"}, {"caption": "플레이스홀더 — 이미지 캡션"}], "titleEn": "", "titleKo": "", "variant": "images4"}, {"rows": [{"label": "검사 결과 해석", "content": "복부 초음파 검사 결과, 간 내 다수의 결절과 담낭 슬러지가 확인되었습니다. 양쪽 신장에서는 만성 신장 질환(CKD) 소견이 관찰됩니다. 비장, 방광, 위장관 및 주변 림프절에서는 특이 소견이 없었습니다."}], "compact": true, "titleEn": "Ultrasonography", "titleKo": "초음파 검사", "variant": "rows"}, {"images": [{"caption": "플레이스홀더 — 이미지 캡션"}, {"caption": "플레이스홀더 — 이미지 캡션"}, {"caption": "플레이스홀더 — 이미지 캡션"}, {"caption": "플레이스홀더 — 이미지 캡션"}, {"caption": "플레이스홀더 — 이미지 캡션"}, {"caption": "플레이스홀더 — 이미지 캡션"}, {"caption": "플레이스홀더 — 이미지 캡션"}, {"caption": "플레이스홀더 — 이미지 캡션"}, {"caption": "플레이스홀더 — 이미지 캡션"}], "titleEn": "", "titleKo": "", "variant": "imagesGrid3x3"}], "recheckWithin1Month": "간 정밀 검사\\n간 결절의 정확한 진단을 위해 조직 검사를 진행합니다.", "systemsPage3bBlocks": [{"rows": [{"label": "주요 진단 내용", "content": "혈액 검사 결과, 신장 기능 지표인 SDMA 수치가 16 µg/dL로 상승한 것이 확인되었습니다. 뇨검사에서 뇨비중은 1.015로 낮게 측정되었고, 뇨스틱 검사는 정상 소견이었습니다. 복부 초음파 검사 결과 양쪽 신장에서 만성 신장 질환(CKD) 소견이 관찰되었습니다."}, {"label": "시사점", "content": "SDMA 수치 상승, 낮은 뇨비중, 그리고 초음파 상 만성 신장 질환 소견은 신장 기능 저하 및 만성 신장 질환을 강하게 시사합니다. 이는 지속적인 관리가 필요한 질환으로, 신장 기능 보호를 위한 식이 관리 및 약물 치료 계획이 필요합니다."}], "titleEn": "Kidney & Urinary System", "titleKo": "신장 및 비뇨기계", "variant": "rows"}, {"rows": [{"label": "주요 진단 내용", "content": "복부 방사선 검사에서 간이 전반적으로 커져 있는 간종대 소견이 관찰되었습니다. 복부 초음파 검사에서는 간 내부에 여러 개의 결절(nodule)이 확인되었고, 담낭에는 슬러지(sludge)가 관찰되었습니다."}, {"label": "시사점", "content": "간종대와 간 내 다발성 결절은 간 종양의 가능성을 배제할 수 없습니다. 이는 양성일 수도 악성일 수도 있으므로, 정밀 조직 검사를 통해 정확한 진단이 필요합니다. 담낭 슬러지는 담즙 저류나 염증과 관련될 수 있어 주의 깊은 관찰이 요구됩니다."}], "titleEn": "Hepatobiliary System", "titleKo": "간담도계", "variant": "rows"}, {"rows": [{"label": "주요 진단 내용", "content": "방사선 검사 결과, 양쪽 무릎 관절에 심한 관절염 소견이 확인되었으며, 좌측 고관절에서는 퇴행성 관절 질환(DJD)이 관찰되었습니다."}, {"label": "시사점", "content": "양쪽 무릎의 심한 관절염과 좌측 고관절의 퇴행성 변화는 통증과 보행 불편을 유발할 수 있습니다. 이는 만성적인 통증 관리가 필요한 상태이며, 활동량 조절, 보조제 급여, 그리고 필요시 통증 완화를 위한 약물 처방 등을 고려해야 합니다."}], "titleEn": "Musculoskeletal System", "titleKo": "근골격계", "variant": "rows"}], "recheckWithin3Months": "췌장 및 혈압 평가\\n췌장염 재평가 및 고혈압 관리 상태를 확인합니다.", "recheckWithin6Months": "종합 건강 검진\\n전반적인 건강 상태 및 만성 질환 관리 재평가.", "recheckWithin1to2Weeks": "신장 기능 재평가\\n신장 식이 및 약물 반응 평가를 위해 내원 바랍니다."}'::jsonb, '2026-04-13 04:27:31.33059+00'::timestamptz, '2026-04-13 04:27:29.227+00'::timestamptz
);

insert into staging.generated_run_content (
  id, parse_run_id, content_type, payload, created_at, updated_at
) values (
  'db328199-fdce-45cc-8b79-402318fa179e'::uuid, '866623d4-2049-4bc3-a81d-1f5d248a9f69'::uuid, 'health_checkup', E'{"coverProgram": "미니", "followUpCare": "양측 슬개골 탈구의 관리를 위해 가정에서 미끄러지지 않는 환경을 조성해 주시고 높은 곳에서 뛰어내리는 등의 행동은 자제시켜 주세요. 정기적인 재검이 권장되며, 필요 시 수술적 교정을 고려할 수 있습니다.\\n\\n사지 지간염과 입가 발적은 소독 등 적합한 방법으로 관리가 필요하며 해당 부위를 핥거나 긁지 않는지 관찰해 주세요. 알러지에 유의하여 주시고 증상이 지속되거나 악화될 경우 내원이 필요합니다.\\n\\n경도의 치석이 확인되며 양치질과 주기적인 스케일링으로 치아를 관리해 주세요.", "coverOwnerName": "한현준", "overallSummary": "이번 건강검진 결과, 전반적인 혈액 검사에서는 전반적으로 정상 수치를 보였습니다.\\n\\n양측 슬개골 탈구가 확인됩니다.\\n\\n사지 지간염과 입가 발적이 확인되며 지속적인 관찰이 필요합니다.\\n\\n구강 내 경미한 치석이 관찰되어 치과 관리도 필요합니다.\\n\\n검이경 검사와 안과 검사에서는 특별한 이상 소견은 발견되지 않았습니다.", "coverPatientAge": "4", "coverPatientSex": "수컷", "coverCheckupDate": "2026-04-25", "coverPatientName": "구름", "coverPatientBreed": "Mixed", "coverVeterinarian": "이덕원", "labInterpretation": "혈액 검사 결과, 전반적인 혈구 수치 및 혈청 화학 검사 항목들은 모두 정상 범위 내에 있었습니다. ", "coverPatientWeight": "2.86kg", "systemsPage3Blocks": [{"rows": [{"label": "주요 진단 내용", "content": "심장 청진 시 특이 소견은 관찰되지 않았습니다. 호흡 패턴 역시 정상 범위 내에 있었습니다."}, {"label": "시사점", "content": "현재까지는 순환기 및 호흡기 계통에서 특별한 임상적인 이상 징후는 발견되지 않았습니다. 보호자께서는 평소와 다른 기침, 호흡 곤란, 활동량 감소 등의 변화가 있는지 주의 깊게 살펴봐 주시기 바랍니다."}], "titleEn": "Circulatory & Respiratory Systems", "titleKo": "순환기&호흡기", "variant": "rows"}, {"rows": [{"label": "주요 진단 내용", "content": "혈액 검사에서 총단백 6.9g/dL, 알부민 3.7g/dL, 글로불린 3.2g/dL로 모두 정상 범위 내에 있었습니다. 아밀라아제 424U/L, 리파아제 146U/L 수치 또한 참고 범위 내로 확인되었습니다. 구토, 설사 등 소화기계 증상은 없었습니다."}, {"label": "시사점", "content": "현재 소화기계 관련 혈액 검사 및 임상 증상에서 특이사항은 확인되지 않았습니다. 평소와 다른 식욕 부진, 구토, 설사 등의 소화기계 이상 증상이 나타나는지 지속적인 관찰이 필요합니다."}], "titleEn": "Digestive System", "titleKo": "소화기", "variant": "rows"}, {"rows": [{"label": "주요 진단 내용", "content": "신체검사 결과 체중 대비 BCS(Body Condition Score)는 5/9로 이상적인 상태를 유지하고 있습니다. 혈액 검사상 혈당 74mg/dL, 콜레스테롤 126mg/dL, 중성지방 61mg/dL 모두 정상 범위로 확인되었습니다."}, {"label": "시사점", "content": "현재 내분비계와 관련된 검사 수치 및 임상 상태는 양호합니다. 적절한 체중을 유지하고 있으며, 당뇨병 등 내분비 질환의 위험 징후는 발견되지 않았습니다. 앞으로도 균형 잡힌 식사와 운동으로 건강한 체중을 유지하는 것이 중요합니다."}], "titleEn": "Endocrine System", "titleKo": "내분비계", "variant": "rows"}], "systemsPage4Blocks": [{"rows": [{"label": "주요 진단 내용", "content": "구강 검사 결과 경미한 치석이 관찰되었습니다. 잇몸의 염증이나 치아의 흔들림, 파절 등 심각한 치주 질환은 현재 확인되지 않았습니다. 안과 검사상 양측 안구 모두 특이 소견은 없었습니다."}, {"label": "시사점", "content": "경미한 치석이 시작되고 있으므로, 스케일링을 통한 관리가 필요할 수 있습니다. 가정에서 매일 양치질을 해 주시면 치석이 심해지는 것을 예방하고 구강 건강을 유지하는 데 큰 도움이 됩니다. 눈 건강은 현재 양호합니다."}], "titleEn": "Dental & Ophthalmology", "titleKo": "치과 및 안과", "variant": "rows"}, {"images": [{"src": "nuel-260427-01_866623d4/2026-04-25/1777693113355_0_44b14712.webp", "caption": "치아", "rotationDeg": 0}, {"src": "nuel-260427-01_866623d4/2026-04-25/1777693131251_0_e44a3d90.webp", "caption": "치아", "rotationDeg": 0}, {"src": "nuel-260427-01_866623d4/2026-04-25/1777693121514_0_3a2158fe.webp", "caption": "치아", "rotationDeg": 0}, {"src": "nuel-260427-01_866623d4/2026-04-25/1777693104773_0_04042921.webp", "caption": "치아", "rotationDeg": 0}, {"src": "nuel-260427-01_866623d4/2026-04-25/1777693057807_0_d7968223.webp", "caption": "안과", "rotationDeg": 0}, {"src": "nuel-260427-01_866623d4/2026-04-25/1777693066745_0_0516153f.webp", "caption": "안과", "rotationDeg": 0}], "titleEn": "", "titleKo": "", "variant": "imagesGrid2x3"}, {"rows": [{"label": "주요 진단 내용", "content": "신체검사 결과 사지 지간에 염증 소견이 관찰되었으며, 입가 주변에서도 경미한 발적이 확인되었습니다. 피부 각질, 탈모, 가려움증 등 다른 전반적인 피부 이상은 뚜렷하게 관찰되지 않았습니다."}, {"label": "시사점", "content": "지간염과 입가 발적은 알러지 또는 습관적인 행동과 관련이 있을 수 있습니다. 해당 부위를 핥거나 긁는 행동이 심해지지 않는지 관찰해 주시고, 증상이 지속되거나 악화될 경우 정확한 원인 파악을 위한 추가 검진이 필요합니다."}], "titleEn": "Skin & External Ear Canal", "titleKo": "피부와 외이도", "variant": "rows"}, {"images": [{"src": "nuel-260427-01_866623d4/2026-04-25/1777693016330_0_faf08d3b.webp", "caption": "검이경", "rotationDeg": 0}, {"src": "nuel-260427-01_866623d4/2026-04-25/1777693158737_0_13fac9b3.webp", "caption": "검이경", "rotationDeg": 0}, {"caption": "플레이스홀더 — 이미지 캡션"}], "titleEn": "", "titleKo": "", "variant": "images"}], "systemsPage5Blocks": [{"rows": [{"label": "검사 결과 해석", "content": ""}], "compact": true, "titleEn": "X-ray", "titleKo": "방사선 검사", "variant": "rows"}, {"images": [{"src": "nuel-260427-01_866623d4/2026-04-25/1777693141687_0_e9148cb1.webp", "caption": "흉부 방사선", "rotationDeg": 0}, {"src": "nuel-260427-01_866623d4/2026-04-25/1777693150925_0_3a0a6634.webp", "caption": "흉부 방사선", "rotationDeg": 0}, {"src": "nuel-260427-01_866623d4/2026-04-25/1777693079938_0_1bdd759b.webp", "caption": "복부 방사선", "rotationDeg": 0}, {"src": "nuel-260427-01_866623d4/2026-04-25/1777693094686_0_61f11a9f.webp", "caption": "복부 방사선", "rotationDeg": 0}], "titleEn": "", "titleKo": "", "variant": "images4"}, {"rows": [{"label": "검사 결과 해석", "content": "해당 프로그램 미포함 영역"}], "compact": true, "titleEn": "Ultrasonography", "titleKo": "초음파 검사", "variant": "rows"}, {"images": [{"caption": "플레이스홀더 — 이미지 캡션"}, {"caption": "플레이스홀더 — 이미지 캡션"}, {"caption": "플레이스홀더 — 이미지 캡션"}, {"caption": "플레이스홀더 — 이미지 캡션"}, {"caption": "플레이스홀더 — 이미지 캡션"}, {"caption": "플레이스홀더 — 이미지 캡션"}, {"caption": "플레이스홀더 — 이미지 캡션"}, {"caption": "플레이스홀더 — 이미지 캡션"}, {"caption": "플레이스홀더 — 이미지 캡션"}], "titleEn": "", "titleKo": "", "variant": "imagesGrid3x3"}], "coverPatientSpecies": "개", "recheckWithin1Month": "피부 상태 추적 관찰\\n지간염과 입가 피부의 발적 유무를 관찰합니다.", "systemsPage3bBlocks": [{"rows": [{"label": "주요 진단 내용", "content": "현재 활력 징후와 임상 증상에서는 비뇨기계 이상 소견은 확인되지 않았습니다."}, {"label": "시사점", "content": "신장 및 비뇨기계 관련 혈액 검사 수치는 모두 양호한 상태를 보이고 있어, 현재 신장 기능에 대한 특별한 이상소견은 관찰되지 않습니다.\\n정기적인 수분 섭취와 규칙적인 배뇨 활동을 유지하는 것이 중요합니다."}], "titleEn": "Kidney & Urinary System", "titleKo": "신장 및 비뇨기계", "variant": "rows"}, {"rows": [{"label": "주요 진단 내용", "content": "혈액 검사 결과 간수치(ALT 40U/L, AST 25U/L, ALP 40U/L, GGT 8U/L) 및 총 빌리루빈(<0.1mg/dL)이 모두 정상 범위 내에 있었습니다. "}, {"label": "시사점", "content": "현재 혈액 검사상 간담도계 기능은 정상 범위로 판단됩니다. 특별한 이상 소견은 관찰되지 않았으나, 추후 건강검진 시 간담도계 관련 정밀 검사를 고려해 보는 것도 좋습니다."}], "titleEn": "Hepatobiliary System", "titleKo": "간담도계", "variant": "rows"}, {"rows": [{"label": "주요 진단 내용", "content": "신체검사 결과 양측 슬개골 탈구 소견이 확인되었습니다. 현재 통증이나 파행은 뚜렷하게 관찰되지 않았습니다."}, {"label": "시사점", "content": "슬개골 탈구는 진행성 질환이므로 지속적인 관리가 필요합니다. 높은 곳에서 뛰어내리거나 미끄러운 바닥을 걷는 것을 최소화하여 관절에 무리가 가지 않도록 주의해 주시고, 주기적인 재검진을 통해 진행 상황을 평가하는 것이 중요합니다."}], "titleEn": "Musculoskeletal System", "titleKo": "근골격계", "variant": "rows"}], "recheckWithin3Months": "슬개골 상태 평가\\n슬개골 탈구 진행 양상 및 통증 유무를 확인합니다.", "recheckWithin6Months": "종합 건강검진\\n전반적인 건강 상태 재평가 및 구강 검진을 포함합니다.", "recheckWithin1to2Weeks": ""}'::jsonb, '2026-04-27 09:09:37.420717+00'::timestamptz, '2026-05-02 05:37:05.766+00'::timestamptz
);

insert into staging.generated_run_content (
  id, parse_run_id, content_type, payload, created_at, updated_at
) values (
  'aa44f3ea-6107-416b-bfce-dfe33b2d090e'::uuid, '3a6dff31-2ad2-4e3c-8b07-9ad9566de248'::uuid, 'health_checkup', E'{"coverProgram": "종합", "followUpCare": "췌장 수치와 고지혈증 수치 상승 등을 고려하여 식이 관리와 체중 조절이 권장되며 향후 재검이 추천됩니다.\\n심장 질환 지표인 proBNP 수치 상승과 심장 초음파에서 확인된  초기 심장 판막 질환을 고려하여 6-12개월 단위 모니터링이 권장됩니다.\\n\\n기관 허탈 소견과 관련하여 온습도 관리 등 생활 환경 조절이 필요하며, 지속적인 기침 등 증상 변화를 세심히 관찰해 주시기 바랍니다. \\n퇴행성 관절 질환 및 슬개골 탈구 관리를 위하여 체중 관리, 관절 보조제 복용을 권장하며 필요한 경우 진통제 처방 등을 고려할 수 있습니다. 정기적인 재평가를 통한 증상 모니터링이 추천됩니다.\\n현재 확인된 피부 종괴 중 일부를 수술을 통해 제거하였으며 조직 검사가 의뢰되었습니다. 검사 결과에 따라 적절한 처치를 진행할 예정입니다.\\n구강 내 치석과 치은염 관리를 위해 스케일링과 발치 등 치과 치료가 진행되었습니다. 양치질과 주기적인 스케일링으로 치아를 관리해 주세요.\\n양측 눈의 부분 백내장 등 수정체 혼탁은 진행 속도를 관찰을 위한 정기적인 안과 검진이 권장됩니다.\\n초음파 검사에서 관찰되는 담낭슬러지와 전립선 비대는 향후 재검이 권장됩니다.", "coverOwnerName": "강성구", "overallSummary": "혈액 검사에서 췌장염 수치(cPL)와 고지혈증 수치의 상승이 확인되었습니다.\\n\\n심장 질환 관련 지표인 proBNP 수치의 상승도 관찰됩니다.\\n\\n방사선 검사에서 기관 허탈 소견이 확인되었습니다\\n\\n흉요추부  퇴행성 척추증과 양측 슬개골 탈구가 확인됩니다\\n\\n구강 내 심한 치석과 치은염이 확인되었습니다.\\n\\n양측 눈에서 수정체 혼탁, 홍채위축 등 노령성 변화와  부분 백내장 소견이 관찰되었습니다. \\n\\n피부에는 턱 아래 피하 종괴와 피부 종괴가 확인되었고 콧잔등에서도 피부 종괴가 확인되었습니다.\\n\\n초음파 검사에서는 담낭 슬러지와 췌장 음영의 상승, 전립선 비대 소견이 관찰되었습니다.", "coverPatientAge": "16", "coverPatientSex": "수컷", "coverCheckupDate": "2026-04-18", "coverPatientName": "미르", "coverPatientBreed": "요크셔테리어", "coverVeterinarian": "이덕원", "labInterpretation": "혈액 검사 결과, 췌장염 의심 지표인 cPL 수치가 362.1 U/L로 높게 나타났습니다. 또한, 심장 질환 관련 지표인 proBNP 수치가 1434 pmol/L로 상승하여 심장 부담을 시사합니다. 혈중 콜레스테롤 442 mg/dL 및 중성지방 1130 mg/dL 수치가 높아 고지혈증이 확인되었습니다. 이외 다른 혈액 검사 항목들은 대부분 정상 범위 내였습니다.", "coverPatientWeight": "4.7kg", "systemsPage3Blocks": [{"rows": [{"label": "주요 진단 내용", "content": "혈액 검사에서 심장 질환 관련 바이오마커인 proBNP 수치가 1434 pmol/L로 높게 측정되었습니다. 이는 심장에 부담이 있거나 심장 질환이 진행 중일 가능성을 시사합니다. 또한, 흉부 방사선 촬영 결과 기관 허탈이 의심됩니다."}, {"label": "시사점", "content": "높은 proBNP 수치와 심장 초음파에서 보이는 초기 판막 질환은 심장 기능에 대한 지속적인 모니터링이 필요함을 의미합니다. 보호자님께서는 미르의 기침 빈도나 호흡 양상 변화를 주의 깊게 살펴봐 주시기 바랍니다."}], "titleEn": "Circulatory & Respiratory Systems", "titleKo": "순환기&호흡기", "variant": "rows"}, {"rows": [{"label": "주요 진단 내용", "content": "혈액 검사에서 췌장염 특이 수치인 cPL이 362.1 U/L로 높게 측정되었습니다. 복부 초음파 검사에서도 췌장 실질의 에코 변화가 관찰되어 췌장염의 가능성을 뒷받침합니다. 또한, 혈액 검사에서 콜레스테롤 442 mg/dL와 중성지방 1130 mg/dL이 상승하여 고지혈증이 확인되었으며, 이는 췌장염의 위험 요인이 될 수 있습니다."}, {"label": "시사점", "content": "높은 cPL 수치와 췌장 에코 변화, 고지혈증의 관리를 위하여 식이 관리, 체중 조절이 필요합니다.  미르의 식욕 부진, 구토, 설사, 복통 등 소화기 증상 발현 여부를 면밀히 관찰해 주시기 바랍니다."}], "titleEn": "Digestive System", "titleKo": "소화기", "variant": "rows"}, {"rows": [{"label": "주요 진단 내용", "content": "혈액 검사 결과, 콜레스테롤 수치가 442 mg/dL로 정상 범위보다 높게 나타났습니다. 중성지방 수치 또한 1130 mg/dL로 유의하게 상승하여 고지혈증으로 진단됩니다. 갑상선 호르몬(T4 1.99 µg/dL) 및 혈당(GLU 83 mg/dL) 수치는 현재 정상 범위에 있어 갑상선 기능 이상이나 당뇨병과 같은 주요 내분비 질환의 직접적인 증거는 발견되지 않았습니다."}, {"label": "시사점", "content": "고지혈증은 췌장염 등 다른 질환의 위험을 높일 수 있으므로 철저한 관리가 필요합니다. 특히 중성지방 수치가 매우 높아 저지방 식이 조절이 필수적이며, 체중 관리를 통해 혈중 지질 수치를 낮추는 노력이 중요합니다. 정기적인 혈액 검사를 통한 지질 수치의 추적 관찰이 필요합니다."}], "titleEn": "Endocrine System", "titleKo": "내분비계", "variant": "rows"}], "systemsPage4Blocks": [{"rows": [{"label": "주요 진단 내용", "content": "구강 내 심한 치석과 치은염이 관찰되었으며 일부 치아는 이미 소실되었습니다. 안과 검진에서는 양쪽 눈 모두에서 수정체 혼탁과 홍채 위축 소견이 확인되었으며, 부분 백내장이 의심됩니다. 빛 반사 및 눈 관련 반사 작용은 정상적으로 나타났습니다."}, {"label": "시사점", "content": "심한 치석과 치은염이 확인되어 스케일링과 발치 등 치과치료가 진행되었습니다. 앞으로도 양치질과 주기적인 스케일링으로 치아를 관리해 주세요.\\n양안의 부분 백내장 등 수정체 혼탁은 진행 여부 확인을 위해 정기적인 안과 검진을 권장합니다."}], "titleEn": "Dental & Ophthalmology", "titleKo": "치과 및 안과", "variant": "rows"}, {"images": [{"src": "nuel-260422-06_3a6dff31/2026-04-18/1777686250500_0_f8505329.webp", "caption": "치아", "rotationDeg": 0}, {"src": "nuel-260422-06_3a6dff31/2026-04-18/1777686240120_0_a81497a4.webp", "caption": "치아", "rotationDeg": 0}, {"src": "nuel-260422-06_3a6dff31/2026-04-18/1777686228819_0_a6a24676.webp", "caption": "치아", "rotationDeg": 0}, {"src": "nuel-260422-06_3a6dff31/2026-04-18/1777686287293_0_be970730.webp", "caption": "치아", "rotationDeg": 0}, {"src": "nuel-260422-06_3a6dff31/2026-04-18/1777686461505_0_7466f56d.webp", "caption": "안과", "rotationDeg": 0}, {"src": "nuel-260422-06_3a6dff31/2026-04-18/1777686471597_0_8a58b564.webp", "caption": "안과", "rotationDeg": 0}], "titleEn": "", "titleKo": "", "variant": "imagesGrid2x3"}, {"rows": [{"label": "주요 진단 내용", "content": "신체 검진 결과, 턱 아래 종괴 2개소와 와 콧잔등의 피부 종괴가 확인되었습니다. 양측 귀 외이도에서는 발적과 함께 귀지가 관찰되었습니다."}, {"label": "시사점", "content": "현재 턱 아래 종괴와 콧잔등 종괴는 종괴 제거가 진행되었으며 턱 아래 종괴는 조직 검사가 의뢰되었습니다. 조직 검사 결과에 따른 적절한 처치가 진행될 예정입니다. 양측 외이도에서 관찰된 발적과 귀지의 관리를 위하여 꾸준한 귀 세정이 권장됩니다. "}], "titleEn": "Skin & External Ear Canal", "titleKo": "피부와 외이도", "variant": "rows"}, {"images": [{"src": "nuel-260422-06_3a6dff31/2026-04-18/1777686260209_0_e9301c23.webp", "caption": "검이경", "rotationDeg": 0}, {"src": "nuel-260422-06_3a6dff31/2026-04-18/1777686269702_0_9b732c7d.webp", "caption": "검이경", "rotationDeg": 0}, {}], "titleEn": "", "titleKo": "", "variant": "images"}], "systemsPage5Blocks": [{"rows": [{"label": "검사 결과 해석", "content": "훙부 방사선에서 기관 허탈이 의심되는 소견이 있으며 흉요추부에서는 퇴행성 척추증이 확인됩니다. 양측 슬개골 탈구도 관찰됩니다."}], "compact": true, "titleEn": "X-ray", "titleKo": "방사선 검사", "variant": "rows"}, {"images": [{"src": "nuel-260422-06_3a6dff31/2026-04-18/1777686308487_0_19dc5519.webp", "caption": "흉부 방사선", "rotationDeg": 0}, {"src": "nuel-260422-06_3a6dff31/2026-04-18/1777686351304_0_5bca2b4e.webp", "caption": "흉부 방사선", "rotationDeg": 0}, {"src": "nuel-260422-06_3a6dff31/2026-04-18/1777686326253_0_d8604e51.webp", "caption": "복부 방사선", "rotationDeg": 0}, {"src": "nuel-260422-06_3a6dff31/2026-04-18/1777686338599_0_78e04630.webp", "caption": "복부 방사선", "rotationDeg": 0}], "titleEn": "", "titleKo": "", "variant": "images4"}, {"rows": [{"label": "검사 결과 해석", "content": "복부 초음파 검사 결과, 담낭슬러지가 확인되었습니다. 전립선은 전반적으로 비대해져 있습니다. 췌장 실질의 에코 변화가 관찰되어 췌장염의 가능성을 시사합니다."}], "compact": true, "titleEn": "Ultrasonography", "titleKo": "초음파 검사", "variant": "rows"}, {"images": [{}, {}, {}, {}, {}, {}, {}, {}, {}], "titleEn": "", "titleKo": "", "variant": "imagesGrid3x3"}], "coverPatientSpecies": "개", "recheckWithin1Month": "근골격계 평가\\n퇴행성 척추증, 슬개골 탈구와 관련하여 보행과 통증 여부를 평가합니다.", "systemsPage3bBlocks": [{"rows": [{"label": "주요 진단 내용", "content": "혈액 검사에서 신장 기능을 나타내는 BUN(31 mg/dL) 및 SDMA(13 ug/dL) 수치는 현재 정상 범위에 속합니다. 복부 초음파 검사 결과에서는 전립선이 전반적으로 비대해져 있는 소견이 관찰되었습니다. 다른 신장 및 비뇨기계 장기에서 결석이나 구조적 이상, 염증 등 특이할 만한 소견은 확인되지 않았습니다."}, {"label": "시사점", "content": "현재 신장 기능 관련 수치는 양호하나, 노령견임을 감안하여 지속적인 신장 기능 모니터링이 필요합니다. 초음파에서 확인된 전립선 비대는 노령 수컷 강아지에서 흔히 나타나는 변화로, 배뇨 곤란이나 혈뇨 등 비뇨기 증상이 나타나는지 주의 깊게 살펴봐 주셔야 합니다. 이러한 증상이 관찰되면 즉시 병원에 내원하여 추가적인 검진 및 치료를 고려해야 합니다."}], "titleEn": "Kidney & Urinary System", "titleKo": "신장 및 비뇨기계", "variant": "rows"}, {"rows": [{"label": "주요 진단 내용", "content": "복부 초음파 검사 결과, 담낭 슬러지가 관찰되었습니다. 혈액 검사에서 간 기능 지표인 ALT, AST, ALP, GGT 및 빌리루빈 수치는 모두 정상 범위 내에 있어 현재 간 실질의 심각한 손상은 확인되지 않았습니다. 간의 크기나 실질 에코에도 특이적인 이상은 없었습니다."}, {"label": "시사점", "content": "담낭 슬러지는 주로 담즙의 정체나 구성 성분 변화로 인해 발생하며, 시간이 지남에 따라 담석이나 담낭염으로 발전할 가능성이 있습니다. 현재 미르가 특별한 증상을 보이지 않더라도 정기적인 초음파 검사를 통해 담낭 슬러지의 변화를 추적 관찰하는 것이 중요합니다. 또한, 식이 조절을 통해 담즙의 원활한 배출을 돕는 것도 도움이 될 수 있습니다."}], "titleEn": "Hepatobiliary System", "titleKo": "간담도계", "variant": "rows"}, {"rows": [{"label": "주요 진단 내용", "content": "방사선 검사 결과, 흉요추부에서 퇴행성 척추증과 양측 슬개골 탈구가 관찰됩니다."}, {"label": "시사점", "content": "퇴행성 척추 및 관절 질환, 슬개골 탈구는 통증과 파행을 유발할 수 있으며, 적절한 통증 관리와 관절 보조제 급여가 도움 될 수 있습니다. 체중 관리를 통해 관절에 가해지는 부담을 줄이고, 정기적인 재평가를 통한 모니터링이 권장됩니다."}], "titleEn": "Musculoskeletal System", "titleKo": "근골격계", "variant": "rows"}], "recheckWithin3Months": "췌장, 고지혈증 평가\\n췌장 수치와 고지혈증 수치를 재평가합니다.", "recheckWithin6Months": "심장과 전반적인 건강 관리\\n심장, 안과 등을 포함한 전반적인 건강 상태를 살핍니다.", "recheckWithin1to2Weeks": "수술 후 경과 확인\\n피부종괴 수술과 치과 치료 후 상태를 점검합니다."}'::jsonb, '2026-04-22 08:19:41.994235+00'::timestamptz, '2026-05-02 08:30:38.91+00'::timestamptz
);

insert into staging.generated_run_content (
  id, parse_run_id, content_type, payload, created_at, updated_at
) values (
  '618e4b0b-ab8c-4264-9176-c53b20f748dd'::uuid, 'ff350571-1c93-4fae-b24f-a11e26de124c'::uuid, 'health_checkup', E'{"followUpCare": "미우의 건강 관리를 위해 다음 사후 관리 계획을 제안 드립니다.\\n\\n만성 코막힘 및 유루증은 약물 처치와 비강 상태 지속 관찰이 필요합니다. 흉부 방사선상 기관지 무늬 증가는 하부 기도 염증 가능성을 시사하니, 호흡 변화나 기침 증상 발현 시 보호자님의 면밀한 관찰을 부탁드립니다.\\n\\n췌장 효소 수치 상승은 fPLI 정상이므로, 임상 증상 확인 후 소화기 정밀 검진을 고려합니다. 변비 관리를 위해 식이섬유와 수분 섭취를 늘리고, 구토 및 헤어볼 토 빈도를 기록해 주십시오.\\n\\n치석 제거 및 잇몸 염증 관리를 위한 스케일링이 요구됩니다. 구강 내 국소성 부종은 스케일링 시 추가 평가합니다. 외이도 갈색 분비물은 세정 및 소염제 처방 후 경과 확인, 필요시 귀 검진을 진행합니다. 과체중 개선을 위해 활동량 증진과 식이량 조절로 체중 관리에 적극 참여 부탁드립니다.", "coverOwnerName": "이채린", "overallSummary": "이번 건강검진 결과, 미우는 전반적으로 양호한 건강 상태를 보였으나 몇 가지 관리 및 추가 확인이 필요한 소견들이 확인되었습니다.\\n\\n호흡기계에서는 흉부 방사선상 기관지 및 간질성 무늬 증가가 관찰되었으며, 만성 비강 점막 비후로 인한 코막힘과 유루증이 의심됩니다. 이는 상하부 기도 염증 가능성을 시사합니다.\\n\\n소화기계에서는 혈액 검사상 Amylase와 Lipase 수치가 상승하였으나 fPLI는 정상으로, 췌장염 가능성에 대한 추가 평가가 필요합니다. 복부 방사선상 결장 내 변비 소견과 간헐적인 구토 및 헤어볼 토 이력도 확인되었습니다.\\n\\n구강 검사에서는 중등도 치석, 잇몸 충혈, 치아 표면 결손 및 마모, 국소적 잇몸 부종이 관찰되었습니다. 외이도 검사에서 귀 내부 갈색 분비물이 확인되어 염증 가능성이 있습니다. 체형 평가에서는 과체중(BCS 7/9)으로 나타나 체중 관리가 요구됩니다.", "coverPatientAge": "5", "coverPatientSex": "수컷(중성화)", "coverCheckupDate": "2026-03-28", "coverPatientName": "미우", "coverPatientBreed": "C.S", "coverVeterinarian": "이덕원", "labInterpretation": "미우의 혈액 검사 결과 전반적으로 양호한 상태를 보였으나, 췌장 효소인 Amylase와 Lipase 수치가 다소 상승되어 췌장 기능에 대한 추가적인 관심이 필요합니다. RBC 계열에서는 MCV, MCH, 망상적혈구 수치가 약간 상승되어 있음을 확인하였습니다.", "systemsPage3Blocks": [{"rows": [{"label": "주요 진단 내용", "content": "흉부 방사선 검사 결과, 기관지 및 간질성 무늬의 증가 소견이 관찰되었습니다. 임상 증상으로는 양측 비공의 충혈과 코막힘, 유루증 및 안검 부종이 확인되었으며, 재채기 시 좌측 비공에서 분비물이 확인되었습니다. 우측 비공은 개통성 확인이 어려웠습니다."}, {"label": "시사점", "content": "미우는 만성적인 비강 점막 비후로 인한 코막힘이 의심되며, 이는 눈물량 증가 및 안검 부종의 원인이 될 수 있습니다. 흉부 방사선상 기관지 무늬 증가는 하부 기도의 염증성 변화 가능성을 시사하므로, 호흡기계 전반에 대한 지속적인 관찰이 필요합니다."}], "titleEn": "Circulatory & Respiratory Systems", "titleKo": "순환기&호흡기", "variant": "rows"}, {"rows": [{"label": "주요 진단 내용", "content": "혈액 검사에서 췌장 효소인 Amylase 수치가 2341 U/L로, Lipase 수치는 218 U/L로 기준치보다 상승된 소견을 보였습니다. 복부 방사선 검사에서는 결장 내 고형 분변 축적 소견이 확인되었습니다. 사료 토 및 헤어볼 토 이력이 월 2회 내외로 있었으며, 습식 사료 증량 후 변 상태가 개선되었다는 보고가 있었습니다."}, {"label": "시사점", "content": "췌장 효소 수치 상승은 췌장염의 가능성을 시사하나, fPLI 수치가 정상(5 ug/mL)이므로 임상 증상 및 추가 검사를 통해 종합적으로 판단해야 합니다. 간헐적인 구토와 헤어볼 토 이력, 그리고 방사선상 변비 소견이 확인된 점을 고려하여 소화기계 관리와 배변 상태 모니터링이 중요합니다."}], "titleEn": "Digestive System", "titleKo": "소화기", "variant": "rows"}, {"rows": [{"label": "주요 진단 내용", "content": "신체검사 결과, 미우는 체형 평가 점수(BCS)가 9점 만점에 7점으로, 다소 과체중 상태로 평가되었습니다. 혈액 검사에서 갑상선 호르몬(T4 3.21 µg/dL), 혈당(GLU 90 mg/dL), 콜레스테롤(CHOL 179 mg/dL), 중성지방(TRIG 30 mg/dL) 수치는 모두 정상 범위 내에 있었습니다."}, {"label": "시사점", "content": "미우의 과체중은 향후 다양한 대사성 질환 발생 위험을 높일 수 있습니다. 현재 내분비계 관련 혈액 검사 수치들은 모두 정상 범위이나, 적절한 체중 관리와 식이 조절을 통해 건강을 유지하는 것이 중요합니다."}], "titleEn": "Endocrine System", "titleKo": "내분비계", "variant": "rows"}], "systemsPage4Blocks": [{"rows": [{"label": "주요 진단 내용", "content": "구강 검사 결과 중등도(moderate)의 치석이 확인되었고, 하악 구치부에 잇몸 충혈과 치아 표면 결손 및 마모 소견이 관찰되었습니다. 또한 구강 측면 사진에서는 잇몸에 작은 국소성 부종이 확인되었습니다. 안과 검사에서는 유루증 및 안검 부종이 관찰되었습니다."}, {"label": "시사점", "content": "미우는 치석 축적과 잇몸 염증 및 치아 손상 소견이 있어 치과 관리가 필요합니다. 현재 구강 내 부종 소견은 향후 추가적인 평가가 필요합니다. 또한 유루증과 안검 부종은 비강 문제와 연관될 수 있으므로 함께 관리하는 것이 중요합니다."}], "titleEn": "Dental & Ophthalmology", "titleKo": "치과 및 안과", "variant": "rows"}, {"images": [{"src": "nuel-260408-04_ff350571/2026-03-28/1775617533877_6_251ee7cc.webp", "caption": "치아"}, {"src": "nuel-260408-04_ff350571/2026-03-28/1775617534240_7_68ebe2dc.webp", "caption": "치아"}, {"src": "nuel-260408-04_ff350571/2026-03-28/1775617594624_5_2edafb08.webp", "caption": "치아"}, {"src": "nuel-260408-04_ff350571/2026-03-28/1775617533038_4_461f7a54.webp", "caption": "치아 방사선"}, {"src": "nuel-260408-04_ff350571/2026-03-28/1775617593216_2_43033d3f.webp", "caption": "슬릿램프"}, {"src": "nuel-260408-04_ff350571/2026-03-28/1775617594230_4_693f0f93.webp", "caption": "치아"}], "titleEn": "", "titleKo": "", "variant": "imagesGrid2x3"}, {"rows": [{"label": "주요 진단 내용", "content": "신체검사에서 하복부 유두 부근의 피지 축적과 양측 후지 정강이 부위의 탈모가 관찰되었습니다. 검이경 검사 결과, 귀 내부에 갈색 분비물과 이물질로 보이는 소견이 확인되었습니다."}, {"label": "시사점", "content": "미우는 피부의 국소적인 피지 축적 및 탈모 부위가 있어 지속적인 관찰이 필요합니다. 귀 내부의 갈색 분비물 및 이물질은 외이도 염증이나 감염 가능성을 시사하므로, 추가적인 검사와 적절한 처치가 요구됩니다."}], "titleEn": "Skin & External Ear Canal", "titleKo": "피부와 외이도", "variant": "rows"}, {"images": [{"src": "nuel-260408-04_ff350571/2026-03-28/1775617592305_0_ac581c4a.webp", "caption": "검이경"}, {"src": "nuel-260408-04_ff350571/2026-03-28/1775617592671_1_40ffe741.webp", "caption": "검이경"}, {}], "titleEn": "", "titleKo": "", "variant": "images"}], "systemsPage5Blocks": [{"rows": [{"label": "검사 결과 해석", "content": "흉부 방사선 검사에서 기관지 및 간질성 무늬의 증가 소견이 관찰되었습니다. 복부 방사선 검사에서는 결장 내 고형 분변이 축적되어 있는 소견이 확인되었습니다."}], "compact": true, "titleEn": "X-ray", "titleKo": "방사선 검사", "variant": "rows"}, {"images": [{"src": "nuel-260408-04_ff350571/2026-03-28/1775617529033_0_15bbfccb.webp", "caption": "흉부 방사선"}, {"src": "nuel-260408-04_ff350571/2026-03-28/1775617530330_1_fd360ff2.webp", "caption": "복부 방사선"}, {"src": "nuel-260408-04_ff350571/2026-03-28/1775617530965_2_8ab0ec51.webp", "caption": "흉부 방사선"}, {"src": "nuel-260408-04_ff350571/2026-03-28/1775617531896_3_04133edf.webp", "caption": "복부 방사선"}], "titleEn": "", "titleKo": "", "variant": "images4"}, {"rows": [{"label": "검사 결과 해석", "content": "해당 프로그램 미포함 영역"}], "compact": true, "titleEn": "Ultrasonography", "titleKo": "초음파 검사", "variant": "rows"}, {"images": [{}, {}, {}, {}, {}, {}, {}, {}, {}], "titleEn": "", "titleKo": "", "variant": "imagesGrid3x3"}], "coverPatientSpecies": "Feline", "recheckWithin1Month": "구강 및 외이도 재평가\\n잇몸 부종, 치석, 외이도 분비물에 대한 추가 검진 및 처치", "systemsPage3bBlocks": [{"rows": [{"label": "주요 진단 내용", "content": "신장 기능 관련 혈액 검사 항목인 SDMA(11 ug/dL)와 BUN(25 mg/dL) 수치는 모두 정상 범위 내에 있었습니다. 임상 증상상 혈뇨는 없었으며, 배뇨는 원활하고 물 섭취량 또한 양호하다고 확인되었습니다."}, {"label": "시사점", "content": "미우의 신장 및 비뇨기계 기능은 현재 양호한 상태로 판단됩니다. 지속적인 건강 관리를 위해 충분한 수분 섭취를 유지하고, 배뇨 습관 변화를 유심히 관찰해 주시는 것이 좋습니다."}], "titleEn": "Kidney & Urinary System", "titleKo": "신장 및 비뇨기계", "variant": "rows"}, {"rows": [{"label": "주요 진단 내용", "content": "간 기능 관련 혈액 검사 항목인 ALT(72 U/L), AST(32 U/L), ALKP(29 U/L) 수치는 모두 정상 범위 내에 있었습니다. GGT, 총 빌리루빈 수치 또한 참고 범위 내에 있어, 현재 간담도계 기능은 정상으로 평가됩니다."}, {"label": "시사점", "content": "미우의 간담도계 기능은 현재까지 특별한 이상 소견 없이 건강한 상태를 유지하고 있습니다. 앞으로도 균형 잡힌 식단과 정기적인 건강검진을 통해 간 건강을 지속적으로 관리해 주시기를 권장합니다."}], "titleEn": "Hepatobiliary System", "titleKo": "간담도계", "variant": "rows"}, {"rows": [{"label": "주요 진단 내용", "content": "해당 프로그램 미포함 영역"}, {"label": "시사점", "content": "해당 프로그램 미포함 영역"}], "titleEn": "Musculoskeletal System", "titleKo": "근골격계", "variant": "rows"}], "recheckWithin3Months": "소화기 및 체중 관리 상담\\n췌장 기능, 변비, 과체중에 대한 식이 및 생활 습관 상담", "recheckWithin6Months": "종합 건강검진\\n전반적인 건강 상태 및 만성 질환 추적 검사 진행", "recheckWithin1to2Weeks": "비강염 경과 확인\\n비강 점막 비후 및 코막힘, 유루증에 대한 치료 반응 확인"}'::jsonb, '2026-04-18 07:37:03.923031+00'::timestamptz, '2026-04-18 07:37:00.85+00'::timestamptz
);

insert into staging.generated_run_content (
  id, parse_run_id, content_type, payload, created_at, updated_at
) values (
  '9e992118-0ffb-44ce-9f30-32ade0241158'::uuid, 'c97030ba-443b-4fe8-a4d0-952f93f599db'::uuid, 'health_checkup', E'{"followUpCare": "콩의 구강 건강 관리를 위해 현재 관찰된 미약한 치석과 치은염에 대한 관리가 필요합니다. 치은 건강 개선을 위한 치은보조제 사용을 적극적으로 추천드리며, 만약 치은염 증상이 지속되거나 악화될 경우 본원 재방문하시어 내복약 복용 여부에 대해 상담해 주시기 바랍니다. \\n\\n뒷다리 불편감에 대해서는 현재 염좌 가능성이 높으므로, 가정에서 콩의 활동 시 다리 상태를 면밀히 살펴봐 주십시오. 만약 증상이 악화되거나 지속된다면 추가적인 검사와 내복약(진통 소염제 등) 복용이 필요할 수 있으니 본원으로 내원하여 진료를 받아보시는 것이 좋습니다. \\n\\n정기적인 건강검진을 통해 전반적인 건강 상태를 꾸준히 모니터링하며, 특히 치과 및 근골격계 건강에 대한 추적 관찰을 권장합니다. 보호자님의 적극적인 관찰과 협조가 콩의 건강 유지에 매우 중요합니다.", "coverOwnerName": "남혜린", "overallSummary": "콩은 이번 건강검진 결과 전반적으로 양호한 건강 상태를 보였습니다. \\n혈액 검사(CBC, Chem 10) 및 복부 초음파 검사(간, 담낭, 비장, 신장, 방광, 위장관)에서는 모두 정상 범위 소견이 확인되었습니다. \\n흉부 방사선 검사상 심장 크기(VHS 7.7)도 정상 범위에 해당합니다. 이비인후 검이경 검사에서도 특이사항이 없었습니다. \\n다만, 신체 검사에서 미약한 치석과 치은염이 관찰되어 구강 건강 관리에 주의가 필요함을 시사합니다. \\n또한, 보호자님께서 보고하신 뒷다리 불편감에 대해 정형외과 검진 및 방사선 검사를 진행하였으나, 명확한 특이 소견은 발견되지 않았습니다. 현재로서는 일시적인 염좌일 가능성이 높게 추정되며, 증상 변화에 대한 지속적인 관찰이 중요합니다. \\n\\n전반적인 건강 지표는 안정적이나, 구강 및 근골격계 관련하여 면밀한 주의와 관리가 필요합니다.", "coverPatientAge": "3", "coverPatientSex": "수컷(중성화)", "coverCheckupDate": "2026-04-11", "coverPatientName": "콩", "coverPatientBreed": "믹스묘", "coverVeterinarian": "김전모", "labInterpretation": "이번 혈액 검사(CBC, Chem 10) 결과, 모든 항목이 정상 범위 내에 있음을 확인하였습니다. 이는 콩의 전반적인 건강 상태가 매우 양호함을 의미합니다. 빈혈, 염증, 신장 및 간 기능 등 주요 건강 지표들이 안정적으로 유지되고 있습니다.", "systemsPage3Blocks": [{"rows": [{"label": "주요 진단 내용", "content": "신체 검사에서 심잡음이나 폐음 청진상 특이 소견은 확인되지 않았습니다. 흉부 방사선 검사 결과, 심장 크기 측정치(VHS)는 7.7로 확인되었으며, 이는 고양이의 정상 범위에 해당합니다. 폐 실질 및 기관에서도 특이적인 병변이나 협착 소견은 관찰되지 않았습니다."}, {"label": "시사점", "content": "현재 콩의 순환기 및 호흡기계는 양호한 상태로 판단됩니다. 심장 크기나 폐 상태에서 질병을 의심할 만한 소견은 발견되지 않았습니다. 다만, 호흡 곤란, 기침, 활동량 감소 등의 증상이 나타날 경우 즉시 동물병원에 내원하여 추가적인 검진을 받아보시는 것이 좋습니다."}], "titleEn": "Circulatory & Respiratory Systems", "titleKo": "순환기&호흡기", "variant": "rows"}, {"rows": [{"label": "주요 진단 내용", "content": "복부 초음파 검사 결과, 간, 담낭, 비장, 위장관 및 주위 림프절에서 특별한 형태학적 이상 소견은 발견되지 않았습니다. 혈액 검사에서도 소화기계와 관련된 특이 수치 변화는 관찰되지 않아, 현재 소화기계 건강은 양호한 상태로 확인됩니다."}, {"label": "시사점", "content": "현재 콩은 소화기계 관련하여 건강한 상태를 유지하고 있는 것으로 보입니다. 구토, 설사, 식욕 부진 등 소화기계 이상 증상이 발생할 경우, 보호자님께서는 즉시 본원으로 연락하시어 진료를 받아보시길 권해드립니다."}], "titleEn": "Digestive System", "titleKo": "소화기", "variant": "rows"}, {"rows": [{"label": "주요 진단 내용", "content": "혈액 검사(Chem 10) 결과, 혈당(GLU 89mg/dL), 콜레스테롤, 중성지방 등 내분비계와 관련된 주요 수치들이 모두 정상 범위 내로 확인되었습니다. 특히 갑상선 기능이나 당뇨병 등 내분비 질환을 의심할 만한 특별한 소견은 관찰되지 않았습니다."}, {"label": "시사점", "content": "현재 콩의 내분비계 건강은 양호한 상태로 판단됩니다. 하지만 나이가 들어감에 따라 내분비 질환 발생 가능성이 증가할 수 있으므로, 평소와 다른 체중 변화, 다음다뇨(물을 많이 마시고 소변량이 많아지는 것), 피부 이상 등의 증상이 나타나는지 주의 깊게 관찰해 주시기 바랍니다."}], "titleEn": "Endocrine System", "titleKo": "내분비계", "variant": "rows"}], "systemsPage4Blocks": [{"rows": [{"label": "주요 진단 내용", "content": "신체 검사 결과, 콩의 구강 내에서 미약한 치석이 관찰되었으며, 잇몸에도 경미한 치은염 소견이 확인되었습니다. 이 외에 치아 파절이나 심한 흔들림, 구강 내 종괴 등 다른 치과 관련 특이 소견은 발견되지 않았습니다."}, {"label": "시사점", "content": "미약한 치석과 치은염이 있어 구강 관리가 필요합니다. 치은 건강 개선을 위해 치은보조제 사용을 추천드리며, 구강 위생 관리에 신경 써 주시길 바랍니다. 치은염이 지속되거나 악화될 경우 잇몸 염증 조절을 위한 내복약 복용이 필요할 수 있으니 본원 진료를 받아보시길 바랍니다."}], "titleEn": "Dental & Ophthalmology", "titleKo": "치과 및 안과", "variant": "rows"}, {"images": [{"caption": "플레이스홀더 — 이미지 캡션"}, {"caption": "플레이스홀더 — 이미지 캡션"}, {"caption": "플레이스홀더 — 이미지 캡션"}, {"caption": "플레이스홀더 — 이미지 캡션"}, {"caption": "플레이스홀더 — 이미지 캡션"}, {"caption": "플레이스홀더 — 이미지 캡션"}], "titleEn": "", "titleKo": "", "variant": "imagesGrid2x3"}, {"rows": [{"label": "주요 진단 내용", "content": "이비인후과 검이경 검사 결과, 양측 외이도에서 특이 사항은 발견되지 않았습니다. 피부 전반에 걸쳐 탈모, 발적, 종괴 등 육안으로 확인되는 이상 소견은 관찰되지 않았습니다."}, {"label": "시사점", "content": "현재 콩의 피부 및 외이도 건강은 양호한 상태로 확인됩니다. 평소 귀 분비물 증가, 가려움증, 피부 발적 등의 증상이 나타나는지 주의 깊게 살펴봐 주시어 이상 징후 시에는 진료를 받아보시길 권장합니다."}], "titleEn": "Skin & External Ear Canal", "titleKo": "피부와 외이도", "variant": "rows"}, {"images": [{"caption": "플레이스홀더 — 이미지 캡션"}, {"caption": "플레이스홀더 — 이미지 캡션"}, {"caption": "플레이스홀더 — 이미지 캡션"}], "titleEn": "", "titleKo": "", "variant": "images"}], "systemsPage5Blocks": [{"rows": [{"label": "검사 결과 해석", "content": "흉부 방사선 검사에서 심장 크기(VHS 7.7)는 정상 범위에 해당하며, 폐 실질 및 기관에서 특이 병변은 관찰되지 않았습니다. 다리 방사선 검사 결과, 골절이나 관절 이상 등 명확한 특이 소견은 발견되지 않았습니다."}], "compact": true, "titleEn": "X-ray", "titleKo": "방사선 검사", "variant": "rows"}, {"images": [{"caption": "플레이스홀더 — 이미지 캡션"}, {"caption": "플레이스홀더 — 이미지 캡션"}, {"caption": "플레이스홀더 — 이미지 캡션"}, {"caption": "플레이스홀더 — 이미지 캡션"}], "titleEn": "", "titleKo": "", "variant": "images4"}, {"rows": [{"label": "검사 결과 해석", "content": "복부 초음파 검사 결과, 간, 담낭, 비장, 양쪽 신장, 방광, 위장관 및 주위 림프절에서 형태학적 이상 소견이나 종괴, 결석 등은 관찰되지 않았습니다. 모든 복강 장기가 정상적인 구조를 유지하고 있었습니다."}], "compact": true, "titleEn": "Ultrasonography", "titleKo": "초음파 검사", "variant": "rows"}, {"images": [{"caption": "플레이스홀더 — 이미지 캡션"}, {"caption": "플레이스홀더 — 이미지 캡션"}, {"caption": "플레이스홀더 — 이미지 캡션"}, {"caption": "플레이스홀더 — 이미지 캡션"}, {"caption": "플레이스홀더 — 이미지 캡션"}, {"caption": "플레이스홀더 — 이미지 캡션"}, {"caption": "플레이스홀더 — 이미지 캡션"}, {"caption": "플레이스홀더 — 이미지 캡션"}, {"caption": "플레이스홀더 — 이미지 캡션"}], "titleEn": "", "titleKo": "", "variant": "imagesGrid3x3"}], "coverPatientSpecies": "고양이", "recheckWithin1Month": "다리 상태 재평가\\n증상 악화 시 내원하여 약물 상담이 필요합니다.", "systemsPage3bBlocks": [{"rows": [{"label": "주요 진단 내용", "content": "복부 초음파 검사에서 양쪽 신장과 방광의 크기 및 구조는 정상으로 확인되었으며, 결석이나 방광벽 비후 등 특이 소견은 관찰되지 않았습니다. 혈액 검사상 신장 기능 지표인 BUN 19mg/dL, Creatinine 1.0mg/dL 또한 정상 범위 내였습니다."}, {"label": "시사점", "content": "콩의 신장 및 비뇨기계는 현재 건강한 상태를 유지하고 있는 것으로 평가됩니다. 그러나 신장 질환은 초기 증상이 미미할 수 있으므로, 평소 음수량과 배뇨량의 변화, 비정상적인 소변 색깔 등을 세심하게 확인하여 주시길 바랍니다."}], "titleEn": "Kidney & Urinary System", "titleKo": "신장 및 비뇨기계", "variant": "rows"}, {"rows": [{"label": "주요 진단 내용", "content": "복부 초음파 검사 결과, 간, 담낭, 비장에서 형태학적 이상 소견(예: 종괴, 슬러지, 담관 확장)은 발견되지 않았습니다. 혈액 검사에서도 간 수치인 AST 36U/L, ALT 64U/L, ALP 51U/L를 포함한 모든 간담도계 관련 지표들이 정상 범위 내로 확인되었습니다."}, {"label": "시사점", "content": "현재 콩의 간담도계 건강은 양호한 것으로 판단됩니다. 간담도계 질환은 초기에는 증상이 나타나지 않을 수 있으므로, 식욕 부진, 구토, 황달(피부나 눈 흰자위가 노랗게 변하는 것) 등의 증상이 나타나는지 면밀히 관찰해 주시는 것이 중요합니다."}], "titleEn": "Hepatobiliary System", "titleKo": "간담도계", "variant": "rows"}, {"rows": [{"label": "주요 진단 내용", "content": "신체 검사상 좌측 다리에 일시적인 불편감이 관찰되었으나, 다리 촉진 및 정형외과적 검사에서 명확한 골격계 이상은 확인되지 않았습니다. 방사선 검사에서도 다리 부분에 골절이나 관절 변형 등 특별한 특이 소견은 없었습니다. 현재로서는 단순 염좌일 가능성이 높습니다."}, {"label": "시사점", "content": "현재 다리 불편감은 정형외과 및 방사선 검사상 큰 이상이 없어 염좌일 가능성이 높습니다. 보호자님께서는 콩의 활동 시 다리 상태를 지속적으로 관찰해 주시고, 만약 증상이 지속적으로 악화되거나 활동에 심한 제약이 생길 경우, 내원하여 진통 소염제 등의 내복약 복용을 고려해 볼 수 있습니다."}], "titleEn": "Musculoskeletal System", "titleKo": "근골격계", "variant": "rows"}], "recheckWithin3Months": "치은염 상태 확인\\n치은염이 지속되면 내복약 복용을 고려할 수 있습니다.", "recheckWithin6Months": "정기 건강검진\\n전반적인 건강 상태 재평가를 권장합니다.", "recheckWithin1to2Weeks": "다리 증상 관찰\\n다리 불편감이 지속되는지 확인해 주세요."}'::jsonb, '2026-04-20 05:01:43.456427+00'::timestamptz, '2026-04-20 05:03:29.957+00'::timestamptz
);

