  id, parse_run_id, content_type, payload, created_at, updated_at
) values (
  'e259f827-4927-44b4-9ddc-38fe1173297c'::uuid, '37f66a77-7742-40b3-a82a-233237b7475a'::uuid, 'health_checkup', E'{"followUpCare": "확인된 건강 문제들에 대한 체계적인 사후 관리가 필요합니다. 먼저, 근골격계 관련하여 과거 수술 부위 및 관절 퇴행성 변화에 대해서는 환자의 보행 및 활동성을 면밀히 관찰해 주시고, 통증 징후가 보이면 즉시 내원하시어 진찰을 받아보는 것이 중요합니다. 주기적인 재검진을 통해 관절 상태를 평가하고 적절한 관리를 이어갈 예정입니다.\\n\\n구강 내 치석과 염증, 부정교합에 대해서는 스케일링을 포함한 전문적인 치과 처치가 권장됩니다. 외이도 염증 소견은 귀 청소 및 염증 치료를 진행한 후 추후 재검진을 통해 원인 파악 및 관리를 이어갈 계획입니다.\\n\\n혈액 검사에서 나타난 저혈당 소견에 대해서는 환자의 컨디션을 지속적으로 확인하고, 필요시 혈액 검사를 통해 혈당 변화를 추적 관찰할 예정입니다. 방사선 검사에서 의심되는 위장 내 이물 또는 내용물 축적에 대해서는 추가적인 영상 검사를 통해 정확한 원인을 파악할 필요가 있으며, 흉부의 금속성 이물 또한 추적 관찰하며 문제가 발생할 경우 그에 따른 조치를 논의할 것입니다.\\n\\n안과적으로는 각막 및 동공 혼탁에 대한 추가 정밀 검사가 필요합니다. 또한, 항체가 검사 결과 부족한 백신 항체에 대해 예방 접종(항히스타민 주사 병행)을", "coverOwnerName": "이혜숙", "overallSummary": "이번 건강검진 결과, 전반적으로 양호한 신체 활력을 보였으나 몇 가지 주요 소견이 확인되었습니다. 먼저, 과거 수술 이력과 관련된 근골격계 소견으로, 양측 슬관절 및 팔다리 여러 부위에 수술용 금속 고정물이 관찰되며, 요추와 좌측 팔꿈치 주변에서 경미한 퇴행성 골성 변화 및 골질 변화가 의심됩니다. 이는 장기적인 관절 건강 관리가 필요함을 시사합니다.\\n\\n구강 검사에서는 치석과 치은염, 그리고 치주 질환 가능성이 있는 국소 염증이 발견되었으며, 앞니 부정교합 소견도 확인되었습니다. 외이도 검사에서는 다량의 털과 이물성 분비물이 관찰되어 외이도 염증이 의심되는 상황입니다.\\n\\n혈액 검사 결과에서는 혈당(GLU) 수치가 67mg/dL로 낮게 측정되어 저혈당 소견을 보였습니다. 흉부 방사선 검사에서는 경부 및 우측 상부 흉부에서 작은 금속성 이물이 확인되었고, 복부 방사선 검사에서는 우상복부 혼탁과 가스가 혼재되어 위장 내 이물 또는 내용물 축적 가능성이 의심됩니다.\\n\\n또한, 안과 슬릿램프 검사에서는 각막 하부와 동공 중앙에 혼탁 소견이 발견되어 추가적인 안과 평가가 필요합니다.", "coverPatientAge": "6", "coverPatientSex": "암컷(중성화)", "coverCheckupDate": "2026-04-22", "coverPatientName": "호빵", "coverPatientBreed": "비숑프리제", "coverVeterinarian": "이덕원", "labInterpretation": "이번 건강검진 혈액검사 결과, 전반적으로 양호한 수치를 보였으나, 혈당(GLU) 수치가 67mg/dL로 정상 범위보다 낮게 측정되었습니다. 다른 수치는 모두 정상 범위 내에 있었으며, 신장 기능 지표(SDMA, BUN), 간 효소 수치(ALT, AST, ALP, GGT), 췌장염 마커(cPL) 등도 양호하게 확인되었습니다. 저혈당의 원인을 파악하기 위해 추가적인 관찰이 필요할 수 있습니다.", "systemsPage3Blocks": [{"rows": [{"label": "주요 진단 내용", "content": "심폐 청진상 특이 소견은 없었으며, 혈액 검사상 심장 질환 관련 지표인 proBNP 수치 808pmol/L로 정상 범위였습니다. 흉부 방사선 검사에서는 경부 배부 및 우측 상부 흉부에서 작은 금속성 이물이 관찰되었습니다. 이는 외부에서 유입된 것으로 추정됩니다."}, {"label": "시사점", "content": "심장 및 호흡기 기능은 현재 검사상으로는 양호한 것으로 판단됩니다. 다만, 흉부 방사선에서 발견된 금속성 이물은 현재 임상 증상을 유발하지 않더라도 향후 문제를 일으킬 가능성이 있어 추가적인 평가 및 관찰이 필요합니다."}], "titleEn": "Circulatory & Respiratory Systems", "titleKo": "순환기&호흡기", "variant": "rows"}, {"rows": [{"label": "주요 진단 내용", "content": "혈액 검사에서 소화기 관련 지표인 췌장염 수치(cPL 53U/L), 아밀라아제(AMYL 510U/L), 리파아제(LIPA 669U/L) 모두 정상 범위로 확인되었습니다. 복부 방사선 검사 결과, 우상복부에 불규칙한 혼탁 및 고밀도 영역과 가스가 혼재된 소견이 관찰되었습니다. 이는 위장 내 이물 또는 내용물 축적의 가능성을 시사합니다."}, {"label": "시사점", "content": "현재 소화기계 혈액 검사 결과는 양호하나, 복부 방사선에서 관찰된 소견은 위장관 내 이물 또는 비정상적인 내용물 축적을 의심하게 합니다. 이에 대한 추가적인 평가가 필요하며, 구토, 식욕 부진 등의 소화기 증상 발현 시 즉시 내원하시어 진찰을 받아보시기를 권장합니다."}], "titleEn": "Digestive System", "titleKo": "소화기", "variant": "rows"}, {"rows": [{"label": "주요 진단 내용", "content": "갑상선 기능 검사(T4 3.14µg/dL), 콜레스테롤(CHOL 307mg/dL), 중성지방(TRIG 75mg/dL) 수치는 모두 정상 범위였습니다. 그러나 혈액 검사에서 혈당(GLU) 수치가 67mg/dL로 정상 범위보다 낮게 측정되어 저혈당 소견을 보였습니다. 이는 임상적으로 추가적인 평가가 필요한 부분입니다."}, {"label": "시사점", "content": "전반적인 내분비계 건강은 양호한 편이지만, 검사에서 확인된 경미한 저혈당은 다양한 원인에 의해 발생할 수 있습니다. 당일 컨디션이나 검사 전 금식 시간에 따라 일시적일 수 있으나, 지속적인 저혈당은 건강에 영향을 줄 수 있으므로 앞으로 혈당 변화 추이를 면밀히 관찰하고 필요시 추가 검사를 진행하여 원인을 파악하는 것이 중요합니다."}], "titleEn": "Endocrine System", "titleKo": "내분비계", "variant": "rows"}], "systemsPage4Blocks": [{"rows": [{"label": "주요 진단 내용", "content": "구강 검사 결과, 우측 및 왼쪽 어금니에 치석 침착과 경미한 치은염(잇몸 염증) 소견이 관찰되었습니다. 송곳니와 주변 잇몸에서도 발적과 부종이 확인되어 국소 염증(치주 질환 가능성)이 의심됩니다. 또한, 앞니가 겹치고 맞물림이 어긋나는 부정교합 소견이 있어 치과적 확인이 필요합니다. 안과 검사에서는 OU 안검 경도 발적, 경도 결막 충혈 외에 슬릿램프 검사에서 각막 하부 및 동공 중앙에 작은 혼탁 소견이 발견되었습니다."}, {"label": "시사점", "content": "현재 치아 상태는 치석과 치은염, 그리고 치주 질환 가능성이 있어 스케일링을 포함한 전문적인 치과 처치가 필요합니다. 부정교합은 치아 마모나 다른 구강 문제로 이어질 수 있어 치과 진료를 통해 정확한 평가를 받아보시는 것이 좋습니다. 안과적으로는 눈꺼풀과 결막의 경미한 염증 외에 각막 및 동공 혼탁 소견에 대해 추가적인 세극등 검사 및 염색 검사를 진행하여 원인 파악 및 적절한 치료 계획을 수립해야 합니다."}], "titleEn": "Dental & Ophthalmology", "titleKo": "치과 및 안과", "variant": "rows"}, {"images": [{"src": "nuel-260502-02_37f66a77/2026-04-22/1777709970867_0_0dbd8340.webp", "caption": "슬릿램프"}, {"src": "nuel-260502-02_37f66a77/2026-04-22/1777709985555_0_aa5a4a53.webp", "caption": "슬릿램프"}, {"src": "nuel-260502-02_37f66a77/2026-04-22/1777710026293_0_c4187629.webp", "caption": "치아"}, {"src": "nuel-260502-02_37f66a77/2026-04-22/1777710037860_0_fb33f943.webp", "caption": "치아"}, {"src": "nuel-260502-02_37f66a77/2026-04-22/1777710050095_0_28fe93af.webp", "caption": "치아"}, {"src": "nuel-260502-02_37f66a77/2026-04-22/1777710063406_0_63d5306f.webp", "caption": "치아"}], "titleEn": "", "titleKo": "", "variant": "imagesGrid2x3"}, {"rows": [{"label": "주요 진단 내용", "content": "피부 검사상 지간염(발가락 사이 염증)이 확인되었습니다. 외이도 검이경 검사 결과, 양쪽 외이도 내부에 다량의 털과 이물성 분비물이 관찰되었으며, 이는 외이도 염증 가능성을 시사합니다. 추가적으로 귀 청소 및 수의사 진찰이 권장되는 소견입니다."}, {"label": "시사점", "content": "지간염 및 외이도 내 이물과 분비물은 환자에게 불편감을 줄 수 있으며, 만성적인 피부 또는 외이도 염증으로 발전할 수 있습니다. 지간염 관리를 위해 해당 부위 위생에 신경 써 주시고, 외이도 건강을 위해서는 전문적인 귀 청소 및 염증에 대한 적절한 치료가 필요합니다. 추후 외이도 추가 검진을 통해 정확한 원인을 파악하고 관리해야 합니다."}], "titleEn": "Skin & External Ear Canal", "titleKo": "피부와 외이도", "variant": "rows"}, {"images": [{"src": "nuel-260502-02_37f66a77/2026-04-22/1777709895696_0_f39f2666.webp", "caption": "검이경"}, {"src": "nuel-260502-02_37f66a77/2026-04-22/1777709907975_0_305eeedd.webp", "caption": "검이경"}, {}], "titleEn": "", "titleKo": "", "variant": "images"}], "systemsPage5Blocks": [{"rows": [{"label": "검사 결과 해석", "content": "흉부 및 경부 방사선에서 작은 금속성 이물이 확인됩니다. 복부 우상복부에는 혼탁 영역과 가스가 보여 위장 내 이물 또는 내용물 축적이 의심됩니다. 관절 방사선상 양측 슬관절 등 여러 부위에 수술용 금속 고정물과 요추 퇴행성 변화가 확인됩니다."}], "compact": true, "titleEn": "X-ray", "titleKo": "방사선 검사", "variant": "rows"}, {"images": [{"src": "nuel-260502-02_37f66a77/2026-04-22/1777710074195_0_dbfb2db5.webp", "caption": "흉부 방사선"}, {"src": "nuel-260502-02_37f66a77/2026-04-22/1777710087848_0_1e1b1de3.webp", "caption": "흉부 방사선", "rotationDeg": 0}, {"src": "nuel-260502-02_37f66a77/2026-04-22/1777710014197_0_ce216abc.webp", "caption": "복부 방사선"}, {"src": "nuel-260502-02_37f66a77/2026-04-22/1777709999250_0_a6e95c55.webp", "caption": "복부 방사선", "rotationDeg": 0}], "titleEn": "", "titleKo": "", "variant": "images4"}, {"rows": [{"label": "검사 결과 해석", "content": "해당 프로그램 미포함 영역"}], "compact": true, "titleEn": "Ultrasonography", "titleKo": "초음파 검사", "variant": "rows"}, {"images": [{}, {}, {}, {}, {}, {}, {}, {}, {}], "titleEn": "", "titleKo": "", "variant": "imagesGrid3x3"}], "coverPatientSpecies": "개", "recheckWithin1Month": "치과 정밀 검진\\n치아 상태 평가 및 스케일링, 부정교합 확인을 권장합니다.", "systemsPage3bBlocks": [{"rows": [{"label": "주요 진단 내용", "content": "신장 기능 지표인 SDMA 수치 10ug/dL, BUN 수치 23mg/dL 모두 정상 범위로 확인되었습니다. 요비중 및 다른 비뇨기계 관련 검사는 진행되지 않았습니다. 복부 방사선 검사상 요추 부위에 경미한 퇴행성 골성 변화가 관찰되었으나, 신장 및 방광 형태는 특이 사항이 없었습니다."}, {"label": "시사점", "content": "현재까지의 혈액 검사 결과로는 신장 기능이 양호한 것으로 판단됩니다. 비뇨기계 관련 추가적인 문제를 확인하기 위해 요검사를 포함한 정기적인 건강 검진을 통해 지속적으로 관리하는 것이 권장됩니다. 요추의 퇴행성 변화는 통증 유발 가능성이 있어 추적 관찰이 필요합니다."}], "titleEn": "Kidney & Urinary System", "titleKo": "신장 및 비뇨기계", "variant": "rows"}, {"rows": [{"label": "주요 진단 내용", "content": "간 기능 지표인 ALT 27U/L, AST 32U/L, ALP 15U/L, GGT 4U/L 수치가 모두 정상 범위로 확인되었습니다. 총 빌리루빈 수치는 0.1mg/dL 미만으로 측정되어 정상 소견을 보였습니다. 이는 현재 간담도계 건강 상태가 양호함을 시사합니다."}, {"label": "시사점", "content": "현재 혈액 검사상 간담도계 기능은 매우 건강한 것으로 평가됩니다. 특별히 우려할 만한 이상 소견은 발견되지 않았습니다. 앞으로도 정기적인 건강 검진을 통해 지속적인 간담도계 건강 관리를 유지해 주시는 것이 중요합니다."}], "titleEn": "Hepatobiliary System", "titleKo": "간담도계", "variant": "rows"}, {"rows": [{"label": "주요 진단 내용", "content": "환자는 1세 경 양측 슬개골 수술 이력이 있으며, 방사선 검사에서 양측 슬관절 부위에 수술용 금속 물질(와이어/봉합사)이 관찰되었습니다. 또한, 좌측 팔꿈치 부위와 우측 후지 근위 경골에도 금속 고정물이 확인되었고, 좌측 팔꿈치 주변에서는 경미한 골질 변화가 의심됩니다. 고관절에서는 약간의 관절면 불일치가 관찰되었으며, 요추 부위에서 경미한 퇴행성 골성 변화가 확인되었습니다."}, {"label": "시사점", "content": "과거 슬개골 수술 이력과 현재 방사선상 관찰되는 수술 잔존물 및 관절 변화들은 장기적으로 관절염 진행 가능성을 시사합니다. 특히 좌측 팔꿈치 골질 변화, 고관절 불일치, 요추 퇴행성 변화는 통증이나 보행 이상을 유발할 수 있으므로 보호자께서는 환자의 보행 및 활동성에 변화가 있는지 세심하게 관찰해 주셔야 합니다. 필요시 주기적인 재검진을 통해 관절 상태를 평가하고 관리하는 것이 중요합니다."}], "titleEn": "Musculoskeletal System", "titleKo": "근골격계", "variant": "rows"}], "recheckWithin3Months": "관절 및 안과 재평가\\n관절 상태와 안과 혼탁 소견에 대한 재평가가 필요합니다.", "recheckWithin6Months": "전반 건강 검진\\n주요 장기 및 만성 질환 관리 위한 정기 검진을 권장합니다.", "recheckWithin1to2Weeks": "귀 청소 및 재진\\n외이도 염증 관리를 위해 귀 청소 및 치료 후 재진 바랍니다."}'::jsonb, '2026-05-02 09:01:51.967904+00'::timestamptz, '2026-05-02 09:03:10.285+00'::timestamptz
);

