  id, parse_run_id, content_type, payload, created_at, updated_at
) values (
  'f888c4b2-82b8-486a-ade9-a925235a2d8f'::uuid, 'a44fb2a0-9092-4512-b184-6483c06c327a'::uuid, 'health_checkup', E'{"followUpCare": "슈가의 건강 관리를 위해 다음과 같은 사후 관리를 권장해 드립니다.\\n\\n우선, 확인된 고혈압(180mmHg)에 대해서는 주기적인 혈압 측정을 통해 추이를 면밀히 관찰하는 것이 중요합니다. 필요에 따라 혈압 강하제 처방을 고려하거나, 기저 질환 감별을 위한 추가 검사가 진행될 수 있습니다.\\n\\n간 효소 수치 상승에 대해서는 지속적인 간 보호제 급여를 추천합니다. 한 달 이내에 혈액 검사를 통해 간 수치의 변화 양상을 재평가하고, 간 보호제의 효과 및 추가적인 치료 방향을 논의할 예정입니다.\\n\\n비만세포종은 현재 상처가 호전되고 있다고 하셨지만, 눈 주변 부위는 자극에 민감하므로 병변 부위를 주의 깊게 살펴봐 주십시오. 크기나 형태 변화, 가려움증 등 이상 징후 발생 시 본원으로 내원하여 진료를 받는 것이 좋습니다.\\n\\n구토 증상은 간헐적으로 나타나는 만큼, 평소 식이 관리 및 스트레스 요인 조절에 신경 써 주시고, 구토 빈도가 잦아지거나 다른 임상 증상(식욕 부진, 기력 저하 등)이 동반될 경우 즉시 내원하여 정밀 검사를 받는 것을 권장합니다. 귀를 긁는 증상 또한 지속될 경우 원인 파악을 위한 추가 검사를 고려할 수 있습니다.", "coverOwnerName": "박소라", "overallSummary": "이번 2026년 3월 21일 건강검진에서 슈가는 전반적으로 양호한 건강 상태를 보였습니다.\\n\\n주요 소견으로는 혈압 측정 결과 180mmHg로 고혈압이 확인되었으며, 이는 고양이에게서 신장 질환이나 심장 질환, 내분비계 질환 등 다양한 기저 질환과 연관될 수 있어 주의 깊은 관찰이 필요합니다.\\n\\n혈액 검사에서는 간 효소 수치(AST 85 U/L, ALT 136 U/L)가 정상 범위보다 상승한 것이 확인되었습니다. 이는 간세포 손상이나 기능 이상을 시사할 수 있으며, 현재 복부 초음파 검사에서는 간의 구조적인 이상은 발견되지 않았습니다. 간수치 상승이 확인된 만큼, 지속적인 간 보호제 급여를 통해 간 기능을 지원하는 것이 권장됩니다.\\n\\n보호자께서는 눈 옆과 귀 부위에 비만세포종이 있다고 말씀하셨고, 구토 및 귀를 긁는 증상에 대해 우려를 표하셨습니다. 현재 검사 결과에서는 비만세포종의 전신적인 영향이나 구토의 명확한 구조적 원인(초음파상)은 확인되지 않았습니다.", "coverPatientAge": "4", "coverPatientSex": "암컷(중성화)", "coverCheckupDate": "2026-03-21", "coverPatientName": "슈가", "coverPatientBreed": "코리안숏헤어", "coverVeterinarian": "김전모", "labInterpretation": "혈액 검사 결과 전반적으로 양호한 편입니다. 다만, 간 효소 수치인 AST(85 U/L)와 ALT(136 U/L)가 상승되어 간 기능에 대한 추가적인 관찰이 필요합니다. 평균 적혈구 헤모글로빈 농도(MCHC 36.1g/dL)는 다소 높게 측정되었으나, 다른 혈구 수치는 정상 범위였습니다. 신장 수치(SDMA 10)는 양호합니다.", "coverPatientWeight": "1kg", "systemsPage3Blocks": [{"rows": [{"label": "주요 진단 내용", "content": "신체검사에서 심잡음 및 폐음 청취 시 특이사항은 없었으나, 혈압 측정 결과 180mmHg로 정상 범위를 다소 초과하는 고혈압 소견이 확인되었습니다. 흉부 방사선 검사에서 심장 크기(VHS 7.5)는 고양이 기준 정상 범위에 해당합니다."}, {"label": "시사점", "content": "혈압 상승 소견은 고양이에서 신장 질환, 심장 질환, 갑상선 기능 항진증 등 다양한 기저 질환의 2차적인 증상으로 나타날 수 있습니다. 이에 대한 정기적인 추적 관찰이 필요하며, 향후 필요 시 추가적인 정밀 검사를 고려해 볼 수 있습니다."}], "titleEn": "Circulatory & Respiratory Systems", "titleKo": "순환기&호흡기", "variant": "rows"}, {"rows": [{"label": "주요 진단 내용", "content": "보호자께서는 월 2회 가량의 구토 증상을 말씀해 주셨습니다. 복부 초음파 검사에서 위장관 및 주위 림프절에서는 특이 소견이 관찰되지 않았습니다. 신체검사 시 치아 상태 또한 정상으로 확인되었습니다."}, {"label": "시사점", "content": "구토는 다양한 원인에 의해 발생할 수 있으며, 현재 초음파 검사에서는 구조적인 이상이 발견되지 않았습니다. 증상이 지속되거나 빈도가 잦아질 경우, 구토의 원인을 파악하기 위한 추가적인 검사(예: 식이 관리, 약물 치료 또는 내시경 검사 등)를 고려해 볼 수 있습니다."}], "titleEn": "Digestive System", "titleKo": "소화기", "variant": "rows"}, {"rows": [{"label": "주요 진단 내용", "content": "혈액 검사에서 특이적인 내분비계 이상 소견은 확인되지 않았습니다. 현재로서는 갑상선 기능 항진증과 같은 주요 내분비 질환의 직접적인 증거는 발견되지 않았습니다."}, {"label": "시사점", "content": "고혈압 소견은 내분비계 질환(예: 갑상선 기능 항진증, 부신 피질 기능 항진증)과 관련될 수 있으므로, 향후 혈압 재검 시 관련 호르몬 검사도 함께 고려하는 것이 좋습니다. 비만세포종은 피부에 발생하나, 경우에 따라 전신적인 문제가 동반될 수 있습니다."}], "titleEn": "Endocrine System", "titleKo": "내분비계", "variant": "rows"}], "systemsPage4Blocks": [{"rows": [{"label": "주요 진단 내용", "content": "신체검사 시 치아 상태는 전반적으로 양호한 것으로 확인되었습니다. 보호자께서는 눈 바로 옆쪽에 생긴 비만세포종에 대해 말씀해 주셨습니다. 현재 육안상으로 안과적인 특이 소견은 관찰되지 않았습니다."}, {"label": "시사점", "content": "현재 치아 건강은 양호하지만, 향후 지속적인 구강 관리가 필요합니다. 눈 주변의 비만세포종 부위는 상처가 회복되는지 면밀히 지켜보시고, 자극이나 변화 발생 시 본원에 내원하여 재검진을 받는 것이 좋습니다."}], "titleEn": "Dental & Ophthalmology", "titleKo": "치과 및 안과", "variant": "rows"}, {"images": [{"caption": "플레이스홀더 — 이미지 캡션"}, {"caption": "플레이스홀더 — 이미지 캡션"}, {"caption": "플레이스홀더 — 이미지 캡션"}, {"caption": "플레이스홀더 — 이미지 캡션"}, {"caption": "플레이스홀더 — 이미지 캡션"}, {"caption": "플레이스홀더 — 이미지 캡션"}], "titleEn": "", "titleKo": "", "variant": "imagesGrid2x3"}, {"rows": [{"label": "주요 진단 내용", "content": "보호자께서는 귀를 긁는 증상과 함께 눈 옆과 귀 부위에 비만세포종이 있다고 말씀하셨습니다. 검이경 검사 결과 양쪽 외이도에서 특이 소견은 확인되지 않았습니다."}, {"label": "시사점", "content": "귀를 긁는 증상은 외이도 자체의 문제 외에도 알레르기 등 다양한 원인에 의해 나타날 수 있습니다. 비만세포종은 현재 상처가 나아지고 있는 상태라고 하셨으므로, 병변 부위의 변화 여부를 지속적으로 관찰해 주시기 바랍니다."}], "titleEn": "Skin & External Ear Canal", "titleKo": "피부와 외이도", "variant": "rows"}, {"images": [{"caption": "플레이스홀더 — 이미지 캡션"}, {"caption": "플레이스홀더 — 이미지 캡션"}, {"caption": "플레이스홀더 — 이미지 캡션"}], "titleEn": "", "titleKo": "", "variant": "images"}], "systemsPage5Blocks": [{"rows": [{"label": "검사 결과 해석", "content": "흉부 방사선 검사 결과, 심장 크기 측정값(VHS 7.5)은 고양이 기준 정상 범위에 해당합니다. 폐야 및 기관에서는 현재 육안상 특이 소견은 관찰되지 않았습니다."}], "compact": true, "titleEn": "X-ray", "titleKo": "방사선 검사", "variant": "rows"}, {"images": [{"caption": "플레이스홀더 — 이미지 캡션"}, {"caption": "플레이스홀더 — 이미지 캡션"}, {"caption": "플레이스홀더 — 이미지 캡션"}, {"caption": "플레이스홀더 — 이미지 캡션"}], "titleEn": "", "titleKo": "", "variant": "images4"}, {"rows": [{"label": "검사 결과 해석", "content": "복부 초음파 검사 결과, 간, 담낭, 비장, 신장, 방광, 위장관 및 주위 림프절 등 주요 복부 장기에서 현재 구조적인 특이 소견은 확인되지 않았습니다."}], "compact": true, "titleEn": "Ultrasonography", "titleKo": "초음파 검사", "variant": "rows"}, {"images": [{"caption": "플레이스홀더 — 이미지 캡션"}, {"caption": "플레이스홀더 — 이미지 캡션"}, {"caption": "플레이스홀더 — 이미지 캡션"}, {"caption": "플레이스홀더 — 이미지 캡션"}, {"caption": "플레이스홀더 — 이미지 캡션"}, {"caption": "플레이스홀더 — 이미지 캡션"}, {"caption": "플레이스홀더 — 이미지 캡션"}, {"caption": "플레이스홀더 — 이미지 캡션"}, {"caption": "플레이스홀더 — 이미지 캡션"}], "titleEn": "", "titleKo": "", "variant": "imagesGrid3x3"}], "coverPatientSpecies": "고양이", "recheckWithin1Month": "간수치 추가 평가\\n간수치 변동 추이 확인 및 간 보호제 효과를 평가합니다.", "systemsPage3bBlocks": [{"rows": [{"label": "주요 진단 내용", "content": "혈액 검사에서 신장 기능을 평가하는 SDMA 수치는 10으로 정상 범주에 있었습니다. 복부 초음파 검사에서도 양쪽 신장과 방광의 크기 및 구조에서 특이 소견은 관찰되지 않았습니다."}, {"label": "시사점", "content": "현재 신장 및 비뇨기계 기능은 양호한 것으로 판단되나, 고혈압은 신장 질환의 원인이 될 수 있으므로 주기적인 신장 기능 검사 및 요 검사를 통해 지속적인 관리가 중요합니다. 평소 음수량과 배뇨량 변화에 유의하여 살펴봐 주시기 바랍니다."}], "titleEn": "Kidney & Urinary System", "titleKo": "신장 및 비뇨기계", "variant": "rows"}, {"rows": [{"label": "주요 진단 내용", "content": "혈액 검사 결과 간 효소 수치인 AST가 85 U/L, ALT가 136 U/L로 정상 범위보다 상승되어 있습니다. 복부 초음파 검사에서는 간, 담낭, 비장에서 현재 구조적인 특이 소견은 발견되지 않았습니다."}, {"label": "시사점", "content": "간 효소 수치 상승은 간세포 손상이나 기능 이상을 시사할 수 있습니다. 현재 초음파상으로는 이상이 없지만, 간 수치 상승에 대한 원인 감별 및 관리가 필요합니다. 지속적인 간 보호제 급여를 통해 간 기능을 지원하고 보호하는 것이 추천됩니다."}], "titleEn": "Hepatobiliary System", "titleKo": "간담도계", "variant": "rows"}, {"rows": [{"label": "주요 진단 내용", "content": "해당 프로그램 미포함 영역"}, {"label": "시사점", "content": "해당 프로그램 미포함 영역"}], "titleEn": "Musculoskeletal System", "titleKo": "근골격계", "variant": "rows"}], "recheckWithin3Months": "정기 혈압 측정\\n고혈압 관리를 위해 주기적인 혈압 측정을 권장합니다.", "recheckWithin6Months": "종합 건강 재검진\\n전반적인 건강 상태 및 만성 질환 관리를 위해 필요합니다.", "recheckWithin1to2Weeks": "혈압 및 간수치 재확인\\n고혈압 및 간수치 상승에 대한 빠른 재평가가 필요합니다."}'::jsonb, '2026-04-20 05:58:29.844889+00'::timestamptz, '2026-04-20 05:59:18.227+00'::timestamptz
);

insert into staging.generated_run_content (
  id, parse_run_id, content_type, payload, created_at, updated_at
) values (
  'fca85c81-1c20-42fb-8e12-ba37b6fa18ea'::uuid, 'b39a7ebc-dcd8-488d-a0e1-01e7ecfad96f'::uuid, 'health_checkup', E'{"followUpCare": "쿠키의 건강 관리를 위해 다음과 같은 사후 관리 계획을 제안합니다. 경도 소포성 결막염은 처방 안약을 꾸준히 적용해 주시고, 1~2주 내 본원에 재내원하여 안과 상태를 재평가할 예정입니다. 고관절염 의심 소견과 관련하여, 관절 통증 완화 및 기능 개선을 위한 관절 보조제 복용을 권장합니다. 쿠키의 보행 및 기립 시 불편감을 면밀히 관찰해 주시고, 6개월 이내 관절 상태 재평가를 위한 추적 검진을 권합니다. 혈액 검사에서 상승한 cPL 및 ALT 수치는 췌장 및 간 기능에 주의가 필요함을 시사합니다. 한 달에 한두 번 발생하는 공복토 증상을 고려하여 소화기계와 간 건강을 위한 식이 관리에 신경 써 주시고, 간 보조제를 복용하며 1개월 내 혈액 수치 재검을 통해 변화를 평가할 예정입니다. 구토, 설사 등 이상 증상 발생 시 즉시 내원해 주십시오. 경미한 치석과 우측 외이도 발적에 대해서는 정기적인 구강 및 귀 청소를 통해 관리하고, 본원 수의사와 상담하여 적절한 방법을 안내받으시길 바랍니다.", "coverOwnerName": "정영훈", "overallSummary": "쿠키는 이번 건강검진에서 전반적으로 양호한 건강 상태를 보였으나, 몇 가지 주요 소견이 확인되었습니다. 혈액 검사에서 췌장염 보조 진단 지표인 cPL 수치가 140.5U/L로 정상 범위보다 높게 측정되었으며, 간 효소인 ALT 수치 또한 126U/L로 상승 소견을 보였습니다. 이는 췌장 및 간 기능에 대한 추가적인 관심과 관찰이 필요함을 시사합니다. 안과 검진 시 양측 눈에서 경도 소포성 결막염이 확인되었습니다. 또한, 신체 검사 결과 양측 고관절 신전 시 통증 반응이 있었고, 특히 우측 후지 불편감과 무릎 촉진 시 싫어하는 반응이 관찰되어 고관절염이 의심됩니다. 이는 활동성에 영향을 줄 수 있는 중요한 소견으로 판단됩니다. 이 외에도 경미한 치석과 우측 귀 이개부 발적 및 귀지 증가 소견이 있었습니다. 전반적인 건강 관리를 위해 각 소견에 대한 면밀한 추적 관찰과 적절한 사후 관리가 중요합니다.", "coverPatientAge": "2", "coverPatientSex": "수컷(중성화)", "coverCheckupDate": "2026-04-18", "coverPatientName": "쿠키", "coverPatientBreed": "푸들", "labInterpretation": "혈액 검사 결과 췌장염 관련 지표인 cPL 수치가 140.5U/L로, 간 효소인 ALT 수치가 126U/L로 상승 소견을 보였습니다. 이는 췌장 및 간 기능에 대한 정밀한 평가와 지속적인 관찰이 필요함을 시사합니다. 그 외 혈구 수치 및 신장 기능, 갑상선 호르몬 수치는 모두 정상 범위 내로 확인되었습니다.", "systemsPage3Blocks": [{"rows": [{"label": "주요 진단 내용", "content": "심장 질환 관련 혈액 검사에서 proBNP 수치는 821pmol/L로 정상 범위 내에 있었으며, 흉부 방사선 검사 결과도 심장 크기나 폐 음영에서 특이 소견은 확인되지 않았습니다."}, {"label": "시사점", "content": "현재까지 확인된 검사 결과로는 쿠키의 심장 및 호흡기 계통에서 특별한 이상 소견은 관찰되지 않습니다. 꾸준한 관찰을 통해 건강을 유지하는 것이 중요합니다."}], "titleEn": "Circulatory & Respiratory Systems", "titleKo": "순환기&호흡기", "variant": "rows"}, {"rows": [{"label": "주요 진단 내용", "content": "혈액 검사에서 췌장염 보조 진단 지표인 cPL 수치가 140.5U/L로 정상 범위(참고치 0-20U/L)보다 높게 측정되었습니다. 차트 상 한 달에 한두 번 공복토 증상이 확인되었습니다."}, {"label": "시사점", "content": "cPL 수치 상승과 공복토 증상은 췌장염 또는 소화기계의 민감성을 시사할 수 있습니다. 향후 구토, 설사, 식욕 부진 등의 소화기 증상에 대한 보호자님의 면밀한 관찰이 필요합니다."}], "titleEn": "Digestive System", "titleKo": "소화기", "variant": "rows"}, {"rows": [{"label": "주요 진단 내용", "content": "내분비계 관련 검사 결과, 갑상선 호르몬(T4 3.66µg/dL)과 혈당(GLU 91mg/dL), 콜레스테롤(CHOL 211mg/dL), 중성지방(TRIG 60mg/dL) 수치 모두 정상 범위 내에 있습니다."}, {"label": "시사점", "content": "현재 쿠키는 내분비계와 관련된 특별한 이상 소견이 확인되지 않습니다. 비만 등 대사 이상 소견도 없어 건강하게 관리되고 있는 것으로 판단됩니다."}], "titleEn": "Endocrine System", "titleKo": "내분비계", "variant": "rows"}], "systemsPage4Blocks": [{"rows": [{"label": "주요 진단 내용", "content": "구강 검진 시 경미한 치석이 확인되었으며, 108번 치아에 모양 이상 소견이 있었습니다. 2025년 2월 스케일링 및 발치를 진행하여 전반적인 치아 상태는 양호합니다. 안과 검진에서는 양측 눈에서 경도 소포성 결막염이 확인되었습니다."}, {"label": "시사점", "content": "치아 모양 이상은 주기적인 관찰이 필요하며, 현재 경미한 치석은 가정에서의 꾸준한 양치질 및 구강 관리로 예방하는 것이 중요합니다. 경도 소포성 결막염은 처방된 안약을 꾸준히 적용하며 경과를 지켜보고 다음 주 내로 재평가가 필요합니다."}], "titleEn": "Dental & Ophthalmology", "titleKo": "치과 및 안과", "variant": "rows"}, {"images": [{"caption": "플레이스홀더 — 이미지 캡션"}, {"caption": "플레이스홀더 — 이미지 캡션"}, {"caption": "플레이스홀더 — 이미지 캡션"}, {"caption": "플레이스홀더 — 이미지 캡션"}, {"caption": "플레이스홀더 — 이미지 캡션"}, {"caption": "플레이스홀더 — 이미지 캡션"}], "titleEn": "", "titleKo": "", "variant": "imagesGrid2x3"}, {"rows": [{"label": "주요 진단 내용", "content": "외이도 검사 결과 우측 이개부에서 발적이 확인되었고, 귀지가 증가된 소견이 관찰되었습니다. 피부 전반적으로는 특이 소견이 없었습니다."}, {"label": "시사점", "content": "우측 귀의 발적과 귀지는 외이염 초기 단계이거나 관리가 필요한 상태를 의미할 수 있습니다. 평소 귀 청결 유지에 신경 써 주시고, 추가적인 가려움증이나 분비물이 증가할 경우 재내원이 필요합니다."}], "titleEn": "Skin & External Ear Canal", "titleKo": "피부와 외이도", "variant": "rows"}, {"images": [{"caption": "플레이스홀더 — 이미지 캡션"}, {"caption": "플레이스홀더 — 이미지 캡션"}, {"caption": "플레이스홀더 — 이미지 캡션"}], "titleEn": "", "titleKo": "", "variant": "images"}], "systemsPage5Blocks": [{"rows": [{"label": "검사 결과 해석", "content": "해당 프로그램 미포함 영역"}], "compact": true, "titleEn": "X-ray", "titleKo": "방사선 검사", "variant": "rows"}, {"images": [{"caption": "플레이스홀더 — 이미지 캡션"}, {"caption": "플레이스홀더 — 이미지 캡션"}, {"caption": "플레이스홀더 — 이미지 캡션"}, {"caption": "플레이스홀더 — 이미지 캡션"}], "titleEn": "", "titleKo": "", "variant": "images4"}, {"rows": [{"label": "검사 결과 해석", "content": "해당 프로그램 미포함 영역"}], "compact": true, "titleEn": "Ultrasonography", "titleKo": "초음파 검사", "variant": "rows"}, {"images": [{"caption": "플레이스홀더 — 이미지 캡션"}, {"caption": "플레이스홀더 — 이미지 캡션"}, {"caption": "플레이스홀더 — 이미지 캡션"}, {"caption": "플레이스홀더 — 이미지 캡션"}, {"caption": "플레이스홀더 — 이미지 캡션"}, {"caption": "플레이스홀더 — 이미지 캡션"}, {"caption": "플레이스홀더 — 이미지 캡션"}, {"caption": "플레이스홀더 — 이미지 캡션"}, {"caption": "플레이스홀더 — 이미지 캡션"}], "titleEn": "", "titleKo": "", "variant": "imagesGrid3x3"}], "coverPatientSpecies": "개", "recheckWithin1Month": "혈액 검사 재평가\\n췌장염 및 간 수치 변화를 평가하기 위한 재검진이 필요합니다.", "systemsPage3bBlocks": [{"rows": [{"label": "주요 진단 내용", "content": "신장 기능 지표인 SDMA(11ug/dL)와 BUN(23mg/dL) 수치가 모두 정상 범위 내에 있습니다. 요검사에서도 특이 소견은 확인되지 않았습니다."}, {"label": "시사점", "content": "쿠키의 신장 및 비뇨기계 기능은 현재 양호한 것으로 평가됩니다. 특별한 관리 없이 건강하게 유지되고 있습니다."}], "titleEn": "Kidney & Urinary System", "titleKo": "신장 및 비뇨기계", "variant": "rows"}, {"rows": [{"label": "주요 진단 내용", "content": "간 수치 중 ALT가 126U/L로 정상 범위(참고치 0-100U/L)보다 상승 소견을 보였습니다. 다른 간 기능 지표인 AST(40U/L)와 ALP(63U/L) 등은 정상 범위 내에 있습니다."}, {"label": "시사점", "content": "ALT 수치 상승은 간세포 손상 가능성을 시사할 수 있습니다. 현재 임상 증상은 없지만, 장기적인 관점에서 간 건강을 위한 식이 관리 및 보조제 복용을 고려하고 1개월 후 재검을 통해 변화를 확인하는 것이 중요합니다."}], "titleEn": "Hepatobiliary System", "titleKo": "간담도계", "variant": "rows"}, {"rows": [{"label": "주요 진단 내용", "content": "신체 검사 시 양측 고관절 신전 시 통증 반응이 명확하게 확인되었습니다. 특히 우측 후지를 오래 걷거나 누워있다가 일어날 때 불편해하는 증상이 있었으며, 무릎 촉진 시에도 불편감을 나타냈습니다."}, {"label": "시사점", "content": "이러한 소견들은 양측 고관절염의 가능성을 강하게 시사하며, 무릎 관절에도 경미한 통증이 있는 것으로 보입니다. 쿠키의 활동성과 삶의 질 유지를 위해 관절 관리가 매우 중요합니다."}], "titleEn": "Musculoskeletal System", "titleKo": "근골격계", "variant": "rows"}], "recheckWithin3Months": "일반 건강 상태 확인\\n전반적인 건강 상태와 관절 보조제 복용 효과를 점검합니다.", "recheckWithin6Months": "정기 건강검진 및 관절 재평\\n췌장 및 간 수치 장기적 변화와 고관절 상태를 다시 확인합니다.", "recheckWithin1to2Weeks": "결막염 재평가\\n처방된 안약 적용 후 눈 상태를 재확인합니다."}'::jsonb, '2026-04-22 03:24:40.049734+00'::timestamptz, '2026-04-22 03:24:39.832+00'::timestamptz
);

