  id, parse_run_id, content_type, payload, created_at, updated_at
) values (
  '87a75593-e45d-42d2-b6eb-800628bac089'::uuid, 'def92dd9-8572-48a3-bfed-3c2a1708678b'::uuid, 'health_checkup', E'{"followUpCare": "오복이의 양측 고관절 관절염 및 아탈구 의심 소견에 대해 추가적인 정형외과 평가를 권장합니다. 정확한 진단을 위해 본원에 내원하시어 전문 수의사와 상담 후 정밀 검사를 진행해 주십시오. 이는 장기적인 관절 건강 유지를 위해 매우 중요합니다.\\n\\n외이도염 의심 소견과 관련하여, 외이도 내부 상태를 정확히 확인하고 적절한 치료 방향을 설정하기 위해 추가적인 귀 검사(예: 귀 내시경) 및 세균/곰팡이 배양 검사가 필요할 수 있습니다. 또한, 결막 충혈 및 각막 염색 소견에 대해서는 안과 정밀 검사를 통해 원인을 파악하고 적절한 안과 처치를 시작해야 합니다. 보호자께서는 오복이의 귀를 긁거나 머리를 흔드는 행동, 눈을 불편해하는 행동 변화를 주의 깊게 관찰해 주시고, 이상 증상 발생 시 즉시 본원으로 연락해 주시기 바랍니다. 모든 권장 사항은 아이의 편안하고 건강한 삶을 위한 조치입니다.", "coverOwnerName": "양윤청", "overallSummary": "오복이의 2026년 4월 4일 건강검진 결과, 전반적으로 양호한 건강 상태를 보였습니다. 그러나 방사선 검사에서 양측 고관절의 관절염 및 아탈구 소견이 확인되어 이에 대한 세심한 주의와 추가적인 평가가 필요합니다. 이는 향후 보행 변화나 통증을 유발할 수 있는 중요한 소견입니다.\\n\\n또한, 외이도 검사에서 갈색 귀지와 염증성 소견으로 외이도염이 의심되며, 슬릿램프 검사에서는 결막 충혈 및 각막 염색 소견이 관찰되어 안과적 문제의 가능성이 있습니다. 이 두 가지 소견은 아이의 불편감을 유발할 수 있으므로 신속한 확인과 관리가 요구됩니다. 주기적인 건강검진을 통해 오복이의 건강을 지속적으로 관리해 주시는 것이 중요합니다.", "coverPatientAge": "5", "coverPatientSex": "수컷(중성화)", "coverCheckupDate": "2026-04-04", "coverPatientName": "오복이", "coverPatientBreed": "브리티시숏헤어", "labInterpretation": "이번 건강검진에서 진행된 혈액 검사 상 임상적으로 유의미한 이상 소견은 확인되지 않았습니다. 현재까지는 전반적으로 건강한 상태를 유지하고 있는 것으로 판단됩니다.", "systemsPage3Blocks": [{"rows": [{"label": "주요 진단 내용", "content": "해당 프로그램 미포함 영역"}, {"label": "시사점", "content": "해당 프로그램 미포함 영역"}], "titleEn": "Circulatory & Respiratory Systems", "titleKo": "순환기&호흡기", "variant": "rows"}, {"rows": [{"label": "주요 진단 내용", "content": "해당 프로그램 미포함 영역"}, {"label": "시사점", "content": "해당 프로그램 미포함 영역"}], "titleEn": "Digestive System", "titleKo": "소화기", "variant": "rows"}, {"rows": [{"label": "주요 진단 내용", "content": "해당 프로그램 미포함 영역"}, {"label": "시사점", "content": "해당 프로그램 미포함 영역"}], "titleEn": "Endocrine System", "titleKo": "내분비계", "variant": "rows"}], "systemsPage4Blocks": [{"rows": [{"label": "주요 진단 내용", "content": "슬릿램프 검사 결과, 결막에 충혈 소견이 확인되었으며 각막 염색 검사에서 염색 소견이 의심됩니다. 치과 관련하여 특이 소견은 확인되지 않았습니다."}, {"label": "시사점", "content": "이는 결막염 또는 각막 손상의 가능성을 시사하며, 시력 저하 및 통증을 유발할 수 있으므로, 정확한 원인 파악과 적절한 치료를 위한 추가적인 안과 평가가 필요합니다."}], "titleEn": "Dental & Ophthalmology", "titleKo": "치과 및 안과", "variant": "rows"}, {"images": [{"src": "nuel-260422-02_def92dd9/2026-04-04/1776830518677_7_98934042.webp", "caption": "슬릿램프"}, {}, {}, {}, {}, {}], "titleEn": "", "titleKo": "", "variant": "imagesGrid2x3"}, {"rows": [{"label": "주요 진단 내용", "content": "외이도 검사 결과, 양측 외이도에서 갈색 귀지와 염증성 소견이 관찰되었습니다. 이는 외이도염이 의심되는 상태입니다."}, {"label": "시사점", "content": "외이도염은 통증과 가려움증을 유발하여 아이가 귀를 긁거나 털 수 있으며, 만성화될 경우 청력에 영향을 줄 수 있으므로 정확한 진단과 치료가 필요합니다. 청결 관리에 유의해 주십시오."}], "titleEn": "Skin & External Ear Canal", "titleKo": "피부와 외이도", "variant": "rows"}, {"images": [{"src": "nuel-260422-02_def92dd9/2026-04-04/1776830517974_5_223fbfe9.webp", "caption": "피부"}, {"src": "nuel-260422-02_def92dd9/2026-04-04/1776830518331_6_5a5e4132.webp", "caption": "피부"}, {}], "titleEn": "", "titleKo": "", "variant": "images"}], "systemsPage5Blocks": [{"rows": [{"label": "검사 결과 해석", "content": "방사선(관절) 검사 결과, 양측 고관절에서 관절염 및 아탈구 소견이 확인되었습니다. 흉부 및 복부 방사선 검사에서는 특이적인 이상 소견이 관찰되지 않았습니다."}], "compact": true, "titleEn": "X-ray", "titleKo": "방사선 검사", "variant": "rows"}, {"images": [{"src": "nuel-260422-02_def92dd9/2026-04-04/1776830515942_2_444879c6.webp", "caption": "관절 방사선"}, {"src": "nuel-260422-02_def92dd9/2026-04-04/1776830517047_3_31e30057.webp", "caption": "관절 방사선"}, {"src": "nuel-260422-02_def92dd9/2026-04-04/1776830513625_0_7cb44e98.webp", "caption": "흉부 방사선"}, {"src": "nuel-260422-02_def92dd9/2026-04-04/1776830514819_1_e3e1ec10.webp", "caption": "복부 방사선"}], "titleEn": "", "titleKo": "", "variant": "images4"}, {"rows": [{"label": "검사 결과 해석", "content": "해당 프로그램 미포함 영역"}], "compact": true, "titleEn": "Ultrasonography", "titleKo": "초음파 검사", "variant": "rows"}, {"images": [{}, {}, {}, {}, {}, {}, {}, {}, {}], "titleEn": "", "titleKo": "", "variant": "imagesGrid3x3"}], "coverPatientSpecies": "고양이", "recheckWithin1Month": "고관절 정형외과 평가\\n고관절 상태 평가를 위한 정형외과 검진을 권장합니다.", "systemsPage3bBlocks": [{"rows": [{"label": "주요 진단 내용", "content": "해당 프로그램 미포함 영역"}, {"label": "시사점", "content": "해당 프로그램 미포함 영역"}], "titleEn": "Kidney & Urinary System", "titleKo": "신장 및 비뇨기계", "variant": "rows"}, {"rows": [{"label": "주요 진단 내용", "content": "해당 프로그램 미포함 영역"}, {"label": "시사점", "content": "해당 프로그램 미포함 영역"}], "titleEn": "Hepatobiliary System", "titleKo": "간담도계", "variant": "rows"}, {"rows": [{"label": "주요 진단 내용", "content": "방사선(관절) 검사 결과, 양측 고관절에서 관절염 및 아탈구 소견이 관찰되었습니다."}, {"label": "시사점", "content": "이는 고관절의 기능 저하와 통증을 유발할 수 있는 상태로, 아이의 보행이나 움직임 변화에 대한 세심한 관찰이 필요하며 추가적인 정형외과 평가가 권장됩니다."}], "titleEn": "Musculoskeletal System", "titleKo": "근골격계", "variant": "rows"}], "recheckWithin3Months": "관절 건강 모니터링\\n고관절 상태 변화를 주기적으로 확인하는 것이 중요합니다.", "recheckWithin6Months": "정기 건강검진\\n전반적인 건강 상태 유지를 위해 정기 검진을 진행합니다.", "recheckWithin1to2Weeks": "외이도염 및 안과 재검진\\n외이도염 치료 및 안과 재검진을 위해 방문해 주세요."}'::jsonb, '2026-04-22 06:27:35.531262+00'::timestamptz, '2026-04-22 06:27:34.416+00'::timestamptz
);

insert into staging.generated_run_content (
  id, parse_run_id, content_type, payload, created_at, updated_at
) values (
  '02d812ad-4c4d-4683-beaf-566d7c49fd86'::uuid, '33d65cc1-ce7f-4082-b247-7a056bf20a77'::uuid, 'health_checkup', E'{"coverProgram": "프리미엄", "followUpCare": "푸푸의 건강검진 결과를 바탕으로 다음과 같은 사후 관리를 권장합니다. 우선, 확인된 고혈압 관리를 위해 혈압약 복용을 시작하시고, 한 달 이내에 본원에 내원하시어 혈압 재평가를 통해 약물 반응을 확인하고 필요 시 용량을 조정해 주십시오. 기관허탈은 현재 경미한 수준이나, 호흡기 증상이 발현되면 폐야 변화 가능성과 함께 평가를 위해 즉시 내원해 주시기 바랍니다.\\n\\n담낭슬러지와 경미하게 상승한 ALKP 수치에 대해서는 현재 복용 중인 간영양제를 지속적으로 급여하시면서, 소화기 증상 발생 여부를 주의 깊게 관찰해 주십시오. 초음파에서 확인된 위장관 장벽 비후, 신장 에코 변화, 부신 크기 측정 소견은 향후 주기적인 추적 관찰을 통해 변화 여부를 평가하는 것이 중요합니다.\\n\\n중등도 치석 및 잇몸 염증, 치조골 소실 등 치과 질환은 전신 건강에 영향을 미칠 수 있으므로, 빠른 시일 내에 스케일링을 포함한 전문적인 치과 치료를 받는 것을 권장합니다. 외이염에 대해서는 처방해 드린 귀 물약을 지시대로 적용하시고, 1~2주 이내에 귀 치료 경과를 확인하기 위한 재검진을 받아 주십시오. 혈소판 수치 저하에 대해서도 원인 파악을 위한 추가 검사 또는 주기적인 재검사가 필요할 수 있습니다.", "coverOwnerName": "남은정", "overallSummary": "이전 건강검진에서 2026년 2월 2일 진행된 푸푸의 종합 건강검진 결과, 다양한 계통에서 주요 소견들이 확인되었습니다. 심혈관계에서는 맥박수 172회/분, 혈압 208/141(평균 163)mmHg로 고혈압이 진단되었으며, 호흡기계에서는 경미한 기관허탈과 흉부 방사선상 폐야의 간질성 패턴 증가 및 기관지 주변 침윤 가능성이 관찰되었습니다. proBNP 수치는 정상입니다.\\n\\n소화기계에서는 혈액 검사상 ALKP 수치가 248U/L로 경미하게 상승하였고, 복부 초음파 검사에서 담낭슬러지, 위장관 장벽 비후, 복강 내 낭성 또는 복합성 병변이 확인되어 추가적인 평가가 필요합니다. 신장 및 비뇨기계에서는 우측 신장 내부 에코 구조 변화와 고에코성 구조물이 초음파에서 관찰되어 신장 내 병변 가능성이 있습니다. 또한, 내분비계에서는 좌우 부신이 측정되었으며, 크기에 대한 추가 평가가 필요합니다.\\n\\n치과 검진에서는 중등도의 치석과 잇몸 염증이 전반적으로 확인되었고, 치과 방사선 검사에서 여러 치아 주변의 치조골 소실 및 치근단 변화가 뚜렷하게 관찰되었습니다. 피부 및 외이도 검진에서는 이도 발적과 부종을 동반한 외이염으로 진단되었습니다. 혈액 검사상 PLT 수치가 12710x3/μL로 낮게 측정된 점도 주목하여 추적 관찰이 필요합니다.", "coverPatientAge": "12", "coverPatientSex": "수컷", "coverCheckupDate": "2026-02-02", "coverPatientName": "푸푸", "coverPatientBreed": "Poodle", "coverVeterinarian": "남기웅", "labInterpretation": "이번 혈액 검사 결과, ALKP 수치가 248U/L로 경미하게 상승하여 간담도계 기능과 관련하여 주의 깊은 관찰이 필요합니다. HGB 21g/dL, MCH 26.3pg, MPV 14.6fL 수치는 높게, PLT 12710x3/μL 수치는 낮게 측정되어 혈액 세포 조성에 일부 변화가 확인됩니다. 현재 정상 범위인 다른 수치들과 함께 전반적인 건강 상태를 확인하였으며, 이상 소견에 대해서는 정기적인 추적 검사가 권장됩니다.", "systemsPage3Blocks": [{"rows": [{"label": "주요 진단 내용", "content": "푸푸는 맥박수 172회/분, 혈압 208/141(평균 163)mmHg로 측정되어 고혈압 소견을 보였습니다. 흉부 방사선 검사에서는 폐야에 간질성 패턴 증가 및 기관지 주변 침윤 가능성이 관찰되었고, 기관직경 차이가 30%로 경미한 기관허탈이 확인되었습니다. 경부 피하에 마이크로칩이 관찰되었으며, 흉강 내에 선형의 이물질이 확인되었으나 임상적 증상은 없었습니다. proBNP 수치는 363.01pmol/L로 정상 범위였습니다."}, {"label": "시사점", "content": "푸푸의 고혈압 소견은 심장과 다른 장기에 부담을 줄 수 있어 관리가 필요하며, 혈압약 복용을 권장합니다. 경미한 기관허탈은 현재 임상 증상이 경미하므로 추적 관찰이 필요하지만, 기관지 주변 침윤 가능성과 폐 무늬 변화는 호흡기 증상 발현 시 폐렴이나 만성 기관지염 등의 가능성을 염두에 두고 추가적인 평가를 고려해야 합니다. 흉강 내 선형 이물질은 위치 및 형태 변화 여부를 주기적으로 확인하는 것이 중요합니다."}], "titleEn": "Circulatory & Respiratory Systems", "titleKo": "순환기&호흡기", "variant": "rows"}, {"rows": [{"label": "주요 진단 내용", "content": "혈액 검사에서 Amylase 수치가 335U/L로 정상 범위 하단에 있었습니다. 복부 초음파 검사에서 담낭슬러지가 관찰되었으며, 내부 침전물이 확인된 확장된 담낭 소견도 있었습니다. 또한, 위장관 장벽이 비후된 소견과 비후된 장벽 및 확장된 내강을 보이는 위장관 초음파 소견이 있었습니다. 복강 내 낭성 또는 복합성 병변이 확인되었고, 복부 방사선 검사에서는 다수의 고밀도 장내 내용물(배변 정체 또는 변비 가능성)이 관찰되었습니다."}, {"label": "시사점", "content": "담낭슬러지는 담즙 배출에 영향을 줄 수 있으므로, 간영양제를 꾸준히 복용하며 복통이나 구토 등 소화기 증상 발현 여부를 면밀히 관찰해야 합니다. 위장관 장벽 비후는 염증성 변화를 시사할 수 있으며, 복강 내 병변과 함께 추가적인 평가가 필요합니다. 장내 고밀도 내용물은 식이 관리나 수분 섭취 증가를 통해 개선될 수 있으나, 만성적인 경우 변비 또는 기타 소화기 문제의 징후일 수 있으니 식습관을 살펴봐 주십시오."}], "titleEn": "Digestive System", "titleKo": "소화기", "variant": "rows"}, {"rows": [{"label": "주요 진단 내용", "content": "혈액 검사에서 T4 수치는 2.7µg/dL, GLU 수치는 113mg/dL로 모두 정상 범위에 있었습니다. 복부 초음파 검사 결과 좌측 부신과 우측 부신이 각각 측정되었으며, 그 크기에 대한 추가적인 평가가 필요하다는 소견이 확인되었습니다."}, {"label": "시사점", "content": "갑상선 기능 및 혈당 수치는 현재 정상 범위로 확인되어 특별한 우려는 없습니다. 그러나 좌우 부신이 측정되었고 크기에 대한 추가 평가가 필요하다는 소견이 있어, 부신 관련 질환의 가능성을 완전히 배제하기는 어렵습니다. 부신 기능 검사 등 정밀 검사를 통해 정확한 상태를 확인하고, 앞으로 부신 질환 관련 증상(다음다뇨, 복부 팽만 등)이 나타나는지 주의 깊게 관찰하는 것이 중요합니다."}], "titleEn": "Endocrine System", "titleKo": "내분비계", "variant": "rows"}], "systemsPage4Blocks": [{"rows": [{"label": "주요 진단 내용", "content": "구강 검진에서 중등도의 치석과 잇몸 염증이 전반적으로 확인되었습니다. 특히 오른쪽, 왼쪽 치아 및 앞니와 송곳니 주변에 심한 치석과 치태, 잇몸 발적이 관찰되었습니다. 치과 방사선 검사 결과, 여러 치아 주변의 치조골 소실 및 치근단 변화가 의심되며, 하악 견치 부위의 치근 노출과 주변 골 소실이 뚜렷하게 확인되었습니다. 일부 치아 뿌리 주변의 골 밀도 변화 및 불규칙한 형태도 관찰되었습니다."}, {"label": "시사점", "content": "푸푸는 중등도 이상의 치과 질환을 앓고 있으며, 이는 단순한 치석 문제를 넘어 치아 주변 지지 조직과 치근까지 영향을 미치고 있는 상황입니다. 심한 치과 질환은 통증, 식욕 부진, 구취는 물론 전신 염증 반응을 유발할 수 있습니다. 따라서 전신 마취 하의 스케일링을 포함한 전문적인 치과 치료(발치 등)가 시급히 필요합니다. 치료 후에는 정기적인 구강 관리와 재검진을 통해 치아 건강을 유지하는 것이 중요합니다."}], "titleEn": "Dental & Ophthalmology", "titleKo": "치과 및 안과", "variant": "rows"}, {"images": [{"src": "dodam-260329-01_33d65cc1/2026-02-02/1775469684735_0_fe7e0719.webp", "caption": "치아 방사선"}, {"src": "dodam-260329-01_33d65cc1/2026-02-02/1775469685321_1_71929b12.webp", "caption": "치아 방사선"}, {"src": "dodam-260329-01_33d65cc1/2026-02-02/1775469685568_2_3fa06172.webp", "caption": "치아 방사선"}, {"src": "dodam-260329-01_33d65cc1/2026-02-02/1775470616302_0_609beb3b.webp", "caption": "치아"}, {"src": "dodam-260329-01_33d65cc1/2026-02-02/1775470617094_1_6abd08a9.webp", "caption": "치아"}, {"src": "dodam-260329-01_33d65cc1/2026-02-02/1775470617738_2_d4bc1d38.webp", "caption": "치아"}], "titleEn": "", "titleKo": "", "variant": "imagesGrid2x3"}, {"rows": [{"label": "주요 진단 내용", "content": "검이경 검사에서 양쪽 이도에 발적과 부종이 관찰되었으며, 이도 내에 다량의 털과 분비물이 확인되어 외이염 소견이 뚜렷합니다. 그 외 피부에 대한 직접적인 이상 소견은 차트에서 확인되지 않았습니다."}, {"label": "시사점", "content": "확인된 외이염은 푸푸에게 불편함과 통증을 유발할 수 있습니다. 처방해 드린 귀 물약을 지시대로 꾸준히 적용하시고, 이도 발적과 분비물이 줄어드는지 주의 깊게 관찰해 주시기 바랍니다. 1~2주 이내에 본원에 재방문하여 치료 경과를 평가하고, 필요 시 추가적인 처치나 검사를 진행하여 만성적인 외이염으로의 진행을 막는 것이 중요합니다. 평소에도 귀 관리에 신경 써 주시길 권장합니다."}], "titleEn": "Skin & External Ear Canal", "titleKo": "피부와 외이도", "variant": "rows"}, {"images": [{"src": "dodam-260329-01_33d65cc1/2026-02-02/1775487100764_0_9995957c.webp", "caption": "검이경"}, {"src": "dodam-260329-01_33d65cc1/2026-02-02/1775487101456_1_bc1c55ae.webp", "caption": "검이경"}, {}], "titleEn": "", "titleKo": "", "variant": "images"}], "systemsPage5Blocks": [{"rows": [{"label": "검사 결과 해석", "content": "흉부 방사선 검사에서 폐야에 경미한 기관지성/간질성 무늬와 기관직경 차이 30%의 기관허탈이 확인됩니다. 흉강 내 소형 금속성 이물질이 관찰되며, 복부 방사선상 요추 부위 경미한 측만증과 장내 고밀도 내용물 소견이 확인됩니다."}], "compact": true, "titleEn": "X-ray", "titleKo": "방사선 검사", "variant": "rows"}, {"images": [{"src": "dodam-260329-01_33d65cc1/2026-02-02/1775469801874_0_4bac7b26.webp", "caption": "복부 방사선"}, {"src": "dodam-260329-01_33d65cc1/2026-02-02/1775472441640_4_db3fb977.webp", "caption": "복부 방사선"}, {"src": "dodam-260329-01_33d65cc1/2026-02-02/1775469836591_0_092b1346.webp", "caption": "흉부 방사선"}, {"src": "dodam-260329-01_33d65cc1/2026-02-02/1775470505998_0_165cd5b5.webp", "caption": "흉부 방사선"}], "titleEn": "", "titleKo": "", "variant": "images4"}, {"rows": [{"label": "검사 결과 해석", "content": "복부 초음파 검사에서 담낭 내 슬러지 및 침전물, 위장관 장벽 비후 소견이 확인됩니다. 우측 신장 내부 에코 변화 및 고에코성 구조물이 관찰되었고, 좌우 부신 크기에 대한 추가 평가가 필요합니다. 복강 내 낭성/복합성 병변도 확인됩니다."}], "compact": true, "titleEn": "Ultrasonography", "titleKo": "초음파 검사", "variant": "rows"}, {"images": [{"src": "dodam-260329-01_33d65cc1/2026-02-02/1775470993055_1_6be7451d.webp", "caption": "복부 초음파"}, {"src": "dodam-260329-01_33d65cc1/2026-02-02/1775470993518_3_2dd542a7.webp", "caption": "초음파"}, {"src": "dodam-260329-01_33d65cc1/2026-02-02/1775471048069_0_dfe6f390.webp", "caption": "피부 초음파"}, {"src": "dodam-260329-01_33d65cc1/2026-02-02/1775471048385_1_74e1b89c.webp", "caption": "복부 초음파"}, {"src": "dodam-260329-01_33d65cc1/2026-02-02/1775471275343_2_3a9e89b5.webp", "caption": "초음파"}, {"src": "dodam-260329-01_33d65cc1/2026-02-02/1775487233409_0_5141ad9e.webp", "caption": "복부 초음파"}, {}, {}, {}], "titleEn": "", "titleKo": "", "variant": "imagesGrid3x3"}], "coverPatientSpecies": "Canine", "recheckWithin1Month": "혈압 및 약물 효과 확인\\n혈압약 복용 후 혈압을 재측정하여 약물 효과를 평가합니다.", "systemsPage3bBlocks": [{"rows": [{"label": "주요 진단 내용", "content": "혈액 검사에서 BUN 수치는 10mg/dL, Creatinine 수치는 0.6mg/dL로 신장 기능 관련 수치는 정상 범위였습니다. 복부 초음파 검사에서는 우측 신장의 내부 에코 구조에 변화가 관찰되었으며, 강한 후방 음영을 동반한 고에코성 구조물이 신장 내에서 두 차례 확인되었습니다."}, {"label": "시사점", "content": "신장 기능 관련 혈액 수치는 현재 정상이나, 우측 신장의 내부 에코 구조 변화와 고에코성 구조물은 신장 내 결석, 염증, 또는 기타 병변의 가능성을 시사합니다. 이는 신장 건강에 영향을 줄 수 있으므로, 주기적인 초음파 재검진을 통해 병변의 변화 여부를 확인하고, 필요 시 추가적인 비뇨기계 검사를 고려하여 정확한 원인과 상태를 파악하는 것이 중요합니다."}], "titleEn": "Kidney & Urinary System", "titleKo": "신장 및 비뇨기계", "variant": "rows"}, {"rows": [{"label": "주요 진단 내용", "content": "혈액 검사에서 ALKP 수치가 248U/L로 경미하게 상승한 소견을 보였습니다. ALT 수치는 53U/L, GGT 수치는 0U/L로 모두 정상 범위였습니다. 복부 초음파 검사에서는 내부 침전물이 관찰되는 확장된 담낭과 담낭슬러지가 확인되었습니다."}, {"label": "시사점", "content": "ALKP 수치의 경미한 상승은 다양한 원인으로 나타날 수 있으나, 담낭슬러지와 함께 간담도계의 기능 저하 또는 염증을 시사할 수 있습니다. 현재 복용 중인 간영양제를 지속적으로 급여해 주시고, 앞으로 간담도계와 관련된 증상(황달, 구토, 식욕 부진 등)이 나타나는지 주의 깊게 관찰하는 것이 중요합니다. 주기적인 혈액 검사 및 초음파 검사를 통해 간담도계 상태를 추적 관찰하는 것이 좋습니다."}], "titleEn": "Hepatobiliary System", "titleKo": "간담도계", "variant": "rows"}, {"rows": [{"label": "주요 진단 내용", "content": "복부 방사선 검사에서 요추 부위에 경미한 측만증이 관찰되었습니다. 이는 척추의 형태학적 변화를 나타내는 소견입니다. 그 외 다른 주요 근골격계 검사에서는 특별한 이상 소견이 확인되지 않았습니다."}, {"label": "시사점", "content": "요추 부위의 경미한 측만증은 현재 큰 통증이나 보행 이상을 유발하지 않을 수 있지만, 장기적으로는 척추 건강에 영향을 줄 수 있습니다. 평소 푸푸의 활동량, 보행 상태, 점프 시 불편함 유무 등을 세심하게 관찰해 주시기 바랍니다. 만약 근골격계 관련 증상(절뚝거림, 허리 통증 등)이 나타나면 추가적인 평가가 필요하며, 체중 관리와 적절한 운동을 통해 척추에 가해지는 부담을 줄여주는 것이 중요합니다."}], "titleEn": "Musculoskeletal System", "titleKo": "근골격계", "variant": "rows"}], "recheckWithin3Months": "치과 질환 재평가\\n치과 질환 진행 여부 및 치료 계획 수립을 위해 구강 상태를 재확인합니다.", "recheckWithin6Months": "종합 건강검진 실시\\n전반적인 건강 상태와 만성 질환 관리를 위한 정기 검진이 필요합니다.", "recheckWithin1to2Weeks": "외이염 치료 경과 평가\\n귀 물약 치료 후 이도 상태와 염증 완화 여부를 확인합니다."}'::jsonb, '2026-04-27 00:39:31.538859+00'::timestamptz, '2026-04-27 00:48:29.325+00'::timestamptz
);

insert into staging.generated_run_content (
  id, parse_run_id, content_type, payload, created_at, updated_at
) values (
  '26db8b38-db2b-4f82-983f-6e7dc8f0d04c'::uuid, '9ee98309-dde9-4f96-967f-b7a40f7336de'::uuid, 'health_checkup', E'{"coverProgram": "종합", "followUpCare": "심장 관련 3- 6개월 단위 재검이 권장되며 가정에서 기침, 빈호흡 등 증상이 발생하지 않는지 모니터링 해 주세요.\\n신장 수치와 신장 초음파의 재검이 권장됩니다.\\n양측 눈의 부분 백내장 등 수정체 혼탁과 관련하여 주기적인 모니터링이 권장됩니다.\\n양치질과 주기적인 스케일링으로 치아를 관리해 주세요.\\n양측 슬개골 탈구가 확인되며 체중조절과 관절보조제가 권장됩니다.\\n지간 소독 등 적합한 방법으로 피부를 관리해 주세요.\\n지알디아(Giardia) 원충 감염이 확인되며 처방된 내복약을 꾸준히 먹여 주세요. 향후 재검이 권장됩니다.", "coverOwnerName": "이시후", "overallSummary": "혈구검사, 간 수치 등 전반적인 혈액검사 결과가 정상범위로 확인됩니다.\\n췌장효소수치(cPL), 갑상선 수치(T4)도 정상 범위로 확인됩니다.\\n심장 관련 BNP 수치의 상승이 관찰되며 심장초음파 결과 B2 단계의 심장 판막 질환이 확인됩니다. \\n복부 초음파에서 양측 신장 음영의 상승이 관찰됩니다. 현재 신장 수치와 조기신장마커(SDMA)는 정상범위로 확인됩니다.\\n양측 눈에서 홍채위축과 핵경화증과 같은 노령성 변화가 확인되며 부분백내장이 관찰됩니다. 주기적인 모니터링이 권장됩니다.\\n중등도치석과 경도의 치은염이 확인됩니다. \\n양측 슬개골 탈구가 확인됩니다.\\n사지지간염이 관찰됩니다. \\n분변 키트 검사에서 지알디아(Giardia) 감염이 확인되었습니다.", "coverPatientAge": "13", "coverPatientSex": "암컷(중성화)", "coverCheckupDate": "2026-04-22", "coverPatientName": "슈슈", "coverPatientBreed": "말티즈", "coverVeterinarian": "이덕원", "labInterpretation": "혈액 검사 결과, 대부분의 수치는 정상 범위로 확인되었습니다. 다만, proBNP 수치는 1064 pmol/L로 상승하였으며 향후 재검이 권장됩니다.", "coverPatientWeight": "4.27kg", "systemsPage3Blocks": [{"rows": [{"label": "주요 진단 내용", "content": "Echo 검사 결과, 이첨판막(승모판) 폐쇄부전(MMVD) B2단계 소견이 관찰되었으며, 중등도(Moderate)의 승모판 역류(MR)가 확인되었습니다. proBNP 수치는 1064 pmol/L로 정상 범위보다 높게 측정되었습니다."}, {"label": "시사점", "content": "이첨판막 폐쇄부전은 심장 판막 질환의 일종으로, 현재 중등도 역류와 높은 proBNP 수치가 심장에 부담이 가해지고 있음을 시사합니다. 본 질환은 정기적인 심장 검사를 통해 진행 상황을 평가하고, 적절한 시기에 약물 치료를 시작하여 관리하는 것이 중요합니다."}], "titleEn": "Circulatory & Respiratory Systems", "titleKo": "순환기&호흡기", "variant": "rows"}, {"rows": [{"label": "주요 진단 내용", "content": "분변 키트 검사에서 지알디아(Giardia) 양성 반응이 확인되었습니다. 초음파 검사상 췌장 주위에 에코 상승 소견이 관찰되었습니다. "}, {"label": "시사점", "content": "지알디아는 소화기 증상의 원인이 될 수 있는 원충으로, 치료 후에도 재감염 위험이 있어 주의 깊은 관찰이 필요합니다. 췌장 주위 에코 상승은 췌장염 등 췌장 관련 질환의 가능성을 배제할 수 없으므로, 향후 임상 증상 및 추가 검사를 통한 확인이 권장됩니다. 보호자께서는 환자의 구토, 설사 양상을 주의 깊게 살펴봐 주십시오."}], "titleEn": "Digestive System", "titleKo": "소화기", "variant": "rows"}, {"rows": [{"label": "주요 진단 내용", "content": "혈액 검사 결과, 갑상선 기능 관련 수치인 T4 2.04µg/dL, 혈당 84mg/dL, 콜레스테롤 254mg/dL, 중성지방 41mg/dL 등 주요 내분비계 지표들이 모두 정상 범위 내로 확인되었습니다. 환자의 식욕이나 다음다뇨 등 특이적인 임상 증상은 관찰되지 않았습니다."}, {"label": "시사점", "content": "현재 혈액 검사상 내분비계 기능과 관련된 지표들은 모두 건강한 상태를 나타내고 있습니다. 비만 관련 대사 이상이나 호르몬 불균형의 징후는 확인되지 않았습니다. 정기적인 건강검진을 통해 지속적으로 내분비계 건강 상태를 관리해 주시는 것이 권장됩니다."}], "titleEn": "Endocrine System", "titleKo": "내분비계", "variant": "rows"}], "systemsPage4Blocks": [{"rows": [{"label": "주요 진단 내용", "content": "구강 검진 결과, 중등도(Moderate)의 치석과 경미한(Mild) 치은염 소견이 확인되었습니다. 안과 검진에서는 홍채 위축, 핵경화증, 부분 백내장 소견이 관찰되었습니다."}, {"label": "시사점", "content": "치석과 치은염은 구강 위생 관리가 필요한 상태이며, 진행될 경우 치주 질환으로 이어져 통증과 치아 소실의 원인이 될 수 있습니다. 홍채 위축과 핵경화증은 노령견에서 흔히 나타나는 변화이며, 부분 백내장은 진행 여부를 주기적으로 확인하는 것이 권장됩니다."}], "titleEn": "Dental & Ophthalmology", "titleKo": "치과 및 안과", "variant": "rows"}, {"images": [{"src": "nuel-260422-03_9ee98309/2026-04-20/1777703999107_0_1d8e2233.webp", "caption": "슬릿램프", "rotationDeg": 0}, {"src": "nuel-260422-03_9ee98309/2026-04-20/1777704009098_0_032f63c1.webp", "caption": "슬릿램프", "rotationDeg": 0}, {}, {}, {}, {}], "titleEn": "", "titleKo": "", "variant": "imagesGrid2x3"}, {"rows": [{"label": "주요 진단 내용", "content": "신체검사상 사지에 지간염 소견이 관찰되었습니다."}, {"label": "시사점", "content": "지간염은 가려움증이나 불편감을 유발할 수 있습니다. 보호자께서는 환자가 발을 과도하게 핥거나 습해지지 않도록 주의 깊게 관찰해 주시고, 필요 시 소독 등 적절한 관리가 필요합니다."}], "titleEn": "Skin & External Ear Canal", "titleKo": "피부와 외이도", "variant": "rows"}, {"images": [{"src": "nuel-260422-03_9ee98309/2026-04-20/1777703945041_0_34a0750f.webp", "caption": "검이경", "rotationDeg": 0}, {"src": "nuel-260422-03_9ee98309/2026-04-20/1777703954243_0_3b2dce59.webp", "caption": "검이경", "rotationDeg": 0}, {}], "titleEn": "", "titleKo": "", "variant": "images"}], "systemsPage5Blocks": [{"rows": [{"label": "검사 결과 해석", "content": "특이적인 이상 소견은 관찰되지 않았습니다."}], "compact": true, "titleEn": "X-ray", "titleKo": "방사선 검사", "variant": "rows"}, {"images": [{"src": "nuel-260422-03_9ee98309/2026-04-20/1777704018674_0_b29e8278.webp", "caption": "복부 방사선", "rotationDeg": 0}, {"src": "nuel-260422-03_9ee98309/2026-04-20/1777704031609_0_8f04f023.webp", "caption": "복부 방사선", "rotationDeg": 0}, {"src": "nuel-260422-03_9ee98309/2026-04-20/1776840187434_6_c09f82f6.webp", "caption": "관절 방사선"}, {"src": "nuel-260422-03_9ee98309/2026-04-20/1776840186250_4_dcbb68af.webp", "caption": "흉부 방사선"}], "titleEn": "", "titleKo": "", "variant": "images4"}, {"rows": [{"label": "검사 결과 해석", "content": ""}], "compact": true, "titleEn": "Ultrasonography", "titleKo": "초음파 검사", "variant": "rows"}, {"images": [{}, {}, {}, {}, {}, {}, {}, {}, {}], "titleEn": "", "titleKo": "", "variant": "imagesGrid3x3"}], "coverPatientSpecies": "개", "recheckWithin1Month": "치아 상태 평가\\n스케일링과 치과 치료 상담이 필요합니다.", "systemsPage3bBlocks": [{"rows": [{"label": "주요 진단 내용", "content": "복부 초음파 검사 결과, 양측 신장 실질의 에코가 전반적으로 상승된 소견이 확인되었습니다. 혈액 검사상 BUN 20mg/dL, CREA 0.89mg/dL, SDMA 9ug/dL 등으로 신장 기능 관련 수치들은 현재 정상 범위를 유지하고 있습니다."}, {"label": "시사점", "content": "신장 에코 상승은 신장 실질의 변화를 의미할 수 있으며, 이는 만성 신장 질환의 초기 단계이거나 기타 신장 구조적 변화와 연관될 가능성이 있습니다. 현재 혈액 수치는 정상이나, 향후 신장 기능 변화 여부를 정기적으로 추적 관찰하여 잠재적인 문제를 조기에 관리하는 것이 중요합니다."}], "titleEn": "Kidney & Urinary System", "titleKo": "신장 및 비뇨기계", "variant": "rows"}, {"rows": [{"label": "주요 진단 내용", "content": "혈액 검사 결과, 간 효소 수치인 ALT 62U/L, AST 26U/L, ALP 81U/L, GGT 9U/L 및 빌리루빈, 알부민 수치 등이 모두 정상 범위로 확인되었습니다. 복부 초음파 검사에서도 간담도계에 특이적인 이상 소견은 관찰되지 않았습니다."}, {"label": "시사점", "content": "현재 간담도계와 관련된 혈액 수치와 초음파 영상 모두 건강한 상태를 보여주고 있습니다. 지방간, 담낭 슬러지, 담석 등 간담도계 질환의 징후는 확인되지 않았습니다. 앞으로도 균형 잡힌 식단과 생활 습관을 유지하여 간담도계 건강을 지켜주시는 것이 좋습니다."}], "titleEn": "Hepatobiliary System", "titleKo": "간담도계", "variant": "rows"}, {"rows": [{"label": "주요 진단 내용", "content": "양측 슬개골 탈구 소견이 확인되었습니다. "}, {"label": "시사점", "content": "슬개골 탈구는 지속적인 관리가 필요합니다. 관절에 무리가 가지 않도록 체중 관리에 신경 써 주시고, 격렬한 운동은 자제해 주시는 것이 좋습니다."}], "titleEn": "Musculoskeletal System", "titleKo": "근골격계", "variant": "rows"}], "recheckWithin3Months": "신장 기능 모니터링\\n혈액검사와 복부초음파, 소변검사를 통해 신장 기능 변화를 평가하고 관리 계획을 수립합니다.", "recheckWithin6Months": "종합 건강검진\\n안과, 심장, 관절 등전반적인 건강 상태를 점검하고, 만성 질환 관리 계획을 재평가합니다.", "recheckWithin1to2Weeks": "설사 재평가\\n지알디아 치료 경과 확인 및 위장관 증상 개선 여부를 확인합니다."}'::jsonb, '2026-04-22 06:45:10.458391+00'::timestamptz, '2026-05-02 09:11:36.455+00'::timestamptz
);
